/* ---- Storage wrapper: localStorage first (works standalone), falls back to
        window.storage (Claude artifact env), then silently drops writes ---- */
const store = {
  async get(key) {
    try { const v = localStorage.getItem(key); if (v !== null) return { value: v }; } catch {}
    if (typeof window !== "undefined" && window.storage)
      try { return await window.storage.get(key); } catch {}
    return null;
  },
  async set(key, value) {
    try { localStorage.setItem(key, value); return true; } catch {}
    if (typeof window !== "undefined" && window.storage)
      try { await window.storage.set(key, value); return true; } catch {}
    return false;
  },
};

/* ---------- structures ---------- */
const paper1 = (he) => [
  { sec: "A · Historic environment", q: "1", s: `Describe two features of ${he}`, m: 4 },
  { sec: "A · Historic environment", q: "2(a)", s: "How useful are two given sources for an enquiry into the set topic? Explain your answer using the sources and your knowledge of the historical context", m: 8 },
  { sec: "A · Historic environment", q: "2(b)", s: "How could you follow up a detail in one of the sources? Give the question you would ask and the type of source you could use", m: 4 },
  { sec: "B · Thematic study", q: "3", s: "Explain one way [an aspect] was similar or different between two given periods", m: 4 },
  { sec: "B · Thematic study", q: "4", s: "Explain why [a change or development] happened", m: 12 },
  { sec: "B · Thematic study", q: "5 / 6", s: "‘[statement].’ How far do you agree? Explain your answer (choose one of Question 5 or Question 6)", m: 16, spag: true },
];
const aqaPaper = (secA, label) => [
  { sec: `A · ${label}`, q: "01", s: secA, m: 30 },
  { sec: "B · Essays (answer two of 02–04)", q: "02", s: "Essay: ‘Assess the validity of this view’ on [topic]", m: 25 },
  { sec: "B · Essays (answer two of 02–04)", q: "03", s: "Essay: ‘To what extent…’ on [topic]", m: 25 },
  { sec: "B · Essays (answer two of 02–04)", q: "04", s: "Essay: ‘How far do you agree…’ on [topic]", m: 25 },
];
/* OCR J411 combined-paper formats — verified against the J411/16 sample assessment material (3+9+10+18=40 / 3+5+12+20=40) */
const ocrPeriodStudy = () => [
  { sec: "A · Period study", q: "1(a)", s: "Name / give one example relating to [a feature of the topic in an early period]", m: 1 },
  { sec: "A · Period study", q: "1(b)", s: "Name / give one example relating to [a feature of the topic in a middle period]", m: 1 },
  { sec: "A · Period study", q: "1(c)", s: "Name / give one example relating to [a feature of the topic in a recent period]", m: 1 },
  { sec: "A · Period study", q: "2", s: "Write a clear, organised summary analysing how [a development] changed in [a period], supported with examples", m: 9 },
  { sec: "A · Period study", q: "3", s: "What caused [a development] in [a period]? Explain your answer", m: 10 },
  { sec: "A · Period study", q: "4 / 5", s: "‘[statement].’ How far do you agree? (answer one of two essay options)", m: 18, extended: true },
];
const ocrDepthStudy = () => [
  { sec: "B · Depth study", q: "6(a)", s: "Identify and explain one way the interpretation portrays [an aspect of the topic]", m: 3 },
  { sec: "B · Depth study", q: "6(b)", s: "Suggest and justify one area for further research arising from the interpretation", m: 5 },
  { sec: "B · Depth study", q: "7", s: "How far do two interpretations differ about [an aspect of the topic], and what might explain this?", m: 12 },
  { sec: "B · Depth study", q: "8 / 9", s: "‘[statement].’ How far do you agree with this view? (answer one of two interpretation-based essays)", m: 20, extended: true },
];
/* Edexcel A-Level History (9HI0) structure helpers */
const edexcelAlP1 = () => [
  { sec: "Section A · Breadth essay", q: "1 / 2",
    s: "Essay (choose ONE of TWO): 'How accurate is it to say that [X] was the main reason for [Y] in the years [date range]?' (20 marks)", m: 20, extended: true },
  { sec: "Section B · Breadth essay", q: "3 / 4",
    s: "Essay (choose ONE of TWO): 'How far do you agree that [statement about a different aspect of the period]?' (20 marks)", m: 20, extended: true },
  { sec: "Section C · Interpretations", q: "5",
    s: "Interpretations (compulsory): 'Historians have differed in their views about [topic]. How far do you agree with Interpretation 1/2?' (20 marks)", m: 20 },
];
const edexcelAlP2 = () => [
  { sec: "Section A · Sources", q: "1",
    s: "Sources (compulsory): 'Assess the value of Sources 1 and 2 to a historian studying [topic in the depth study]. Explain using the sources and your knowledge of the historical context.' (20 marks)", m: 20 },
  { sec: "Section B · Extended essay", q: "2 / 3",
    s: "Extended essay (choose ONE of TWO): '[Essay question on an aspect of the depth study].' How far do you agree? (40 marks)", m: 40, extended: true },
];
const edexcelAlP3 = () => [
  { sec: "Section A · Aspects in depth", q: "1",
    s: "Historical controversy (compulsory): 'Historians have differed in their views about [topic in the depth study]. How far do you agree with Interpretation 1/2?' (30 marks)", m: 30 },
  { sec: "Section B · Themes in breadth", q: "2 / 3 / 4",
    s: "Thematic essay spanning the full period (answer TWO of THREE): '[Statement about a key theme across the full period].' How far do you agree? (30 marks each)", m: 30, extended: true },
];
/* OCR A-Level History (H505) structure helpers */
const ocrAlP1 = () => [
  { sec: "Section A · Historical Enquiry", q: "1",
    s: "Analyse and evaluate four primary sources to test the hypothesis. How far do the sources support the view that [statement about the British period]? [30m]", m: 30 },
  { sec: "Section B · Period Study", q: "2 / 3",
    s: "'[Statement about an aspect of the British period].' How far do you agree? Choose one essay from two. [20m]", m: 20, extended: true },
];
const ocrAlP2 = () => [
  { sec: "Part a · Compare factors", q: "a",
    s: "Explain which was the more important factor: [A] or [B] in explaining [outcome]. Make a substantiated judgement. [10m]", m: 10 },
  { sec: "Part b · Essay", q: "b / c",
    s: "'[Statement about the non-British period studied].' How far do you agree? Choose one essay from two. [20m]", m: 20, extended: true },
];
const ocrAlP3 = () => [
  { sec: "Section A · Historical Interpretations", q: "1",
    s: "Read two extracts from historians. Assess which interpretation is more convincing about [a historical issue in the depth study]. Justify your view using the extracts and contextual knowledge. [30m]", m: 30 },
  { sec: "Section B · Thematic Essays", q: "2 / 3 / 4",
    s: "'[Statement about a theme across the full period studied].' To what extent do you agree? (Answer 2 from choice of 3; 25m each.) [25m]", m: 25, extended: true },
];

