/* ═══════════════════════════════════════════════════════════════════════════
   GEOGRAPHY — question structure helpers
   AQA GCSE 8035 | AQA A-Level 7037 | Edexcel GCSE B 1GB0 | OCR GCSE A J383
   ═══════════════════════════════════════════════════════════════════════════ */
function geoAqaGcse(secA, secB, secC) {
  /* AQA 8035 — three sections, each with similar question ladders */
  const qs = (sec, ql) => ql.map(([q, s, m, spag]) => ({ sec, q, s, m, ...(spag ? { spag: true } : {}) }));
  return [
    ...qs(secA, [["1","Give one example of / State / Name [basic recall]", 1],
                 ["2","Describe [using Fig. or own knowledge]", 2],
                 ["3","Explain [with specific detail or named example]", 4],
                 ["4","Assess / Using a case study, explain why…", 6],
                 ["5","'[Statement]' — evaluate this view.", 9, true]]),
    ...qs(secB, [["1","Give one / State [recall]", 1],
                 ["2","Describe [using Fig.]", 2],
                 ["3","Explain [with detail / case study]", 4],
                 ["4","Assess using a named example", 6]]),
    ...qs(secC, [["1","Give one / State", 1],
                 ["2","Describe / Outline", 2],
                 ["3","Explain [with located example]", 4],
                 ["4","Assess / Using a named example, explain", 6],
                 ["5","'[Statement]' — evaluate this view.", 9, true]]),
  ];
}
function geoAqaAlevel(secA, secB, secC) {
  /* AQA 7037/1 Physical Geography actual structure:
     Sec A (Water & Carbon, compulsory): 01.1 (4m) | 01.2 (6m) | 01.3 (6m) | 01.4 (20m) = 36m
     Sec B (Physical option, choose 1): x.1 (4m) | x.2 (6m) | x.3 (6m) | x.4 (20m) = 36m
     Sec C (Hazards OR Ecosystems, choose 1): x.1 (4m) | x.2 (6m) | x.3 (9m) | x.4 (9m) | x.5 (20m) = 48m
     Total = 120m */
  const qs = (sec, ql) => ql.map(([q, s, m]) => ({ sec, q, s, m }));
  return [
    ...qs(secA, [
      ["01.1", "Outline / define [4m — recall of concept, process or feature]", 4],
      ["01.2", "Analyse the data shown in the figure [6m — AO3 data interpretation]", 6],
      ["01.3", "Using the figure and your own knowledge, assess… [6m — AO2+AO3]", 6],
      ["01.4", "Evaluate / With reference to a named area, evaluate… [20m essay]", 20],
    ]),
    ...qs(secB, [
      ["x.1", "Outline [4m — describe feature, sequence or concept of chosen landscape]", 4],
      ["x.2", "Analyse / interpret the data shown [6m — AO3 data interpretation]", 6],
      ["x.3", "Using the figure and your own knowledge, assess / evaluate… [6m]", 6],
      ["x.4", "With reference to one or more areas studied, assess / evaluate… [20m essay]", 20],
    ]),
    ...qs(secC, [
      ["x.1", "Outline [4m — recall of process, concept or mechanism]", 4],
      ["x.2", "Interpret / analyse the data shown [6m — AO3]", 6],
      ["x.3", "Using the figure and your own knowledge, assess challenges / approaches [9m]", 9],
      ["x.4", "To what extent / How far do you agree… [9m — synoptic links]", 9],
      ["x.5", "'[Statement]' Evaluate this view with reference to a named event or place [20m essay]", 20],
    ]),
  ];
}
/* AQA 7037/2 Human Geography uses a separate structure:
   Sec A (Global Systems, compulsory, 36m): 01.1(4) | 01.2(6) | 01.3(6) | 01.4(20)
   Sec B (Changing Places, compulsory, 36m): 02.1(4) | 02.2(6) | 02.3(6) | 02.4(20)
   Sec C (Human option, choose 1, 48m): x.1(4) | x.2(6) | x.3(9) | x.4(9) | x.5(20) */
function geoAqaAlevel2(secA, secB, secC) {
  const qs = (sec, ql) => ql.map(([q, s, m]) => ({ sec, q, s, m }));
  return [
    ...qs(secA, [
      ["01.1", "Outline the role of / Outline characteristics of [4m — global systems recall]", 4],
      ["01.2", "Analyse the data shown in Figure 1 [6m — AO3 data interpretation]", 6],
      ["01.3", "Using the figure and your own knowledge, assess… [6m — trade, governance, global flows]", 6],
      ["01.4", "'[Statement]' Critically assess the extent to which you agree [20m essay]", 20],
    ]),
    ...qs(secB, [
      ["02.1", "Outline how you used a [qualitative/quantitative] data source in your place study [4m — NEA]", 4],
      ["02.2", "Interpret the maps / data shown [6m — AO3 place-specific data]", 6],
      ["02.3", "To what extent can [factor] change the characteristics of a place? [6m — AO2+AO3]", 6],
      ["02.4", "Assess the role of [endogenous/exogenous] factors in shaping lived experience [20m essay]", 20],
    ]),
    ...qs(secC, [
      ["x.1", "Outline [4m — recall of concept in chosen human option]", 4],
      ["x.2", "Analyse / interpret the data shown [6m — AO3]", 6],
      ["x.3", "Using the figure and your own knowledge, evaluate / assess… [9m — AO2+AO3]", 9],
      ["x.4", "To what extent / How far do you agree… [9m — evaluate strategy, policy or trend]", 9],
      ["x.5", "'[Statement]' To what extent do you agree? [20m essay]", 20],
    ]),
  ];
}
function geoEdexcelGcse(sec1, sec2) {
  const qs = (sec, ql) => ql.map(([q, s, m, spag]) => ({ sec, q, s, m, ...(spag ? { spag: true } : {}) }));
  return [
    ...qs(sec1, [["1","Give one example / State", 1],
                 ["2","Describe [using the figure]", 2],
                 ["3","Explain [with specific detail]", 4],
                 ["4","Using a named example, assess…", 6],
                 ["5","'[Statement]' — to what extent do you agree?", 8, true]]),
    ...qs(sec2, [["1","Give one / State", 1],
                 ["2","Describe", 2],
                 ["3","Explain", 4],
                 ["4","Assess using a named example", 6],
                 ["5","'[Statement]' — to what extent do you agree?", 8, true]]),
  ];
}
function geoOcrGcse(sec) {
  return [
    { sec, q: "1", s: "Give one example / State [recall]", m: 1 },
    { sec, q: "2", s: "Describe [using the resource]", m: 2 },
    { sec, q: "3", s: "Explain [with supporting detail]", m: 4 },
    { sec, q: "4", s: "Assess / evaluate [extended writing]", m: 6 },
    { sec, q: "5", s: "'[Statement]' — do you agree? Justify your answer.", m: 8, spag: true },
  ];
}

