/* ═══ Edexcel A-Level Geography (9GE0) structure helpers ═══ */
function geoEdexcelALevel1() {
  /* 9GE0/01 Dynamic Landscapes — 105m, 2h 15m
     Sec A Tectonic (16m): Q1a stats (4m) + Q1b assess (12m)
     Sec B Landscape Systems (40m): Q2 Glaciated OR Q3 Coastal: 6+6+8+20
     Sec C Water + Carbon (49m): structured questions + 12m + 20m essays */
  return [
    { sec: "A · Tectonic Processes & Hazards", q: "1(a)", s: "Calculate statistical measure(s) from data [Spearman's rank rs, mean, median, IQR] (4m)", m: 4 },
    { sec: "A · Tectonic Processes & Hazards", q: "1(b)", s: "Assess the effectiveness of / importance of… [12m extended writing on tectonic hazard management, impacts or vulnerabilty]", m: 12 },
    { sec: "B · Landscape Systems (Q2 Glaciated OR Q3 Coastal)", q: "2a / 3a", s: "Explain how / Explain the contribution of [6m — process or feature using resource booklet figure]", m: 6 },
    { sec: "B · Landscape Systems", q: "2b / 3b", s: "Explain / Suggest [6m — second landscape process/feature using resource booklet]", m: 6 },
    { sec: "B · Landscape Systems", q: "2c / 3c", s: "Explain [8m — landform value, management challenge, or formation detail]", m: 8 },
    { sec: "B · Landscape Systems", q: "2d / 3d", s: "'[Statement about landscape fragility, management or change]' — Evaluate this view. [20m essay]", m: 20 },
    { sec: "C · Water Cycle & Water Insecurity", q: "4", s: "Describe / outline [using figure — water cycle processes or water budget data]", m: 4 },
    { sec: "C · Water Cycle & Water Insecurity", q: "5", s: "Assess / explain [water insecurity causes, consequences or management approaches]", m: 12 },
    { sec: "C · Carbon Cycle & Energy Security", q: "6", s: "Explain / assess [carbon cycle process, energy security issue, or climate change feedback]", m: 6 },
    { sec: "C · Carbon Cycle & Energy Security", q: "7", s: "'[Statement about carbon cycle, energy or climate change]' — Evaluate this view. [20m essay]", m: 20 },
  ];
}
function geoEdexcelALevel2() {
  /* 9GE0/02 Dynamic Places — 105m, 2h 15m
     Sec A Globalisation (16m) + Superpowers (16m) = both compulsory = 32m total
     Sec B Shaping Places (35m): Q3 Regenerating OR Q4 Diverse
     Sec C Global Development (38m): Q5 Health/Human Rights OR Q6 Migration/Identity */
  return [
    { sec: "A · Globalisation (Q1 — compulsory)", q: "1(a)", s: "Explain one reason why [switched off from globalisation / trade pattern / cultural diffusion] (4m)", m: 4 },
    { sec: "A · Globalisation", q: "1(b)", s: "Assess the positive and negative impacts of / the extent to which… [12m extended writing on globalisation or 'westernised' culture]", m: 12 },
    { sec: "A · Superpowers (Q2 — compulsory)", q: "2(a)", s: "Explain one reason why [countries join economic alliances / superpowers maintain status] (4m)", m: 4 },
    { sec: "A · Superpowers", q: "2(b)", s: "Assess the importance of [hard power / soft power / technology in maintaining superpower status] (12m)", m: 12 },
    { sec: "B · Shaping Places (Q3 Regenerating OR Q4 Diverse)", q: "3a(i) / 4a(i)", s: "Suggest one reason why [voter turnout / ethnic diversity / deprivation affects place] (3m)", m: 3 },
    { sec: "B · Shaping Places", q: "3a(ii) / 4a(ii)", s: "Suggest why [deprivation / ethnic diversity / living spaces / functions vary] [6m using figures + named places]", m: 6 },
    { sec: "B · Shaping Places", q: "3b / 4b", s: "Explain the reasons for [variation in place functions / representation / economic change] [6m using named local + contrasting place]", m: 6 },
    { sec: "B · Shaping Places", q: "3c / 4c", s: "Evaluate the success of [rebranding / regeneration / diversity strategies] [20m essay]", m: 20 },
    { sec: "C · Global Development (Q5 Health OR Q6 Migration)", q: "5a / 6a", s: "Explain [health burden in a country / patterns of migration / intervention rationale] (6m)", m: 6 },
    { sec: "C · Global Development", q: "5b / 6b", s: "Assess the role of / Evaluate the extent to which… [12m extended writing]", m: 12 },
    { sec: "C · Global Development", q: "5c / 6c", s: "'[Statement about health inequalities, migration consequences or human rights]' — Evaluate [20m essay]", m: 20 },
  ];
}
function geoEdexcelALevel3() {
  /* 9GE0/03 Synoptic Investigation — 70m, 2h 15m (spend 15 min reading the resource booklet)
     Must link Physical (Paper 1) and Human (Paper 2) content in answers */
  return [
    { sec: "Resource Booklet — read first (15 min)", q: "intro", s: "Read the provided resource booklet carefully before answering. Synoptic links between physical and human geography are expected throughout.", m: 0 },
    { sec: "Synoptic Questions (using booklet)", q: "1", s: "Use the resource booklet to describe / interpret geographical data or patterns [4–8m]", m: 8 },
    { sec: "Synoptic Extended Writing", q: "2", s: "Assess / evaluate [24m synoptic question — integrate physical and human content from Papers 1 and 2]", m: 24 },
    { sec: "Synoptic Essay", q: "3", s: "'[Statement]' — Evaluate this view. [38m main synoptic essay — must weave together physical and human geography themes]", m: 38 },
  ];
}
const EDEXCEL_ALEVEL_GEO = [
  { id: "geo_edexcel_alevel_p1", board: "Edexcel", level: "A Level", subject: "Geography",
    name: "Dynamic Landscapes (Physical Geography)", short: "Dyn. Landscapes",
    icon: Mountain, paper: "Paper 1", option: "9GE0/01", code: "9GE0/01",
    duration: "2h 15m", marks: 105, weight: "30%",
    env: "Section A · Tectonic Processes & Hazards (16m, compulsory) | Section B · Landscape Systems: Glaciated (Q2) or Coastal (Q3) (40m, choose 1) | Section C · Water Cycle & Water Insecurity + Carbon Cycle & Energy Security (49m, compulsory)",
    structure: geoEdexcelALevel1() },
  { id: "geo_edexcel_alevel_p2", board: "Edexcel", level: "A Level", subject: "Geography",
    name: "Dynamic Places (Human Geography)", short: "Dyn. Places",
    icon: Landmark, paper: "Paper 2", option: "9GE0/02", code: "9GE0/02",
    duration: "2h 15m", marks: 105, weight: "30%",
    env: "Section A · Globalisation (Q1) + Superpowers (Q2) — both compulsory (32m) | Section B · Shaping Places: Regenerating (Q3) or Diverse (Q4) (35m, choose 1) | Section C · Global Development: Health/Human Rights (Q5) or Migration/Identity (Q6) (38m, choose 1)",
    structure: geoEdexcelALevel2() },
  { id: "geo_edexcel_alevel_p3", board: "Edexcel", level: "A Level", subject: "Geography",
    name: "Synoptic Investigation", short: "Synoptic Inv.",
    icon: Target, paper: "Paper 3", option: "9GE0/03", code: "9GE0/03",
    duration: "2h 15m", marks: 70, weight: "20%",
    env: "Resource booklet provided in the exam (15 min reading time advised). All questions must integrate physical (P1) and human (P2) geography. Strongest answers make explicit synoptic links.",
    structure: geoEdexcelALevel3() },
];
TOPICS.push(...EDEXCEL_ALEVEL_GEO);
TOPICS.push(...GEO_TOPICS);
TOPICS.forEach((t) => { if (!t.board) t.board = t.level === "A Level" ? "AQA" : "Edexcel"; });
TOPICS.forEach((t) => { if (!t.subject) t.subject = "History"; });

