  // ─── AQA A-Level Geography Paper 3 (7037/3) — 2022, 2023, 2024 ───────────
  // Structure idx: 0=planning (4m) | 1=reliability (6m) | 2=evaluate (9m) | 3=significance (14m) | 4=synoptic (27m)
  "geo_aqa_alevel_p3-2024-1-0": { summary: "Independent Investigation (NEA) Q2 — Assess the reliability and accuracy of the data collection methods used in your independent investigation and the data collected [6m]", topic: "NEA fieldwork — assess reliability of methods and data", markScheme: "6m: L3 (5-6m): clear, explained argument using specific examples; for \"assess\" questions, considers more than one viewpoint. L2 (3-4m): partial explanation with some examples. L1 (1-2m): descriptive or limited." },
  "geo_aqa_alevel_p3-2024-2-0": { summary: "Independent Investigation (NEA) Q3 — Evaluate the extent to which your independent investigation was successful in achieving its aims, with reference to the conclusions drawn [9m]", topic: "NEA fieldwork — evaluate success and conclusions drawn", markScheme: "9m: L4 (8-9m): clear organised analysis of trends/patterns with accurate data and specific place knowledge. L3 (6-7m): explained with some data. L2 (3-5m): partial explanation. L1 (1-2m): descriptive." },
  "geo_aqa_alevel_p3-2024-3-0": { summary: "Independent Investigation (NEA) Q4 — Reflect on the wider geographical significance of your independent investigation: how does it relate to the wider issues, processes and patterns in geography? [14m]", topic: "NEA fieldwork — reflect on wider geographical significance", markScheme: "4m: L2 (3-4m): explained point with named example or accurate data. L1 (1-2m): simple statement." },
  "geo_aqa_alevel_p3-2024-4-0": { summary: "Synoptic Geography Q5 — Using the resource material provided and your own knowledge, analyse and evaluate [the geographical issue or management decision in the unfamiliar context provided]. [27m synoptic essay]", topic: "Synoptic geography — evaluate using unfamiliar resource material [27m]", markScheme: "L4 (13-16m): Sustained, balanced argument explaining at least two aspects; well-supported overall judgement. AO1 (knowledge) up to 4m | AO2 (analysis) up to 12m. L3 (9-12m): Explains at least two aspects. L2 (5-8m): Some explanation of one or more aspects. L1 (1-4m): Simple, generalised comments." },

  "geo_aqa_alevel_p3-2023-1-0": { summary: "Independent Investigation (NEA) 2023 Q2 — Assess the reliability of the data collection methods used in your independent investigation [6m]", topic: "NEA fieldwork 2023 — assess data collection reliability", markScheme: "6m: L3 (5-6m): clear, explained argument using specific examples; for \"assess\" questions, considers more than one viewpoint. L2 (3-4m): partial explanation with some examples. L1 (1-2m): descriptive or limited." },
  "geo_aqa_alevel_p3-2023-2-0": { summary: "Independent Investigation (NEA) 2023 Q3 — Evaluate the success of your independent investigation [9m]", topic: "NEA fieldwork 2023 — evaluate investigation success", markScheme: "9m: L4 (8-9m): clear organised analysis of trends/patterns with accurate data and specific place knowledge. L3 (6-7m): explained with some data. L2 (3-5m): partial explanation. L1 (1-2m): descriptive." },
