  "geo_edexcel_alevel_p3-2024-1-0": { summary: "Synoptic Investigation 2024 — Q1: Use the resource booklet to describe / analyse / interpret geographical data or patterns [8m — AO3 focus using booklet material]", topic: "Synoptic Investigation 2024 — analyse booklet data [8m]", markScheme: "12m (+3 SPaG): L4 (10-12m): Decision justified with specific evidence from the resource booklet; evaluates trade-offs and considers alternatives. L3 (7-9m): Justified with some evidence. L2 (4-6m): Partial justification. L1 (1-3m): States decision only." },
  "geo_edexcel_alevel_p3-2024-2-0": { summary: "Synoptic Investigation 2024 — Q2: Assess / evaluate [24m synoptic question — integrate physical and human content from Papers 1 and 2, using resource booklet material]", topic: "Synoptic Investigation 2024 — assess with P1+P2 links [24m]", markScheme: "12m (+3 SPaG): L4 (10-12m): Decision justified with specific evidence from the resource booklet; evaluates trade-offs and considers alternatives. L3 (7-9m): Justified with some evidence. L2 (4-6m): Partial justification. L1 (1-3m): States decision only." },
  "geo_edexcel_alevel_p3-2024-3-0": { summary: "Synoptic Investigation 2024 — Q3: 'Statement about the geographical issue in the resource booklet.' Evaluate this view. [38m essay — must weave together physical and human geography with synoptic links]", topic: "Synoptic Investigation 2024 — evaluate view, 38m synoptic essay", markScheme: "12m (+3 SPaG): L4 (10-12m): Decision justified with specific evidence from the resource booklet; evaluates trade-offs and considers alternatives. L3 (7-9m): Justified with some evidence. L2 (4-6m): Partial justification. L1 (1-3m): States decision only." },

  "geo_edexcel_alevel_p3-2023-1-0": { summary: "Synoptic Investigation 2023 — Q1: Analyse / interpret data from the resource booklet [8m]", topic: "Synoptic Investigation 2023 — analyse booklet data [8m]", markScheme: "8m: L4 (7-8m): detailed, well-organised analysis using specific located examples; evaluates evidence. L3 (5-6m): mostly explained with some specificity. L2 (3-4m): some explanation. L1 (1-2m): mainly descriptive." },
  "geo_edexcel_alevel_p3-2023-2-0": { summary: "Synoptic Investigation 2023 — Q2: Assess synoptic issue using physical and human geography knowledge [24m]", topic: "Synoptic Investigation 2023 — assess P1+P2 links [24m]", markScheme: "4m: L2 (3-4m): explained point with named example or accurate data. L1 (1-2m): simple statement." },
