  "geo_edexcel_alevel_p3-2022-1-0": { summary: "Synoptic Investigation 2022 — Q1: Analyse data from the resource booklet [8m]", topic: "Synoptic Investigation 2022 — analyse booklet data [8m]", markScheme: "8m: L4 (7-8m): detailed, well-organised analysis using specific located examples; evaluates evidence. L3 (5-6m): mostly explained with some specificity. L2 (3-4m): some explanation. L1 (1-2m): mainly descriptive." },
  "geo_edexcel_alevel_p3-2022-2-0": { summary: "Synoptic Investigation 2022 — Q2: Assess using synoptic links between physical and human [24m]", topic: "Synoptic Investigation 2022 — assess synoptic [24m]", markScheme: "4m: L2 (3-4m): explained point with named example or accurate data. L1 (1-2m): simple statement." },
