  // Edexcel GCSE History — migration 2018 and 2019 (partial coverage fix)
  "migration-2018-0-0": { summary: "Q01 — Source analysis: assess the usefulness of two sources for studying [migration to Britain in a specified period] [8m]", topic: "Migration to Britain 2018 — source usefulness [8m]", markScheme: "L5 (25-30m): Sustained, critical evaluation of ALL sources using NOP (nature, origin, purpose) + substantial contextual knowledge; clear, evidenced overall judgement on the enquiry question. L4 (19-24m): Evaluates all sources analytically. L3 (13-18m): Evaluates most sources. L2 (7-12m): Describes or partially evaluates. L1 (1-6m): Describes." },
  "migration-2018-1-0": { summary: "Q02 — Describe two features of [migration to Britain in a specified period, e.g. Irish immigration 1840s / Commonwealth migration 1948-70] [4m]", topic: "Migration 2018 — describe two features [4m]", markScheme: "4m: Give ONE feature — 2m for identifying the feature with 2m for supporting detail. (Or: 2 x [1m feature + 1m detail] for two features.) Must be distinct features from the specified period/source." },
