  "migration-2024-3-0": { summary: "Similar opportunities for Jewish migrants: medieval vs c1700–1900 Britain", topic: "Migration c800–c1500",
    markScheme: "L1 (1–2): a general similarity. L2 (3–4): a developed comparison, e.g. economic opportunities in both (William I's merchants vs Royal Exchange trading), or antisemitism limiting both (lost property vs university bans until 1871)." },
  "migration-2024-4-0": { summary: "Why attitudes to migration changed in Britain, 1900–present", topic: "Migration c1900–present",
    markScheme: "L1–4 reward range and depth. Key turning points: the 1905 Aliens Act, Kindertransport refugees, post-war recruitment (London Transport, NHS staff from the Caribbean), Powell's 1968 'Rivers of Blood' speech, and recent refugee crises." },
