/* ---------- series (date-aware: rolls forward automatically each year) ---------- */
function seriesFor(level) {
  const start = level === "A Level" ? 2017 : 2018;
  const cancelled = [2020, 2021];
  const now = new Date();
  const cy = now.getFullYear();
  const releasedThisYear = now.getMonth() >= 7; // results out ~mid-August
  const arr = [];
  for (let y = start; y <= cy; y++) {
    const status = cancelled.includes(y) ? "cancelled" : y < cy ? "sat" : releasedThisYear ? "sat" : "pending";
    arr.push({ year: y, status });
  }
  if (releasedThisYear) arr.push({ year: cy + 1, status: "pending" }); // next series shown as upcoming
  return arr;
}
const realYears = (level) => seriesFor(level).filter((s) => s.status === "sat").map((s) => s.year);
const pendingYearFor = (level) => { const p = seriesFor(level).find((s) => s.status === "pending"); return p ? p.year : new Date().getFullYear(); };
const topicsIn = (b, l, s = "History") => TOPICS.filter((t) => t.board === b && t.level === l && t.subject === s);
const boardSpecLabel = (b, s = "History") =>
  s === "Geography"
    ? (b === "AQA" ? "AQA 8035 (GCSE) · 7037 (AL)" : b === "OCR" ? "OCR J383 (GCSE)" : "Edexcel 1GB0 (GCSE) · 9GE0 (AL)")
    : (b === "AQA" ? "AQA 8145 / 7042" : b === "OCR" ? "OCR J411 / H505" : "Edexcel 1HI0 / 9HI0");

/* ---------- local keyword-based topic tagger (no network, instant) ---------- */
const TAG_STOPWORDS = new Set([
  "the","a","an","of","to","in","on","for","and","or","how","why","what","which","who","were","was","is","are",
  "with","by","from","that","this","these","those","their","its","as","at","be","do","did","does","into","about",
  "over","under","between","during","through","using","explain","describe","compare","account","convincing","write",
  "source","sources","interpretation","interpretations","useful","important","importance","significance","significant",
  "far","agree","factor","factors","main","two","features","ways","way","changes","changed","change","contextual",
  "knowledge","study","studies","more","most","you","your","did","extent","statement","question","marks","one","both",
  "people","period","britain","england","analysis","develop","developed","development","impact","affected"
]);
const tagTokens = (s) => (s || "").toLowerCase().match(/[a-z0-9]{3,}/g)?.filter((t) => !TAG_STOPWORDS.has(t)) || [];
/* Normalise a question-number label so "Q01", "q 01", "01" etc. all compare equal — the AI sometimes
   echoes back the "Q"-prefixed form shown in the prompt's question list instead of the bare number. */
const normQ = (s) => String(s ?? "").toLowerCase().replace(/^q/, "").replace(/[^a-z0-9]/g, "").replace(/^0+(?=\d)/, "");
/* Some combined-paper codes (OCR's "J411/1X"/"J411/3X", AQA's two-option Paper 1/2 codes) use a placeholder
   suffix because the real suffix depends on which OTHER option a student is paired with — that placeholder
   isn't searchable and would actively hurt web-search relevance, so describe it instead of stating it as fact. */
const codeHint = (t) => (/[X·]|\/.*\//.test(t.code))
  ? `${t.code.split("/")[0]} — the exact component code depends on which other option this is paired with, so don't rely on that code alone`
  : `spec code ${t.code}`;
/* AI responses that use the web-search tool can spend a lot of their token budget on the searches
   themselves, so the trailing JSON sometimes gets cut off mid-array. A plain indexOf("[")/lastIndexOf("]")
   slice then fails to parse and the WHOLE response is discarded. Instead, try that first, but if it fails
   (or finds nothing), salvage whichever individual {...} objects ARE complete — partial results are still useful. */
function extractJsonArray(text) {
  const a = text.indexOf("["), b = text.lastIndexOf("]");
  if (a !== -1 && b > a) {
    try { const arr = JSON.parse(text.slice(a, b + 1)); if (Array.isArray(arr)) return arr; } catch {}
  }
  const out = [];
  const re = /\{[^{}]*\}/g; let m;
  while ((m = re.exec(text))) { try { out.push(JSON.parse(m[0])); } catch {} }
  return out;
}
function guessSpecArea(areas, text) {
  const qTokens = tagTokens(text);
  if (!areas || !areas.length || !qTokens.length) return "";
  let best = "", bestScore = 0;
  for (const area of areas) {
    const aTokens = tagTokens(area);
    let score = 0;
    qTokens.forEach((t) => {
      if (aTokens.includes(t)) score += t.length >= 5 ? 2 : 1;
      else if (t.length >= 5 && aTokens.some((a) => a.length >= 5 && a.slice(0, 5) === t.slice(0, 5))) score += 1;
    });
    if (score > bestScore) { bestScore = score; best = area; }
  }
  return bestScore > 0 ? best : "";
}

function buildScaffold() {
  const out = {};
  TOPICS.forEach((t) => {
    const rows = [];
    const isEdexcelGCSE = t.board === "Edexcel" && t.level === "GCSE";
    if (!t.structure || !Array.isArray(t.structure)) { out[t.id] = []; return; }
    realYears(t.level).forEach((yr) => {
      t.structure.forEach((r, i) => {
        if (!r || r.q == null) return;
        r.q.split(" / ").forEach((qn, j) => {
          const genericMs = isEdexcelGCSE && r.m === 16 && r.spag ? GENERIC_MS_16 : isEdexcelGCSE && r.m === 12 ? GENERIC_MS_12 : "";
          rows.push({ id: `${t.id}-${yr}-${i}-${j}`, series: yr, paper: t.paper, qNumber: qn.trim(),
            summary: r.s, topic: "", marks: r.m, spag: !!r.spag, extended: !!r.extended, markScheme: genericMs, source: "scaffold" });
        });
      });
    });
    out[t.id] = rows;
  });
  return out;
}
const escapeHtml = (s) => String(s == null ? "" : s).replace(/[&<>"]/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[ch]));

/* =========================================================================== */
class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(e) { return { error: e }; }
  componentDidCatch(e, info) { console.error("ExamChronicle crash:", e, info); }
  render() {
    if (this.state.error) {
      const msg = String(this.state.error?.message || this.state.error);
      const stack = this.state.error?.stack ? "\n\n" + this.state.error.stack.split("\n").slice(0,6).join("\n") : "";
      return (
        <div style={{ padding: "2rem", fontFamily: "system-ui,sans-serif", maxWidth: 640, margin: "2rem auto" }}>
          <h2 style={{ color: "#991B1B", fontWeight: 700, marginBottom: "0.75rem" }}>⚠ Exam Chronicle error</h2>
          <p style={{ color: "#374151", fontSize: "0.875rem", marginBottom: "1rem" }}>
            An error occurred. Copy the details below and use Try again, or reload the page.
          </p>
          <pre style={{ background: "#FEF2F2", border: "1px solid #FCA5A5", borderRadius: 6, padding: "1rem",
            fontSize: "0.7rem", color: "#7F1D1D", overflowX: "auto", whiteSpace: "pre-wrap", wordBreak: "break-all" }}>
{msg}{stack}
          </pre>
          <button onClick={() => this.setState({ error: null })}
            style={{ marginTop: "1rem", padding: "0.5rem 1.25rem", background: "#6B2D3E", color: "#fff", border: "none", borderRadius: 6, cursor: "pointer" }}>
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}


