            const _gr = _cp<0?null:_cp>=85?"A":_cp>=70?"B":_cp>=55?"C":_cp>=40?"D":"E";
            const _gc = !_gr?null:_gr==="A"?"#059669":_gr==="B"?"#0D9488":_gr==="C"?"#C9A84C":_gr==="D"?"#D97706":"#DC2626";
