                {(() => { const pct = topicConfPct(data[t.id]); return pct >= 0 ? <ConfRing pct={pct} size={18} /> : null; })()}
              {n > 0 && <span className="font-mono text-[10px] rounded-full px-1.5 py-0.5 font-bold" style={{ background: on ? c.oxbloodSoft : c.lineSoft, color: on ? c.oxblood : c.mute }}>{n}</span>}
