/* ─── ResourceChips ─ textbooks & revision guide links ─── */
function ResourceChips({ topic }) {
  const [open, setOpen] = React.useState(false);
  const links = getTopicResources(topic);
  if (!links.length) return null;
  const kindColor = { spec: "#1E40AF", textbook: "#166534", revision: "#6D28D9" };
  const kindBg   = { spec: "#EFF6FF", textbook: "#F0FDF4", revision: "#F5F3FF" };
  const kindLabel = { spec: "Official", textbook: "Textbook", revision: "Revision" };
  return (
    <div className="mt-3">
      <button onClick={() => setOpen(o => !o)}
        className="inline-flex items-center gap-1.5 font-mono text-[10px] rounded px-2 py-1"
        style={{ background: "#F5F3FF", color: "#6D28D9", border: "1px solid #DDD6FE" }}>
        📚 {open ? "Hide resources ▾" : "Textbooks & revision guides ▸"}
      </button>
      {open && (
        <div className="mt-2 flex flex-wrap gap-1.5">
          {links.map((l, i) => (
            <a key={i} href={l.url} target="_blank" rel="noopener noreferrer"
              className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-2 py-1 no-underline"
              style={{ background: kindBg[l.kind] || "#F9FAFB", color: kindColor[l.kind] || "#374151",
                border: `1px solid ${kindColor[l.kind] || "#D1D5DB"}44` }}>
              <span style={{ fontSize: 9, fontWeight: 700, opacity: 0.7 }}>{kindLabel[l.kind] || l.kind}</span>
              {l.label} ↗
            </a>
          ))}
        </div>
      )}
    </div>
  );
}
/* ------------------------------- topic panel ------------------------------- */
/* ═══════════════════════════════════════════════════════════════════════════
   QuestionMarker — AI-powered conservative mark-scheme grading via photo
   Edexcel GCSE & A-Level History focus; AO breakdown per question type.
   ═══════════════════════════════════════════════════════════════════════════ */

function getAOBreakdown(topic, entry) {
  const m = Number(entry.marks) || 0;
  const q = String(entry.qNumber || "");
  const spag = !!entry.spag;
  const level = topic.level || "GCSE";
  const summary = (entry.summary || "").toLowerCase();

  if (level === "GCSE") {
    // 7-slot thematic (medicine/warfare/crime/migration) & 4-slot (elizabethan etc.)
    if (q === "1" && m <= 4) return { ao1: m };                              // describe features
    if ((q === "2(a)" || q === "2a") && m === 8) return { ao3: 8 };          // source utility
    if ((q === "2(b)" || q === "2b") && m <= 4) return { ao4: 4 };           // follow-up enquiry
    if (q === "3" && m === 4) return { ao4: 4 };                              // similarity
    if (q === "4" && m === 12) return { ao1: 4, ao2: 8 };                    // explain why
    if ((q === "5" || q === "6") && m === 16) return spag ? { ao1: 4, ao2: 12, spag: 4 } : { ao1: 4, ao2: 12 };
    // British depth & period studies
    if (q === "1(a)" && m <= 4) return { ao1: m };
    if (q === "1(b)" && m === 12) return { ao1: 4, ao2: 8 };
    if ((q === "1(c)(i)" || q === "1(c)(ii)") && m === 16) return spag ? { ao1: 4, ao2: 12, spag: 4 } : { ao1: 4, ao2: 12 };
    if (q === "1" && m === 8) return { ao1: 4, ao2: 4 };                     // period study Q1
    if (q === "2" && m === 8) return { ao2: 8 };                              // narrative account
    if (q === "3" && m === 16) return { ao1: 8, ao2: 8 };                    // importance essay
    // Paper 3 modern depth / Paper 2 (russia, maoschina, usa5475)
    if (q === "1" && m === 4) return { ao3: 4 };                             // source inference
    if (q === "2" && m === 12) return { ao1: 4, ao2: 8 };                    // explain why
    if ((q === "3(a)" || q === "3a") && m === 8) return { ao3: 8 };          // source utility
    if ((q === "3(b)" || q === "3b") && m === 4) return { ao4: 4 };          // interp difference
    if ((q === "3(c)" || q === "3c") && m === 4) return { ao4: 4 };          // reason for diff
    if ((q === "3(d)" || q === "3d") && m === 16) return spag ? { ao1: 4, ao2: 8, ao4: 4, spag: 4 } : { ao1: 4, ao2: 8, ao4: 4 };
    return m <= 4 ? { ao1: m } : m <= 8 ? { ao1: Math.ceil(m/2), ao2: Math.floor(m/2) } : { ao1: 4, ao2: m - 4 };
  } else {
    // A-Level
    if (m === 20) {
      if (summary.includes("interpret") || q.toLowerCase().includes("c")) return { ao1: 5, ao2: 5, ao4: 10 };
      if (summary.includes("source") || summary.includes("extract")) return { ao3: 20 };
      return { ao1: 10, ao2: 10 };
    }
    if (m === 30) {
      if (summary.includes("interpret") || summary.includes("controversy")) return { ao1: 10, ao2: 10, ao4: 10 };
      return { ao1: 15, ao2: 15 };
    }
    if (m === 25) return { ao1: 10, ao2: 15 };
    if (m === 40) return { ao1: 20, ao2: 20 };
    return { ao1: Math.ceil(m/2), ao2: Math.floor(m/2) };
  }
}

function aoLabel(key) {
  return { ao1: "AO1 Knowledge", ao2: "AO2 Analysis", ao3: "AO3 Sources", ao4: "AO4 Interpretations", spag: "SPaG" }[key] || key.toUpperCase();
}
function aoColour(key) {
  return { ao1: "#1E40AF", ao2: "#065F46", ao3: "#7C3AED", ao4: "#9A3412", spag: "#1F2937" }[key] || "#374151";
}
function aoBg(key) {
  return { ao1: "#EFF6FF", ao2: "#ECFDF5", ao3: "#F5F3FF", ao4: "#FFF7ED", spag: "#F9FAFB" }[key] || "#F3F4F6";
}

