async function batchFillSources(topic, entries, onBulk, provider, apiKey, endpoint, setStatus) {
  const toFill = entries.filter(e => {
    if (e.source === "scaffold" || e.sourceText || e.interp1) return false;
    const q = String(e.qNumber||"");
    return !!q.match(/^1$|^2\(a\)$|^3\(a\)$|^2a$|^3a$|^3\(b\)$|^3\(c\)$|^3\(d\)$|^01$|^02$|^03$/);
  });
  if (!toFill.length) { setStatus("All source questions already filled ✓"); setTimeout(()=>setStatus(""),3000); return; }
  setStatus(`AI filling ${toFill.length} questions…`);
  const specAreas = (SPEC_AREAS[topic.id]||[]).join(", ");
  let filled=0;
  const updated=[...entries];
  for (const e of toFill) {
    const q=String(e.qNumber||""), isInterp=!!q.match(/^3\(b\)$|^3\(c\)$|^3\(d\)$|^01$|^02$|^03$/);
    const prompt = isInterp
      ? `History revision app. Topic: ${topic.name} (${topic.board} ${topic.level}, ${e.series}). Q: ${e.summary}. Spec: ${specAreas}. Generate TWO contrasting historian interpretations (real historians + book + year + 2-3 sentence extract). JSON only: {"text1":"...","text2":"..."}`
      : `History revision app. Topic: ${topic.name} (${topic.board} ${topic.level}, ${e.series}). Q: ${e.summary}. Spec: ${specAreas}. Generate TWO period-appropriate primary source extracts (attribution + 2-3 sentence extract). JSON only: {"text1":"...","text2":"..."}`;
    try {
      const raw = await callAIText({ provider, apiKey, endpoint, prompt });
      const p = JSON.parse(raw.replace(/```json|```/g,"").trim());
      const i=updated.findIndex(x=>x.id===e.id);
      if (i>=0) { if(isInterp) updated[i]={...updated[i],interp1:p.text1||"",interp2:p.text2||""}; else updated[i]={...updated[i],sourceText:p.text1||"",interp1:p.text2||""}; filled++; }
      setStatus(`Filling… ${filled}/${toFill.length}`);
    } catch {}
    await new Promise(r=>setTimeout(r,300));
  }
  onBulk(updated);
  setStatus(`Done — filled ${filled} questions ✓`);
  setTimeout(()=>setStatus(""),4000);
}

const CONF = [
  { icon: "○", label: "Not attempted", bg: "#F1F5F9", color: "#94A3B8", ring: "#E2E8F0" },
  { icon: "◑", label: "Attempted",     bg: "#FFF7ED", color: "#D97706", ring: "#FCD34D" },
  { icon: "●", label: "Confident",     bg: "#ECFDF5", color: "#059669", ring: "#6EE7B7" },
];
function ConfidenceBtn({ value = 0, onToggle, size = 28 }) {
  const c2 = CONF[value] || CONF[0];
  const [bounce, setBounce] = React.useState(false);
  function handleClick(e) {
    e.stopPropagation(); setBounce(true); haptic("light");
    setTimeout(()=>setBounce(false),300);
    onToggle((value+1)%3);
  }
  return (
    <button onClick={handleClick} title={c2.label}
      className="grid place-items-center rounded-lg flex-shrink-0 font-bold text-xs select-none"
      style={{ width:size, height:size, background:c2.bg, color:c2.color, border:`1px solid ${c2.color}35`,
        transition:"all 0.2s", transform:bounce?"scale(1.35)":"scale(1)" }}>
      {c2.icon}
    </button>
  );
}
function ConfRing({ pct, size = 20 }) {
  const r = (size / 2) - 2.5;
  const circ = 2 * Math.PI * r;
  return (
    <svg width={size} height={size} className="flex-shrink-0" style={{transform:"rotate(-90deg)"}}>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="#E2E8F0" strokeWidth="2.5" />
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="#C9A84C" strokeWidth="2.5"
        strokeDasharray={circ} strokeDashoffset={circ * (1 - pct / 100)}
        strokeLinecap="round"
        style={{transition:"stroke-dashoffset 0.6s cubic-bezier(0.4,0,0.2,1), stroke 0.3s ease"}} />
    </svg>
  );
}
function topicConfPct(entries) {
  const verified = (entries || []).filter(e => e.source !== "scaffold");
  if (!verified.length) return -1;
  const conf = verified.filter(e => e.confidence === 2).length;
  return Math.round(conf / verified.length * 100);
}


/* ─── Source / Interpretation info card ──────────────────────────────────── */
function SourceTextDisplay({ entry, topic }) {
  if (!entry.sourceText && !entry.interp1 && !entry.interp2) return null;
  const qn = String(entry.qNumber||"");
  const isInterp = !!qn.match(/3\(b\)|3\(c\)|3\(d\)|3b$|3c$|3d$|^01$|^02$|^03$/);
  const hasTwoSrc = !!qn.match(/2\(a\)|3\(a\)|2a$|3a$/);

  if (isInterp && (entry.interp1 || entry.interp2)) return (
    <div className="rounded-xl overflow-hidden mb-2" style={{ border:"1px solid #DDD6FE" }}>
      <div className="px-3 py-2" style={{ background:"#7C3AED", color:"#fff" }}>
        <p className="text-[10px] font-mono font-bold tracking-widest">📜 INTERPRETATIONS FROM THE PAPER</p>
      </div>
      {entry.interp1 && <div className="px-3 py-2.5" style={{ borderBottom: entry.interp2?"1px solid #EDE9FE":"none" }}>
        <p className="text-[10px] font-mono font-bold mb-1" style={{ color:"#7C3AED" }}>INTERPRETATION 1</p>
        <p className="text-xs leading-relaxed italic" style={{ color:"#3B0764" }}>"{entry.interp1}"</p>
      </div>}
      {entry.interp2 && <div className="px-3 py-2.5">
        <p className="text-[10px] font-mono font-bold mb-1" style={{ color:"#7C3AED" }}>INTERPRETATION 2</p>
        <p className="text-xs leading-relaxed italic" style={{ color:"#3B0764" }}>"{entry.interp2}"</p>
      </div>}
    </div>
  );

  return (
    <div className="rounded-xl overflow-hidden mb-2" style={{ border:"1px solid #BFDBFE" }}>
      <div className="px-3 py-2" style={{ background:"#2563EB", color:"#fff" }}>
        <p className="text-[10px] font-mono font-bold tracking-widest">🔍 SOURCE{hasTwoSrc&&entry.interp1?"S":""} FROM THE PAPER</p>
      </div>
      {entry.sourceText && <div className="px-3 py-2.5" style={{ borderBottom: (hasTwoSrc&&entry.interp1)?"1px solid #DBEAFE":"none" }}>
        <p className="text-[10px] font-mono font-bold mb-1" style={{ color:"#2563EB" }}>{hasTwoSrc?"SOURCE A":"SOURCE A"}</p>
        <p className="text-xs leading-relaxed" style={{ color:"#1E3A5F" }}>{entry.sourceText}</p>
      </div>}
      {hasTwoSrc && entry.interp1 && <div className="px-3 py-2.5">
        <p className="text-[10px] font-mono font-bold mb-1" style={{ color:"#2563EB" }}>SOURCE B</p>
        <p className="text-xs leading-relaxed" style={{ color:"#1E3A5F" }}>{entry.interp1}</p>
      </div>}
    </div>
  );
}


function SourceInfoCard({ info }) {
  if (!info) return null;
  const isInterp = info.type === "interp";
  const bg    = isInterp ? "#F5F3FF" : "#EFF6FF";
  const color = isInterp ? "#7C3AED"  : "#2563EB";
  const icon  = isInterp ? "📜" : "🔍";
  return (
    <div className="rounded-xl p-3 space-y-2" style={{ background: bg, border:`1px solid ${color}20` }}>
      <div className="flex items-center gap-2">
        <span>{icon}</span>
        <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color }}>
          {isInterp ? "INTERPRETATION CONTEXT" : "SOURCE CONTEXT"}
        </span>
        {info.url && (
          <a href={info.url} target="_blank" rel="noopener noreferrer"
            className="ml-auto inline-flex items-center gap-1 text-[10px] font-semibold rounded-lg px-2 py-0.5"
            style={{ background: color+"15", color }}>
            Past papers <ExternalLink size={9} />
          </a>
        )}
      </div>
      {info.desc && <p className="text-xs leading-relaxed" style={{ color:"#1E3A5F" }}>{info.desc}</p>}
      {info.about && <p className="text-xs leading-relaxed" style={{ color:"#3B0764" }}>{info.about}</p>}
      {info.historians && (
        <div className="rounded-lg px-2.5 py-1.5" style={{ background:`${color}10` }}>
          <p className="text-[10px] font-semibold mb-0.5" style={{ color }}>Historians commonly cited</p>
          <p className="text-[11px]" style={{ color:"#4C1D95" }}>{info.historians}</p>
        </div>
      )}
      {info.url && (
        <a href={info.url} target="_blank" rel="noopener noreferrer"
          className="inline-flex items-center gap-1.5 text-[11px] font-semibold"
          style={{ color }}>
          <ExternalLink size={11} /> View official past papers →
        </a>
      )}
    </div>
  );
}


