function MobileExpandMs({ entry: e, topicId, onQuickUpdate }) {
  const [open, setOpen] = React.useState(false);
  if (!e.markScheme && !e.sourceText && !e.interp1) return null;
  return (
    <div className="mt-2">
      <button onClick={() => setOpen(o => !o)}
        className="flex items-center gap-1.5 text-[11px] font-semibold rounded-lg px-2.5 py-1 w-full"
        style={{ background: open ? "rgba(201,168,76,0.12)" : c.lineSoft, color: open ? "#C9A84C" : c.mute,
          border: `1px solid ${open ? "rgba(201,168,76,0.3)" : c.line}`, transition:"all 0.2s" }}>
        <span style={{ fontSize:10, transform: open ? "rotate(90deg)" : "rotate(0deg)", transition:"transform 0.25s", display:"inline-block" }}>▶</span>
        {open ? "Hide mark scheme" : "Show mark scheme"}
      </button>
      <div style={{ maxHeight: open ? 600 : 0, overflow:"hidden", transition:"max-height 0.35s cubic-bezier(0.4,0,0.2,1)", marginTop: open ? 6 : 0 }}>
        <SourceTextDisplay entry={e} topic={{id:topicId}} />
        <MarkSchemeNote text={e.markScheme} reportUrl={getExaminerReportUrl(topicId, e.series)} question={e.summary} marks={e.marks} />
      {typeof onQuickUpdate==="function" && <QuestionNote entry={e} onSave={(id,p)=>onQuickUpdate(topicId,id,p)} />}
      </div>
    </div>
  );
}


function Th({ children, className = "", light }) { return <th className={`px-4 py-2.5 text-xs font-semibold tracking-wide ${className}`} style={{ color: light ? c.inkSoft : "#fff" }}>{children}</th>; }
function Td({ children, className = "", style }) { return <td className={`px-4 py-3 align-top ${className}`} style={style}>{children}</td>; }
function MarkBadge({ m }) { return <span className="font-mono text-xs rounded px-2 py-0.5 inline-block" style={{ background: c.oxbloodSoft, color: c.oxblood, fontWeight: 600 }}>{m}</span>; }
function Badge({ children, color, bg }) { return <span className="ml-2 font-mono text-[10px] rounded px-1.5 py-0.5 align-middle whitespace-nowrap" style={{ background: bg, color }}>{children}</span>; }
function SpagTag() { return <span className="ml-2 font-mono text-[10px] rounded px-1.5 py-0.5 align-middle" style={{ background: c.tealSoft, color: c.teal }}>+4 SPaG</span>; }
function ExtTag() { return <span className="ml-2 font-mono text-[10px] rounded px-1.5 py-0.5 align-middle" style={{ background: c.brassSoft, color: c.brass }}>levels · QER</span>; }
function TopicAreaNote({ text }) {
  const [open, setOpen] = useState(false);
  if (!text) return null;
  return (
    <div className="mt-1">
      <button onClick={() => setOpen((o) => !o)} className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5" style={{ background: c.tealSoft, color: c.teal }}>
        <Info size={9} /> about this area {open ? "▾ hide" : "▸ show"}
      </button>
      {open && <p className="text-xs mt-1" style={{ color: c.inkSoft }}>{text}</p>}
    </div>
  );
}
function MarkSchemeNote({ text, reportUrl, question, marks }) {
  const [open, setOpen] = useState(false);
  const [whyOpen, setWhyOpen] = useState(false);
  const [whyText, setWhyText] = useState("");
  const [whyLoading, setWhyLoading] = useState(false);
  const { provider, apiKey, endpoint } = useAIProvider();

  async function explainWhy() {
    if (whyText) { setWhyOpen(w => !w); return; }
    setWhyLoading(true); setWhyOpen(true);
    const prompt = `You are an expert ${provider} examiner. Explain WHY these mark scheme points earn marks for this question.

Question: "${question || "exam question"}" [${marks || "?"}m]
Mark scheme:
${text}

Give a brief, student-friendly explanation (3-5 sentences) of:
1. Which Assessment Objectives are being tested
2. WHY these specific points earn marks (the examiner logic)
3. The most common mistake students make

Be concise and direct. No headers or bullet points — just clear prose.`;
    try {
      const resp = await callAIText({ provider, apiKey, endpoint, prompt });
      setWhyText(resp);
    } catch(e) { setWhyText("Unable to generate explanation. Check your API key in the Marker panel."); }
    setWhyLoading(false);
  }

  if (!text) return null;

  /* Parse into { level, items[] } */
  const parsed = (() => {
    const m = text.match(/^(L\d+:\s*[\d\u2013\-]+(?:\s*[\/+]\s*[\d\u2013\-]+)?)[.\s]+/);
    const level = m ? m[1] : null;
    const body  = m ? text.slice(m[0].length) : text;
    /* Split on "; " (semicolon-space) — the standard separator in these mark schemes */
    const raw = body.split(/;\s+/).map(s => s.trim()).filter(Boolean);
    /* Each segment may end with a stray trailing period — keep it tidy */
    return { level, items: raw };
  })();

  /* Detect "section header" items (For:, Against:, Source A:, Successes:, etc.) */
  const isSectionHead = (s) =>
    /^(For\b|Against\b|Source [A-C]\b|Successes?:|Failures?:|Content\b|Provenance\b|Strong answers|L[34]:|Evidence\b)/i.test(s);

  return (
    <div className="mt-1">
      <div className="inline-flex items-center gap-1.5 flex-wrap">
        <button
          onClick={() => setOpen(o => !o)}
          className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5"
          style={{ background: c.brassSoft, color: c.brass }}
        >
          <ClipboardCheck size={9} /> mark scheme {open ? "▾ hide" : "▸ show"}
        </button>
        {reportUrl && (
          <a
            href={reportUrl} target="_blank" rel="noopener noreferrer"
            className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5 no-underline"
            style={{ background: "#EFF6FF", color: "#1E40AF", border: "1px solid #BFDBFE" }}
          >
            <ExternalLink size={9} /> examiner report ↗
          </a>
        )}
      </div>

      {open && (
        <div className="mt-1.5 rounded p-2.5 text-xs" style={{ background: "#FAFAF9", border: `1px solid ${c.line}` }}>
          {parsed.level && (
            <p className="font-semibold mb-1.5" style={{ fontFamily: "monospace", fontSize: 10, color: c.brass }}>
              {parsed.level}
            </p>
          )}
          <ul className="space-y-1" style={{ color: c.inkSoft }}>
            {parsed.items.map((item, i) => {
              const head = isSectionHead(item);
              /* Distinguish "For:" vs "Against:" vs neutral bullets */
              const isFor = /^For\b/i.test(item);
              const isAgainst = /^Against\b/i.test(item);
              const dotColor = isFor ? c.teal : isAgainst ? c.oxblood : c.brass;
              return (
                <li key={i} className="flex gap-1.5 leading-snug">
                  <span style={{ color: dotColor, flexShrink: 0, marginTop: 2, fontWeight: 700 }}>•</span>
                  <span className={head ? "font-semibold" : ""}>{item}</span>
                </li>
              );
            })}
          </ul>
        </div>
      )}
      {/* Why? button — AI mark scheme explainer */}
      <div className="flex items-center gap-2 mt-1.5 flex-wrap">
        <button onClick={explainWhy}
          className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5 transition-all"
          style={{ background: whyOpen?"#0D1B2E":"rgba(13,27,46,0.07)", color: whyOpen?"#C9A84C":c.mute,
            border:`1px solid ${whyOpen?"rgba(201,168,76,0.4)":"transparent"}` }}>
          {whyLoading ? <Loader2 size={9} className="animate-spin"/> : "🤔"} why these marks?
        </button>
      </div>
      {whyOpen && (
        <div className="mt-1.5 rounded-xl p-2.5 text-[11px] leading-relaxed"
          style={{ background:"rgba(13,27,46,0.05)", border:"1px solid rgba(13,27,46,0.1)", color:c.ink }}>
          {whyLoading
            ? <span style={{color:c.mute}}>Analysing examiner logic…</span>
            : whyText}
        </div>
      )}
    </div>
  );
}
