/* --------------------------------- modal ----------------------------------- */
/* ═══════════════════════════════════════════════════════════════════════════
   compressImage + SourceRefModal — attach a screenshot or link to any
   source / interpretation question entry
   ═══════════════════════════════════════════════════════════════════════════ */
async function compressImage(file) {
  return new Promise((res, rej) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      const MAX = 900;
      const scale = img.width > MAX ? MAX / img.width : 1;
      const w = Math.round(img.width * scale), h = Math.round(img.height * scale);
      const canvas = document.createElement("canvas");
      canvas.width = w; canvas.height = h;
      canvas.getContext("2d").drawImage(img, 0, 0, w, h);
      URL.revokeObjectURL(url);
      res(canvas.toDataURL("image/jpeg", 0.78));
    };
    img.onerror = () => { URL.revokeObjectURL(url); rej(new Error("load failed")); };
    img.src = url;
  });
}

function qTypeColor(qNumber, marks) {
  const q = String(qNumber||"");
  if (q.match(/^1$/) && marks===4) return "#2563EB";
  if (q.match(/^2\(a\)$|^3\(a\)$/)) return "#7C3AED";
  if (q.match(/^3\(b\)$|^3\(c\)$/)) return "#7C3AED";
  if (q.match(/^3\(d\)$/)) return "#C9A84C";
  if (marks >= 16) return "#C9A84C";
  if (marks >= 8) return "#059669";
  if (marks >= 4) return "#0EA5E9";
  return null;
}
function qTypeIcon(qNumber, marks) {
  const q = String(qNumber||"");
  if (q.match(/^1$/) && marks===4) return "📖";
  if (q.match(/^2\(a\)$|^3\(a\)$/)) return "🔍";
  if (q.match(/^3\(b\)$|^3\(c\)$|^3\(d\)$/)) return "💬";
  if (marks >= 16) return "✍️";
  if (marks >= 8) return "📝";
  return null;
}


