function PrintRevisionSheet({ topic, entries }) {
  function doPrint() {
    const printWin = window.open("", "_blank");
    if (!printWin) { alert("Please allow popups to print."); return; }
    const visible = entries.filter(e => e.source !== "scaffold");
    const totalMarks = visible.reduce((s,e)=>s+(e.marks||0),0);
    const confLabels = ["Not started","In progress","Confident"];
    const confCols   = ["#94A3B8","#D97706","#059669"];
    const rows = visible.map((e,i) => {
      const conf = confLabels[e.confidence||0]; const col = confCols[e.confidence||0];
      const lines = Array.from({length:Math.max(3,(e.marks||3)*1.5|0)}).map(()=>'<div style="border-bottom:1px solid #ddd;height:22px"></div>').join("");
      const ms = e.markScheme ? '<div style="margin-top:6px;padding:8px 10px;background:#f8f8f6;border-left:3px solid #C9A84C;font-size:11px;line-height:1.6">'+e.markScheme.replace(/</g,"&lt;")+'</div>' : "";
      return '<div style="margin-bottom:24px;page-break-inside:avoid"><div style="display:flex;gap:12px"><div style="width:28px;height:28px;border-radius:50%;border:1.5px solid #1a1a1a;display:grid;place-items:center;font-size:11px;font-weight:700;flex-shrink:0">'+(i+1)+'</div><div style="flex:1"><div style="display:flex;justify-content:space-between;gap:8px"><p style="font-size:13px;font-weight:600;margin:0;line-height:1.4">'+e.summary.replace(/</g,"&lt;")+'</p><div><span style="font-size:10px;border:1.5px solid #1a1a1a;padding:2px 8px;font-family:monospace;font-weight:700">['+e.marks+'m]</span> <span style="font-size:9px;font-weight:700;border-radius:999px;padding:2px 8px;background:'+col+'22;color:'+col+'">'+conf+'</span></div></div>'+ms+'<div style="margin-top:8px">'+lines+'</div></div></div></div>';
    }).join('<hr style="border:none;border-top:1px dashed #ccc;margin:20px 0"/>');
    const html = "<!DOCTYPE html><html><head><meta charset=UTF-8><title>"+topic.name+" Revision Sheet</title>"
      + '<style>*{box-sizing:border-box}body{font-family:"Times New Roman",serif;color:#1a1a1a;margin:0;padding:32px 40px;font-size:13px}@media print{@page{size:A4;margin:20mm}body{padding:0}}</style></head><body>'
      + '<div style="border-bottom:3px solid #1a1a1a;padding-bottom:12px;margin-bottom:20px"><div style="display:flex;justify-content:space-between;align-items:flex-end"><div>'
      + '<p style="font-size:10px;font-weight:700;text-transform:uppercase;margin:0;color:#666">'+topic.board+' · '+topic.level+' · '+topic.subject+'</p>'
      + '<h1 style="font-size:22px;font-weight:700;margin:4px 0 2px">'+topic.name+'</h1>'
      + '<p style="font-size:10px;color:#888;margin:0">'+visible.length+' questions · '+totalMarks+' total marks</p></div>'
      + '<div style="text-align:right;font-size:10px;color:#aaa;font-family:monospace">EXAM CHRONICLE</div></div></div>'
      + rows + "<script>window.print();<\/script></body></html>";
    printWin.document.write(html); printWin.document.close();
  }
  return (
    <button onClick={doPrint}
      className="inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-semibold shrink-0"
      style={{ background:"#fff", color:c.inkSoft, border:"1px solid "+c.line }}>
      🖨 Print sheet
    </button>
  );
}


function useConfetti() {
  const [burst, setBurst] = React.useState(false);
  const [pos, setPos] = React.useState({x:0,y:0});
  function fire(x,y) { setPos({x,y}); setBurst(true); setTimeout(()=>setBurst(false),2200); }
  const el = burst ? (
    <div style={{position:"fixed",left:pos.x,top:pos.y,pointerEvents:"none",zIndex:9999}}>
      {Array.from({length:30}).map((_,i) => {
        const angle = (i/30)*360;
        const dist  = 40 + Math.random()*80;
        const col   = ["#C9A84C","#059669","#0D9488","#7C3AED","#EF4444","#F59E0B"][i%6];
        const size  = 5 + Math.random()*7;
        return (
          <div key={i} style={{
            position:"absolute",width:size,height:size,background:col,borderRadius:Math.random()>0.5?"50%":"2px",
            transform:"translate(-50%,-50%)",
            animation:"confetti-fall 2s ease-out forwards",
            animationDelay:(Math.random()*0.3)+"s",
            "--dx":(Math.cos(angle*Math.PI/180)*dist)+"px",
            "--dy":(Math.sin(angle*Math.PI/180)*dist)+"px",
          }} />
        );
      })}
    </div>
  ) : null;
  return { fire, el };
}


