function TopicPanel({ topic, entries, onSave, onDelete, onBulk, onQuickUpdate, data }) {
  const [filter, setFilter] = useState("all");
  const [paperMode, setPaperMode] = useState(false);
  const [topicFilter, setTopicFilter] = useState("all");
  const [query, setQuery] = useState("");
  const [verifiedOnly, setVerifiedOnly] = useState(false);
  const [editing, setEditing] = useState(null);
  const [fillYear, setFillYear] = useState("all");
  const [filling, setFilling] = useState(false);
  const aiProv = useAIProvider();
  const [marking, setMarking] = useState(null); // entry being AI-marked
  const confetti = useConfetti();
  // Check for 100% topic completion
  const prevConf = React.useRef(0);
  React.useEffect(() => {
    const verified = (entries||[]).filter(e=>e.source!=="scaffold");
    const all100 = verified.length>0 && verified.every(e=>e.confidence===2);
    if (all100 && prevConf.current !== verified.length) {
      prevConf.current = verified.length;
      confetti.fire(window.innerWidth/2, window.innerHeight/3);
    }
  }, [entries]);

  const [fillNote, setFillNote] = useState("");
  const Icon = topic.icon;
  const series = seriesFor(topic.level);
  const years = realYears(topic.level);
  const ex = EXAMINER[topic.id];
  const board = `${topic.board} ${topic.level === "A Level" ? "A-Level" : "GCSE"}`;
  const stemOf = (qn) => { const r = topic.structure.find((x) => x.q.split(" / ").map((p) => p.trim()).includes(qn)); return r ? r.s : ""; };

  function autoTagTopics() {
    let total = 0, pending = 0;
    const next = entries.map((e) => {
      if (e.topic) return e;
      if (e.source === "scaffold" || !e.summary) { pending++; return e; }
      const guess = guessSpecArea(SPEC_AREAS[topic.id] || [], e.summary);
      if (!guess) { pending++; return e; }
      total++; return { ...e, topic: guess, tagSource: "auto" };
    });
    onBulk(next);
    setFillNote(total
      ? "Tagged " + total + " question" + (total > 1 ? "s" : "") + " by keyword match against the spec — check and adjust any that look off." + (pending ? " " + pending + " more still show generic exam-board wording — use Auto-fill topics or edit a question to load its real focus, then run Auto-tag again." : "")
      : pending
        ? `${pending} question${pending > 1 ? "s" : ""} still show generic exam-board wording, so there's nothing specific to match yet. Use Auto-fill topics below (or edit a question) to load its real focus — then Auto-tag can tag it.`
        : "Nothing to tag — every question already has a topic.");
  }

  async function autoFillTopics() {
    const targetYears = fillYear === "all" ? years : [Number(fillYear)];
    setFilling(true); setFillNote("");
    let next = entries.slice(); let total = 0;
    let notFound = 0, lastDiagnostic = "";
    for (const yr of targetYears) {
      setFillNote(`Searching the ${yr} paper…`);
      try {
        const qns = [...new Set(next.filter((e) => e.series === yr).map((e) => e.qNumber))];
        const prompt =
`Using web search, find the ACTUAL exam questions on the ${board} History ${topic.paper} "${topic.name}" paper from May/June ${yr} (${codeHint(topic)}).
For each question number listed, give: (1) the specific focus of that exact question in 14 words or fewer, (2) the closest matching spec area from this list: ${(SPEC_AREAS[topic.id] || []).join("; ")}, and (3) a short paraphrase (20 words or fewer, in your own words — never quote the mark scheme directly) of what the mark scheme rewards for that question, e.g. key indicative content points or level-mark criteria.
Use only reliable sources (official board papers or reputable exam/revision sites). Never guess or invent — if a question cannot be confirmed, set "found" to false.
Questions: ${qns.map((q) => "Q" + q + " (" + stemOf(q) + ")").join("; ")}
Return ONLY a JSON array, no prose: [{"qNumber":"<as given>","found":true|false,"focus":"<specific topic>","topicArea":"<one from the list or empty>","markScheme":"<paraphrased mark-scheme summary, or empty>"}]`;
        const res = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST", headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 2000, messages: [{ role: "user", content: prompt }], tools: [{ type: "web_search_20250305", name: "web_search" }] }),
        });
        const json = await res.json();
        if (json.error) { lastDiagnostic = `API error for ${yr}: ${json.error.message || json.error.type || "unknown error"}`; continue; }
        const text = (json.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
        const arr = extractJsonArray(text);
        if (!arr.length) { lastDiagnostic = yr + ": no usable response — " + (text ? 'model said: "' + text.slice(0, 140).trim() + (text.length > 140 ? "…" : "") + '"'  : "empty response (check the model/tool are available)"); }
        arr.forEach((item) => {
          if (!item.found || !item.focus) { if (item.found === false) notFound++; return; }
          const qn = normQ(item.qNumber);
          const area = (SPEC_AREAS[topic.id] || []).includes(item.topicArea) ? item.topicArea : (guessSpecArea(SPEC_AREAS[topic.id] || [], item.focus) || "");
          let matched = false;
          next = next.map((e) => {
            if (e.series === yr && normQ(e.qNumber) === qn && e.source !== "verified") {
              matched = true;
              return { ...e, summary: item.focus, topic: area || e.topic, markScheme: item.markScheme || e.markScheme, source: "ai", aiAt: Date.now() };
            }
            return e;
          });
          if (matched) total++;
          else lastDiagnostic = `${yr}: got "${item.qNumber}" back but no question in this paper matches that number — check the question-number format.`;
        });
      } catch (e) { lastDiagnostic = `${yr}: ${e.message || "request failed"}`; }
    }
    onBulk(next); setFilling(false);
    setFillNote(total
      ? `Filled ${total} question focus${total > 1 ? "es" : ""} (AI-retrieved from the web — please verify against the paper, then edit to confirm).`
      : notFound
        ? `The AI searched but couldn't confirm any questions for the selected year(s) — it explicitly reported them as not found rather than guessing. Try a single recent year (2024 or 2025), or add the focus manually.`
        : `Nothing was filled. ${lastDiagnostic || "Try a single recent year, or add questions manually."}`);
  }

  const visible = useMemo(() =>
    entries.filter((e) => filter === "all" || String(e.series) === filter)
      .filter((e) => topicFilter === "all" || e.topic === topicFilter)
      .filter((e) => !verifiedOnly || e.source === "verified")
      .filter((e) => { if (!query.trim()) return true; const q = query.toLowerCase(); return (e.summary || "").toLowerCase().includes(q) || (e.qNumber || "").toLowerCase().includes(q) || (e.topic || "").toLowerCase().includes(q); })
      .sort((a, b) => (b.series - a.series) || a.qNumber.localeCompare(b.qNumber, undefined, { numeric: true })),
    [entries, filter, topicFilter, query, verifiedOnly]);

  const perYear = useMemo(() => { const m = {}; entries.forEach((e) => { if (e.source === "verified") m[e.series] = (m[e.series] || 0) + 1; }); return m; }, [entries]);

  return (
    <>
    {marking && <QuestionMarker topic={topic} entry={marking} onClose={() => setMarking(null)} />}
    <div>
      <section className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        <div className="p-5 sm:p-6 flex flex-wrap items-start gap-4 justify-between">
          <div className="flex items-start gap-4">
            <div className="grid place-items-center rounded shrink-0" style={{ width: 46, height: 46, background: c.ink }}><Icon size={22} color="#fff" /></div>
            <div><div className="flex items-center gap-2 mb-1"><span className="font-mono text-[10px] font-bold rounded-md px-2 py-0.5 tracking-wide" style={{ background: `${(BOARDS.find((b) => b.id === topic.board) || {}).color}1A`, color: (BOARDS.find((b) => b.id === topic.board) || {}).color }}>{topic.board}</span><p className="font-mono text-[11px] tracking-wide" style={{ color: c.oxblood }}>{topic.level.toUpperCase()} · {topic.paper.toUpperCase()} · {topic.option.toUpperCase()}</p></div>
              <h2 className="font-serif text-2xl leading-tight">{topic.name}</h2>
              <p className="text-sm mt-1.5" style={{ color: c.inkSoft }}>Focus: {topic.env}.</p></div>
          </div>
          <div className="flex gap-2 font-mono text-xs">
            <Stat label="Code" value={topic.code} /><Stat label="Marks" value={topic.marks} /><Stat label="Weight" value={topic.weight} /><Stat label="Time" value={topic.duration} />
          </div>
          <ResourceChips topic={topic} />
        </div>
        <div style={{ borderTop: `1px solid ${c.lineSoft}`, background: "#FAFAFB" }} className="px-4 sm:px-6 py-3 sm:py-4">
          <p className="text-[11px] font-mono tracking-widest mb-2 sm:mb-3" style={{ color: c.mute }}>EXAM SERIES · tap a year to filter</p>
          <div className="flex gap-1.5 sm:gap-2">{series.map((s) => <SeriesCell key={s.year} s={s} count={perYear[s.year] || 0} active={filter === String(s.year)} onClick={() => setFilter((f) => (f === String(s.year) ? "all" : String(s.year)))} />)}</div>
          {filter !== "all" && <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: c.teal }}><Tag size={12} /> Showing {filter} only — <button onClick={() => setFilter("all")} className="underline font-medium" style={{ color: c.teal }}>clear filter</button></p>}
          <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: c.mute }}><AlertTriangle size={12} /> 2020 &amp; 2021 not sat (COVID-19). Numbers show confirmed questions; every sat year is pre-loaded with its scaffold.</p>
        </div>
      </section>

      {/* ── Geography coming-soon notice ── */}
      {topic.subject === "Geography" && (
        <div className="rounded-lg p-4 mt-3 flex items-start gap-3" style={{ background: "#EFF6FF", border: "1px solid #BFDBFE" }}>
          <span style={{ fontSize: 22, lineHeight: 1, flexShrink: 0 }}>&#x1F30D;</span>
          <div>
            <p className="text-sm font-semibold" style={{ color: "#1E40AF" }}>Geography content coming soon</p>
            <p className="text-xs mt-0.5 leading-relaxed" style={{ color: "#3B82F6" }}>
              This section is being built out. Verified past-paper questions with mark schemes are available for
              AQA A-Level (7037/1 &amp; 7037/2) 2018–2024 and Edexcel A-Level (9GE0/01 &amp; 9GE0/02) 2022–2024.
              GCSE question data is in progress — scaffold question types are shown for all years so you can start tracking now.
            </p>
          </div>
        </div>
      )}

      <SectionTitle n="01" title="Standard question structure" note="Identical every series — your revision map." />
      <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        {/* Desktop: full table */}
        <table className="hidden sm:table w-full text-sm border-collapse">
          <thead><tr style={{ background: c.ink, color: "#fff" }} className="text-left"><Th>Section</Th><Th>Q</Th><Th>Question type</Th><Th className="text-right pr-5">Marks</Th></tr></thead>
          <tbody>{topic.structure.map((r, i) => (
            <tr key={i} style={{ borderTop: `1px solid ${c.lineSoft}` }}>
              <Td className="text-xs" style={{ color: c.teal, whiteSpace: "nowrap" }}>{r.sec}</Td>
              <Td className="font-mono" style={{ color: c.inkSoft }}>{r.q}</Td>
              <Td>{r.s}{r.spag && <SpagTag />}</Td>
              <Td className="text-right pr-5"><MarkBadge m={r.m} /></Td>
            </tr>))}</tbody>
        </table>
        {/* Mobile: cards */}
        <div className="sm:hidden divide-y" style={{ borderColor: c.lineSoft }}>
          {topic.structure.map((r, i) => (
            <div key={i} className="px-4 py-2.5 flex items-start justify-between gap-2">
              <div className="flex-1 min-w-0">
                <p className="text-[10px] font-mono mb-0.5" style={{ color: c.teal }}>{r.sec} · Q{r.q}</p>
                <p className="text-sm leading-snug" style={{ color: c.ink }}>{r.s}{r.spag && <SpagTag />}</p>
              </div>
              <MarkBadge m={r.m} />
            </div>
          ))}
        </div>
      </div>

      {/* examiner summary */}
      <SectionTitle n="02" title="Examiner summary" note="What earns marks, from the mark scheme & assessment objectives." />
      <div className="rounded-lg p-4 sm:p-5" style={{ background: c.surface, border: `1px solid ${c.line}`, borderLeft: `4px solid ${c.brass}` }}>
        <div className="flex gap-3">
          <ClipboardCheck size={20} style={{ color: c.brass, flexShrink: 0, marginTop: 2 }} />
          <div>
            {ex ? <p className="text-sm" style={{ color: c.ink }}>{ex.summary}</p> : <p className="text-sm italic" style={{ color: c.inkSoft }}>Examiner guidance for this topic is being prepared.</p>}
            {ex && (<><p className="text-xs font-semibold mt-3 mb-1" style={{ color: c.inkSoft }}>Common ways marks are lost</p>
            <ul className="text-sm space-y-1" style={{ color: c.inkSoft }}>
              {(ex.watch||[]).map((w, i) => <li key={i} className="flex gap-2"><span style={{ color: c.brass }}>•</span><span>{w}</span></li>)}
            </ul></>)}
            <p className="text-xs mt-3" style={{ color: c.mute }}>General guidance based on the {topic.level === "A Level" ? "AQA 7042" : "Edexcel 1HI0"} mark scheme. Official year-by-year examiner reports are on the {topic.level === "A Level" ? "AQA" : "Edexcel"} website.</p>
          </div>
        </div>
      </div>

      <SectionTitle n="03" title={`Questions by series, ${years[0]}–present`} note="Pre-loaded scaffold; confirm each year’s topic from the real paper." />
      {/* filter toolbar — stacked on mobile */}
      <div className="flex flex-col sm:flex-row flex-wrap gap-2 mb-3">
        {/* search — full width on mobile */}
        <div className="flex items-center gap-1.5 rounded px-2.5 py-2 w-full sm:flex-1 sm:min-w-[160px]" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
          <Search size={15} style={{ color: c.mute }} />
          <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search questions…" className="bg-transparent outline-none text-sm w-full" style={{ color: c.ink }} />
        </div>
        {/* second row on mobile: dropdowns + action buttons */}
        <div className="flex flex-wrap gap-2 items-center">
          <select value={filter} onChange={(e) => setFilter(e.target.value)} className="rounded px-2.5 py-2 text-sm outline-none flex-1 min-w-[100px]" style={{ background: c.surface, border: `1px solid ${c.line}`, color: c.ink }}>
            <option value="all">All years</option>{years.map((y) => <option key={y} value={String(y)}>{y}</option>)}
          </select>
          <select value={topicFilter} onChange={(e) => setTopicFilter(e.target.value)} className="rounded px-2.5 py-2 text-sm outline-none flex-1 min-w-[120px]" style={{ background: c.surface, border: `1px solid ${c.line}`, color: c.ink }}>
            <option value="all">All topics</option>{(SPEC_AREAS[topic.id] || []).map((a) => <option key={a} value={a}>{a}</option>)}
          </select>
          <button onClick={() => setVerifiedOnly((v) => !v)} className="inline-flex items-center gap-1.5 rounded px-3 py-2 text-sm font-medium whitespace-nowrap"
            style={{ background: verifiedOnly ? c.tealSoft : c.surface, border: `1px solid ${verifiedOnly ? c.teal : c.line}`, color: verifiedOnly ? c.teal : c.inkSoft }}><ShieldCheck size={15} /> <span className="hidden sm:inline">Confirmed</span><span className="sm:hidden">✓</span></button>
          <button onClick={() => setPaperMode(p => !p)}
            className="inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-semibold shrink-0"
            style={{ background: paperMode?"#1a1a1a":"#fff", color: paperMode?"#C9A84C":c.inkSoft,
              border:`1px solid ${paperMode?"#1a1a1a":c.line}`,
              boxShadow: paperMode?"0 2px 8px rgba(0,0,0,0.25)":"none" }}>
            📄 Paper mode
          </button>
          <PrintRevisionSheet topic={topic} entries={entries} />
          <button onClick={() => exportCsv(topic, entries)} className="inline-flex items-center gap-1.5 rounded px-3 py-2 text-sm font-medium" style={{ background: c.surface, border: `1px solid ${c.line}`, color: c.inkSoft }}><Download size={15} /> <span className="hidden sm:inline">CSV</span></button>
          <button onClick={() => exportClassSheet(topic, entries)}
            className="inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-semibold"
            style={{ color: c.inkSoft, border:`1px solid ${c.line}` }} title="Open printable class sheet">
            <Printer size={14} /> Class sheet
          </button>
          {["Edexcel","AQA"].includes(topic.board) && (
            <button onClick={()=>batchFillSources(topic,entries,onBulk,aiProv.provider,aiProv.apiKey,aiProv.endpoint,setStatus)}
              className="inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-semibold"
              style={{background:"#7C3AED15",color:"#7C3AED",border:"1px solid #7C3AED30"}}>
              <Sparkles size={14}/> Fill sources
            </button>
          )}
          <button onClick={() => setEditing({})} className="inline-flex items-center gap-1.5 rounded px-3.5 py-2 text-sm font-semibold text-white hover:opacity-90" style={{ background: c.oxblood }}><Plus size={16} /> Add</button>
        </div>
      </div>

      {/* Tools panel — collapsible on mobile */}
      {(() => { const [showTools, setShowTools] = React.useState(false); return (
        <div className="mb-3">
          <button onClick={() => setShowTools(s => !s)} className="sm:hidden w-full flex items-center justify-between rounded px-3 py-2.5 text-sm font-medium mb-2"
            style={{ background: c.surface, border: `1px solid ${c.line}`, color: c.inkSoft }}>
            <span className="flex items-center gap-2"><Sparkles size={14} style={{ color: c.brass }} /> AI tools &amp; auto-tag</span>
            <span style={{ color: c.mute }}>{showTools ? "▲" : "▼"}</span>
          </button>
          <div className={showTools ? "" : "hidden sm:block"}>
            <div className="rounded-lg p-3 mb-2 flex flex-wrap items-center gap-2" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
              <Sparkles size={15} style={{ color: c.brass }} />
              <span className="text-xs font-medium" style={{ color: c.inkSoft }}>Step 1 — load real question focus for</span>
              <select value={fillYear} onChange={(e) => setFillYear(e.target.value)} className="rounded px-2 py-1.5 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink }}>
                <option value="all">all years</option>{years.map((y) => <option key={y} value={String(y)}>{y}</option>)}
              </select>
              <button onClick={autoFillTopics} disabled={filling} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-semibold text-white disabled:opacity-50" style={{ background: c.brass }}>
                {filling ? <Loader2 size={14} className="animate-spin" /> : <Sparkles size={14} />}{filling ? "Searching…" : "Auto-fill topics"}
              </button>
              <span className="text-[11px] hidden sm:inline" style={{ color: c.mute }}>web-retrieved · verify before trusting</span>
            </div>
            <div className="rounded-lg p-3 mb-2 flex flex-wrap items-center gap-2" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
              <Tag size={15} style={{ color: c.teal }} />
              <span className="text-xs font-medium" style={{ color: c.inkSoft }}>Step 2 — tag confirmed questions</span>
              <button onClick={autoTagTopics} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-semibold" style={{ background: c.tealSoft, color: c.teal, border: `1px solid ${c.teal}55` }}>
                <Tag size={14} /> Auto-tag
              </button>
              <span className="text-[11px] hidden sm:inline" style={{ color: c.mute }}>instant · local</span>
            </div>
          </div>
          {fillNote && <div className="rounded-lg p-3 mb-2 flex gap-2 text-xs" style={{ background: c.brassSoft, border: `1px solid ${c.brass}33`, color: c.ink }}><AlertTriangle size={14} style={{ color: c.brass, flexShrink: 0, marginTop: 1 }} /><span>{fillNote}</span></div>}
        </div>
      );})()}

      <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        {visible.length === 0 ? <Empty onAdd={() => setEditing({})} /> : (<>
          {paperMode ? <ExamPaperView entries={entries} topic={topic} /> : (<>
          {/* ── Desktop table (≥sm) ── */}
          <table className="hidden sm:table w-full text-sm border-collapse">
            <thead><tr style={{ background: "#F4F5F7", color: c.inkSoft }} className="text-left">
              <Th light>Year</Th><Th light>Q</Th><Th light>Question &amp; topic</Th><Th light className="text-right">Marks</Th><Th light className="text-right pr-4"> </Th></tr></thead>
            <tbody>{visible.map((e) => { const scaffold = e.source === "scaffold"; const ai = e.source === "ai"; return (
              <tr key={e.id} className="group"
                style={{ borderTop:`1px solid ${c.lineSoft}`, borderLeft:"3px solid transparent",
                  transition:"border-color 0.2s, background 0.15s" }}
                onMouseEnter={ev=>{ev.currentTarget.style.borderLeft="3px solid #C9A84C";ev.currentTarget.style.background="rgba(201,168,76,0.04)";}}
                onMouseLeave={ev=>{ev.currentTarget.style.borderLeft="3px solid transparent";ev.currentTarget.style.background="";}}>
                <Td className="font-mono">{e.series}</Td>
                <Td className="font-mono" style={{ color: c.inkSoft }}>{e.qNumber}</Td>
                <Td>
                  <div style={{ color: scaffold ? c.mute : c.ink }}>{e.summary}{e.spag && <SpagTag />}{e.extended && <ExtTag />}
                    {scaffold ? <Badge color={c.brass} bg={c.brassSoft}>confirm topic</Badge> : ai ? <Badge color={c.brass} bg={c.brassSoft}>AI · verify</Badge> : <Badge color={c.teal} bg={c.tealSoft}>confirmed</Badge>}</div>
                  {e.topic ? <div className="mt-1"><span className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5" style={{ background: e.tagSource === "auto" ? c.brassSoft : c.tealSoft, color: e.tagSource === "auto" ? c.brass : c.teal }}>{e.tagSource === "auto" && <Tag size={9} />}{e.topic}</span></div>
                    : scaffold ? <div className="mt-1 text-[11px]" style={{ color: c.mute }}>topic pending</div>
                    : <div className="mt-1 text-[11px]" style={{ color: c.mute }}>no topic tagged</div>}
                  {e.topic && <TopicAreaNote text={TOPIC_AREA_INFO[topic.id]?.[e.topic]} />}
                  {SOURCE_INFO[e.id] && <SourceInfoCard info={SOURCE_INFO[e.id]} />}
                  <SourceTextDisplay entry={e} topic={topic} />
                  <MarkSchemeNote text={e.markScheme} reportUrl={getExaminerReportUrl(topic.id, e.series)} />
                </Td>
                <Td className="text-right"><MarkBadge m={e.marks} /></Td>
                <Td className="text-right pr-4"><div className="inline-flex gap-1 opacity-0 group-hover:opacity-100">
                  {e.source !== "scaffold" && <ConfidenceBtn value={e.confidence||0} onToggle={v => onQuickUpdate && onQuickUpdate(e.id, {confidence:v})} size={26} />}
                  {topic.subject === "History" && topic.board === "Edexcel" && e.source !== "scaffold" && <IconBtn onClick={() => setMarking(e)} label="Mark answer" style={{ color: c.oxblood }}><ClipboardCheck size={14} /></IconBtn>}
                  <IconBtn onClick={() => setEditing(e)} label="Edit"><Pencil size={14} /></IconBtn>
                  <IconBtn onClick={() => onDelete(e.id)} label="Delete" danger><Trash2 size={14} /></IconBtn>
                </div></Td>
              </tr>); })}</tbody>
          </table>
          {/* ── Mobile cards (<sm) ── */}
          <div className="sm:hidden divide-y" style={{ borderColor: c.lineSoft }}>
            {visible.map((e) => { const scaffold = e.source === "scaffold"; const ai = e.source === "ai"; return (
              <div key={e.id} className="px-4 py-3"
                style={{ borderLeft:"3px solid transparent", transition:"border-color 0.2s, background 0.15s" }}
                onTouchStart={ev=>{ev.currentTarget.style.borderLeft="3px solid #C9A84C";ev.currentTarget.style.background="rgba(201,168,76,0.04)";}}
                onTouchEnd={ev=>{setTimeout(()=>{ev.currentTarget.style.borderLeft="3px solid transparent";ev.currentTarget.style.background="";},400);}}>
                {/* row 1: year · Q · marks · status · actions */}
                <div className="flex items-center gap-2 mb-1.5">
                  <span className="font-mono text-xs font-semibold" style={{ color: c.ink }}>{e.series}</span>
                  <span className="font-mono text-xs" style={{ color: c.inkSoft }}>Q{e.qNumber}</span>
                  <MarkBadge m={e.marks} />
                  {scaffold ? <Badge color={c.brass} bg={c.brassSoft}>confirm</Badge>
                    : ai ? <Badge color={c.brass} bg={c.brassSoft}>AI·verify</Badge>
                    : <Badge color={c.teal} bg={c.tealSoft}>✓</Badge>}
                  <div className="ml-auto flex gap-1">
                    <button onClick={() => setEditing(e)} className="grid place-items-center rounded" title="Edit"
                      style={{ width:34, height:34, border:`1px solid ${c.line}`, color: c.inkSoft }}><Pencil size={14} /></button>
                    {topic.subject === "History" && topic.board === "Edexcel" && e.source !== "scaffold" && (
                      <button onClick={() => setMarking(e)} className="grid place-items-center rounded" title="Mark answer"
                        style={{ width:34, height:34, border:`1px solid ${c.oxblood}40`, color: c.oxblood }}><ClipboardCheck size={14} /></button>
                    )}
                    <button onClick={() => onDelete(e.id)} className="grid place-items-center rounded" title="Delete"
                      style={{ width:34, height:34, border:`1px solid #FCA5A5`, color:"#DC2626" }}><Trash2 size={14} /></button>
                  </div>
                </div>
                {/* row 2: summary */}
                <p className="text-sm leading-snug" style={{ color: scaffold ? c.mute : c.ink }}>{e.summary}{e.spag && <SpagTag />}{e.extended && <ExtTag />}</p>
                {/* row 3: topic chip */}
                {e.topic
                  ? <div className="mt-1.5"><span className="inline-flex items-center gap-1 font-mono text-[10px] rounded px-1.5 py-0.5" style={{ background: e.tagSource==="auto" ? c.brassSoft : c.tealSoft, color: e.tagSource==="auto" ? c.brass : c.teal }}>{e.tagSource==="auto" && <Tag size={9} />}{e.topic}</span></div>
                  : scaffold ? <p className="mt-1 text-[11px]" style={{ color: c.mute }}>topic pending — load real question first</p>
                  : <p className="mt-1 text-[11px]" style={{ color: c.mute }}>no topic tagged</p>}
                {e.topic && <TopicAreaNote text={TOPIC_AREA_INFO[topic.id]?.[e.topic]} />}
                <MobileExpandMs entry={e} topicId={topic.id} onQuickUpdate={onQuickUpdate} />
              </div>
            );})}
          </div>
          </>)}
        </>)}
      </div>

      <UpdateNote topic={topic} years={years} />
      {editing && <EntryModal topic={topic} years={years} entry={editing} onClose={() => setEditing(null)} onSave={(e) => { onSave(e); setEditing(null); }} />}
    </div>
    </>
  );
}

function FadePanel({ id, children }) {
  const [vis, setVis] = React.useState(false);
  React.useEffect(() => { const t = setTimeout(()=>setVis(true),10); return ()=>{clearTimeout(t);setVis(false);}; }, [id]);
  return <div style={{opacity:vis?1:0,transform:vis?"translateY(0)":"translateY(8px)",transition:"opacity 0.2s ease,transform 0.2s ease"}}>{children}</div>;
}


function shareContent(title, text, url) {
  if (navigator.share) {
    navigator.share({ title, text, url: url || window.location.href }).catch(() => {});
  } else {
    navigator.clipboard?.writeText(text + " " + window.location.href)
      .then(() => alert("Link copied!")).catch(() => {});
  }
}

function haptic(style) {
  const patterns = { light:[8], medium:[20], heavy:[40,10,40] };
  navigator.vibrate?.(patterns[style]||[8]);
}

function InstallBanner() {
  const [show, setShow] = React.useState(false);
  const [isIOS, setIsIOS] = React.useState(false);
  const [prompt, setPrompt] = React.useState(null);

  React.useEffect(() => {
    const ios = /iphone|ipad|ipod/i.test(navigator.userAgent.toLowerCase());
    const standalone = window.matchMedia("(display-mode:standalone)").matches || window.navigator.standalone;
    const dismissed = localStorage.getItem("ec_install_dismissed");
    if (standalone || dismissed) return;
    if (ios) { setIsIOS(true); setTimeout(() => setShow(true), 3000); return; }
    const fn = e => { e.preventDefault(); setPrompt(e); setTimeout(() => setShow(true), 3000); };
    window.addEventListener("beforeinstallprompt", fn);
    return () => window.removeEventListener("beforeinstallprompt", fn);
  }, []);

  if (!show) return null;
  return (
    <div className="fixed left-3 right-3 z-40 sm:hidden rounded-2xl p-3.5 flex items-center gap-3"
      style={{ bottom:"calc(72px + env(safe-area-inset-bottom,0px) + 8px)",
        background:"#0D1B2E", boxShadow:"0 -4px 32px rgba(13,27,46,0.4)", border:"1px solid rgba(201,168,76,0.3)" }}>
      <img src={LOGO_B64} alt="" style={{ width:36, height:36, borderRadius:8, objectFit:"contain", flexShrink:0 }} />
      <div className="flex-1 min-w-0">
        <p className="text-[13px] font-bold text-white">Install Exam Chronicle</p>
        <p className="text-[10px] mt-0.5 leading-tight" style={{ color:"#64748B" }}>
          {isIOS ? "Safari → Share ↗ → Add to Home Screen" : "Tap Install for offline access"}
        </p>
      </div>
      {!isIOS && prompt && (
        <button onClick={() => { prompt.prompt(); setShow(false); }}
          className="rounded-xl px-3 py-2 text-[11px] font-bold text-white shrink-0"
          style={{ background:"#C9A84C" }}>Install</button>
      )}
      <button onClick={() => { localStorage.setItem("ec_install_dismissed","1"); setShow(false); }}
        style={{ color:"#475569", fontSize:20, lineHeight:1, flexShrink:0, background:"none", border:"none" }}>×</button>
    </div>
  );
}


function MobileBottomNav({ active, setActive, subject }) {
  const tabs = [
    { id: null,        icon: "📚", label: "Topics"   },
    { id: "search",    icon: "🔍", label: "Search"   },
    { id: "flashcard", icon: "✨", label: "Test Me"  },
    { id: "plan",      icon: "📊", label: "Plan"     },
    { id: "marker",    icon: "✅", label: "Marker"   },
  ];
  return (
    <nav className="sm:hidden fixed bottom-0 left-0 right-0 z-50 flex"
      style={{ background:"rgba(255,255,255,0.95)", backdropFilter:"blur(16px)",
        borderTop:"1px solid rgba(201,168,76,0.2)", paddingBottom:"env(safe-area-inset-bottom,12px)", paddingLeft:"env(safe-area-inset-left,0px)", paddingRight:"env(safe-area-inset-right,0px)" }}>
      {tabs.map(t => {
        const on = t.id === null ? !["flashcard","plan","search","marker","predict","paper"].includes(active) : active === t.id;
        return (
          <button key={t.label} onClick={() => setActive(t.id || (active !== null && !["flashcard","plan","search","marker"].includes(active) ? active : null))}
            className="flex-1 flex flex-col items-center justify-center gap-0.5 py-2" style={{ minHeight:48 }}
            style={{ color: on ? "#C9A84C" : "#94A3B8" }}>
            <span style={{ fontSize:20, lineHeight:1, filter: on ? "none" : "saturate(0) opacity(0.6)" }}>{t.icon}</span>
            <span style={{ fontSize:9, fontWeight: on ? 700 : 500, letterSpacing:"0.03em" }}>{t.label}</span>
            {on && <div style={{ width:20, height:2, borderRadius:1, background:"#C9A84C", marginTop:1 }} />}
          </button>
        );
      })}
    </nav>
  );
}


const DARK_PALETTE = {
  ink: "#E8F0FE", inkSoft: "#A8BDD8", mute: "#5A7A9A",
  paper: "#0A1628", surface: "#111F33", elevated: "#162035",
  night: "#060E1A", oxblood: "#C9A84C", oxbloodSoft: "#1A1500",
  teal: "#34D399", tealSoft: "#0D2B22",
  brass: "#FBBF24", brassSoft: "#1C1500",
  line: "#1E3050", lineSoft: "#152238",
  green: "#34D399", greenSoft: "#0D2B22",
  red: "#F87171", redSoft: "#2D0F0F",
};
const ThemeCtx = React.createContext(false);
function useTheme() {
  const dark = React.useContext(ThemeCtx);
  return dark ? DARK_PALETTE : c;
}


function SearchPanel({ data, topics, onSelectTopic }) {
  const [q, setQ] = React.useState("");
  const results = React.useMemo(() => {
    const term = q.trim().toLowerCase();
    if (term.length < 2) return [];
    const out = [];
    topics.forEach(t => {
      (data[t.id] || []).filter(e => e.source !== "scaffold").forEach(e => {
        if ((e.summary||"").toLowerCase().includes(term) ||
            (e.markScheme||"").toLowerCase().includes(term) ||
            (e.topic||"").toLowerCase().includes(term)) {
          out.push({ entry: e, topic: t });
        }
      });
    });
    return out.slice(0, 60);
  }, [q, data, topics]);

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-3">
      <SectionTitle n="01" title="Search" note="Search questions, topics and mark schemes across all specs." />
      <div className="relative">
        <input value={q} onChange={e => setQ(e.target.value)} placeholder="Type a keyword — e.g. 'cholera', 'propaganda', 'Pasteur'…"
          className="w-full rounded-2xl px-4 py-3 pl-10 text-sm"
          style={{ border:`1px solid ${c.line}`, background: c.surface, color: c.ink,
            boxShadow:"0 2px 8px rgba(13,27,46,0.08)", outline:"none" }} autoFocus />
        <span className="absolute left-3.5 top-3.5 text-base">🔍</span>
        {q && <button onClick={() => setQ("")} className="absolute right-3.5 top-3"
          style={{ color: c.mute, fontSize:16, lineHeight:1, background:"none", border:"none", cursor:"pointer" }}>×</button>}
      </div>
      {q.length >= 2 && (
        <p className="text-xs" style={{ color: c.mute }}>
          {results.length === 0 ? "No questions found." : `${results.length} question${results.length!==1?"s":""} found`}
        </p>
      )}
      <div className="space-y-2">
        {results.map(({ entry: e, topic: t }) => (
          <button key={e.id} onClick={() => onSelectTopic && onSelectTopic(t.id)}
            className="w-full text-left rounded-xl p-3 space-y-1"
            style={{ background: c.surface, border:`1px solid ${c.line}`,
              boxShadow:"0 1px 4px rgba(13,27,46,0.06)", transition:"all 0.15s" }}
            onMouseEnter={ev => { ev.currentTarget.style.borderLeft="3px solid #C9A84C"; ev.currentTarget.style.background="rgba(201,168,76,0.04)"; }}
            onMouseLeave={ev => { ev.currentTarget.style.borderLeft=`1px solid ${c.line}`; ev.currentTarget.style.background=c.surface; }}>
            <div className="flex items-center gap-2 flex-wrap">
              <span className="text-[10px] font-mono font-bold rounded-full px-2 py-0.5"
                style={{ background: c.oxbloodSoft, color: c.oxblood }}>{t.short}</span>
              <span className="text-[10px] font-mono" style={{ color: c.mute }}>
                {e.series} · Q{e.qNumber} · {e.marks}m
              </span>
            </div>
            <p className="text-xs leading-relaxed" style={{ color: c.ink }}>
              {(() => {
                const term = q.toLowerCase();
                const text = e.summary || "";
                const i = text.toLowerCase().indexOf(term);
                if (i < 0) return text.slice(0, 120);
                const start = Math.max(0, i - 30);
                const snippet = text.slice(start, i + term.length + 60);
                return (start > 0 ? "…" : "") + snippet + (snippet.length < text.length - start ? "…" : "");
              })()}
            </p>
          </button>
        ))}
      </div>
    </div>
  );
}


function EssayPlannerPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const essays = React.useMemo(() => {
    const out = [];
    topics.forEach(t => {
      (data[t.id]||[]).filter(e => e.source!=="scaffold" && (e.marks===16||e.marks===20||e.marks===25||e.marks===30)).forEach(e => {
        out.push({ entry:e, topic:t });
      });
    });
    return out;
  }, [topics, data]);

  const [selected, setSelected] = React.useState(null);
  const [custom, setCustom] = React.useState("");
  const [loading, setLoading] = React.useState(false);
  const [plan, setPlan] = React.useState(null);
  const [error, setError] = React.useState(null);
  const { provider, apiKey, endpoint } = useAIProvider();

  async function generatePlan(question, topic) {
    setLoading(true); setPlan(null); setError(null);
    const specAreas = (SPEC_AREAS[topic?.id]||[]).join(", ");
    const prompt = `You are an expert ${board} ${level} History examiner.

Generate a detailed essay plan for this question:
"${question}"

Topic: ${topic?.name||"History"} (${board} ${level})
Marks: ${selected?.entry?.marks||16}m
Specification areas: ${specAreas}

Create a structured plan that would achieve full marks. Respond ONLY with valid JSON:
{
  "thesis": "A clear, debatable thesis statement that directly answers the question",
  "points": [
    {
      "argument": "Main point/factor",
      "evidence": "Specific historical evidence, dates, statistics, names",
      "analysis": "How this supports the thesis / significance"
    }
  ],
  "counter": "One strong counter-argument to acknowledge",
  "conclusion": "Concluding judgement that returns to the thesis with a nuanced verdict"
}

Generate 3-4 points. Make evidence highly specific — exact dates, names, figures that an examiner would reward.`;
    try {
      const raw = await callAIText({ provider, apiKey, endpoint, prompt });
      setPlan(JSON.parse(raw.replace(/\`\`\`json|\`\`\`/g,"").trim()));
    } catch(e) { setError("Plan generation failed: "+e.message); }
    finally { setLoading(false); }
  }

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="AI Essay Planner" note="Pick a question or type your own — get a structured plan with thesis, evidence and conclusion." />

      {/* Select from past papers */}
      <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
        <div className="px-4 py-2.5" style={{ background:c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
          <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color:c.mute }}>SELECT A PAST PAPER ESSAY</span>
        </div>
        <div className="max-h-48 overflow-y-auto divide-y" style={{ borderColor:c.lineSoft }}>
          {essays.slice(0,40).map(({entry:e,topic:t}) => (
            <button key={e.id} onClick={() => { setSelected({entry:e,topic:t}); setCustom(""); setPlan(null); }}
              className="w-full text-left px-4 py-2.5 flex items-start gap-3"
              style={{ background: selected?.entry?.id===e.id ? "rgba(201,168,76,0.08)" : "transparent",
                borderLeft: selected?.entry?.id===e.id ? "3px solid #C9A84C" : "3px solid transparent" }}>
              <span className="text-[10px] font-mono shrink-0 mt-0.5" style={{ color:c.oxblood }}>{e.series} Q{e.qNumber} [{e.marks}m]</span>
              <span className="text-xs" style={{ color:c.ink }}>{e.summary}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Or type custom */}
      <div>
        <p className="text-[10px] font-mono font-bold tracking-widest mb-1.5" style={{ color:c.mute }}>OR TYPE YOUR OWN QUESTION</p>
        <textarea value={custom} onChange={e=>{setCustom(e.target.value);setSelected(null);setPlan(null);}}
          placeholder="e.g. 'How far was Hitler responsible for the outbreak of World War Two?'"
          rows={2} className="w-full rounded-xl px-3 py-2.5 text-sm resize-none"
          style={{ border:`1px solid ${c.line}`, color:c.ink, background:c.surface }} />
      </div>

      <button onClick={() => {
        const q = custom.trim() || selected?.entry?.summary;
        const t = selected?.topic || topics[0];
        if (q) generatePlan(q, t);
      }} disabled={loading || (!custom.trim() && !selected)}
        className="w-full rounded-2xl py-3 font-bold text-sm text-white flex items-center justify-center gap-2 disabled:opacity-40"
        style={{ background:"linear-gradient(135deg,#0D1B2E,#1D3A5C)" }}>
        {loading ? <><Loader2 size={16} className="animate-spin"/>Generating plan…</> : "✍️  Generate Essay Plan"}
      </button>

      {error && <div className="rounded-xl p-3 text-sm" style={{ background:"#FEF2F2", color:"#DC2626" }}>{error}</div>}

      {plan && (
        <div className="space-y-3">
          <div className="rounded-2xl p-4" style={{ background:"linear-gradient(135deg,#0D1B2E,#1A2B42)", color:"#fff" }}>
            <p className="text-[10px] font-mono font-bold tracking-widest mb-2" style={{ color:"#C9A84C" }}>📌 THESIS</p>
            <p className="text-sm leading-relaxed font-medium">{plan.thesis}</p>
          </div>
          {plan.points?.map((p,i) => (
            <div key={i} className="rounded-2xl p-4 space-y-2" style={{ background:c.surface, border:`1px solid ${c.line}` }}>
              <div className="flex items-center gap-2">
                <span className="rounded-full text-[10px] font-bold px-2 py-0.5 text-white" style={{ background:c.oxblood }}>P{i+1}</span>
                <p className="text-sm font-bold" style={{ color:c.ink }}>{p.argument}</p>
              </div>
              <div className="rounded-xl p-2.5" style={{ background:c.tealSoft }}>
                <p className="text-[10px] font-mono font-bold mb-1" style={{ color:c.teal }}>EVIDENCE</p>
                <p className="text-xs" style={{ color:c.ink }}>{p.evidence}</p>
              </div>
              <p className="text-xs italic" style={{ color:c.inkSoft }}>{p.analysis}</p>
            </div>
          ))}
          {plan.counter && (
            <div className="rounded-2xl p-4" style={{ background:c.brassSoft, border:`1px solid ${c.brass}30` }}>
              <p className="text-[10px] font-mono font-bold mb-1" style={{ color:c.brass }}>⚖️ COUNTER-ARGUMENT</p>
              <p className="text-xs" style={{ color:c.ink }}>{plan.counter}</p>
            </div>
          )}
          <div className="rounded-2xl p-4" style={{ background:c.oxbloodSoft, border:`1px solid ${c.oxblood}30` }}>
            <p className="text-[10px] font-mono font-bold mb-1" style={{ color:c.oxblood }}>🎯 CONCLUSION</p>
            <p className="text-xs" style={{ color:c.ink }}>{plan.conclusion}</p>
          </div>
        </div>
      )}
    </div>
  );
}


function MockExamPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const [phase, setPhase] = React.useState("setup"); // setup | exam | done
  const [selectedTopics, setSelectedTopics] = React.useState([]);
  const [duration, setDuration] = React.useState(80); // minutes
  const [timeLeft, setTimeLeft] = React.useState(0);
  const [questions, setQuestions] = React.useState([]);
  const [answers, setAnswers] = React.useState({});
  const [qIdx, setQIdx] = React.useState(0);
  const timerRef = React.useRef(null);

  function buildPaper() {
    const pool = [];
    selectedTopics.forEach(tid => {
      (data[tid]||[]).filter(e=>e.source!=="scaffold").forEach(e => pool.push(e));
    });
    const shuffled = pool.sort(() => Math.random()-0.5);
    // Select questions to fill ~duration (assume 1 mark = 1 minute roughly)
    let total = 0; const qs = [];
    for (const q of shuffled) {
      if (total + (q.marks||4) > duration * 1.2) continue;
      qs.push(q); total += q.marks||4;
      if (total >= duration * 0.85) break;
    }
    return qs.sort((a,b) => (a.qNumber||"").localeCompare(b.qNumber||""));
  }

  function startExam() {
    const qs = buildPaper();
    if (!qs.length) { alert("No questions found for selected topics."); return; }
    setQuestions(qs); setAnswers({}); setQIdx(0);
    setTimeLeft(duration * 60); setPhase("exam");
    timerRef.current = setInterval(() => {
      setTimeLeft(t => { if(t<=1){clearInterval(timerRef.current);setPhase("done");return 0;} return t-1;});
    }, 1000);
  }

  React.useEffect(() => () => clearInterval(timerRef.current), []);

  const mm = String(Math.floor(timeLeft/60)).padStart(2,"0");
  const ss = String(timeLeft%60).padStart(2,"0");
  const urgency = timeLeft < 300 ? "#DC2626" : timeLeft < 600 ? "#D97706" : "#059669";
  const totalMarks = questions.reduce((s,q)=>s+(q.marks||0),0);
  const done = Object.keys(answers).length;

  if (phase === "setup") return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Mock Exam" note="Select topics and duration to generate a timed practice paper." />
      <div>
        <p className="text-[10px] font-mono font-bold tracking-widest mb-2" style={{ color:c.mute }}>SELECT TOPICS</p>
        <div className="flex flex-wrap gap-2">
          {topics.map(t => {
            const on = selectedTopics.includes(t.id);
            const Icon = t.icon;
            return (
              <button key={t.id} onClick={() => setSelectedTopics(s => on ? s.filter(x=>x!==t.id) : [...s,t.id])}
                className="inline-flex items-center gap-1.5 rounded-xl px-3 py-2 text-xs font-semibold"
                style={{ background: on ? c.oxblood : c.surface, color: on ? "#fff" : c.inkSoft,
                  border:`1px solid ${on ? c.oxblood : c.line}`, boxShadow: on ? "0 2px 8px rgba(201,168,76,0.3)" : "none" }}>
                <Icon size={12}/>{t.short}
              </button>
            );
          })}
        </div>
      </div>
      <div>
        <p className="text-[10px] font-mono font-bold tracking-widest mb-2" style={{ color:c.mute }}>DURATION</p>
        <div className="flex gap-2 flex-wrap">
          {[[45,"45 min"],[80,"1h 20m"],[105,"1h 45m"],[120,"2h"]].map(([mins,label])=>(
            <button key={mins} onClick={()=>setDuration(mins)}
              className="rounded-xl px-4 py-2 text-sm font-semibold"
              style={{ background: duration===mins ? c.oxblood:"#fff", color: duration===mins?"#fff":c.inkSoft,
                border:`1px solid ${duration===mins?c.oxblood:c.line}` }}>{label}</button>
          ))}
        </div>
      </div>
      <button onClick={startExam} disabled={!selectedTopics.length}
        className="w-full rounded-2xl py-3.5 text-sm font-bold text-white disabled:opacity-40"
        style={{ background:"linear-gradient(135deg,#0D1B2E,#C9A84C)" }}>
        🎓  Start {duration}-minute mock exam
      </button>
    </div>
  );

  if (phase === "done") {
    const answered = Object.keys(answers).length;
    return (
      <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-4 text-center">
        <p className="text-5xl">🎓</p>
        <h2 className="text-xl font-bold" style={{ color:c.ink }}>Time&apos;s up!</h2>
        <p style={{ color:c.mute }}>{answered} of {questions.length} questions attempted · {totalMarks} marks available</p>
        <button onClick={()=>{setPhase("setup");setSelectedTopics([]);}}
          className="rounded-2xl px-8 py-3 font-bold text-white" style={{ background:c.oxblood }}>
          New mock
        </button>
      </div>
    );
  }

  const q = questions[qIdx];
  return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-3">
      {/* Timer bar */}
      <div className="sticky top-0 z-10 rounded-2xl p-3 flex items-center gap-3"
        style={{ background:c.night, boxShadow:"0 4px 16px rgba(13,27,46,0.3)" }}>
        <div className="flex-1">
          <div className="rounded-full h-2" style={{ background:"rgba(255,255,255,0.15)" }}>
            <div className="rounded-full h-2 transition-all" style={{ width:`${(timeLeft/(duration*60))*100}%`, background:urgency }} />
          </div>
        </div>
        <span className="font-mono font-bold text-sm" style={{ color:urgency, minWidth:52 }}>{mm}:{ss}</span>
        <button onClick={()=>{clearInterval(timerRef.current);setPhase("done");}}
          className="text-xs px-3 py-1.5 rounded-lg font-semibold" style={{ background:"rgba(255,255,255,0.1)", color:"#fff" }}>
          End
        </button>
      </div>
      {/* Question nav */}
      <div className="flex items-center gap-2 overflow-x-auto pb-1">
        {questions.map((_,i)=>(
          <button key={i} onClick={()=>setQIdx(i)}
            className="rounded-lg text-[11px] font-bold shrink-0 w-8 h-8"
            style={{ background: i===qIdx ? c.oxblood : answers[questions[i]?.id] ? c.tealSoft : c.surface,
              color: i===qIdx ? "#fff" : answers[questions[i]?.id] ? c.teal : c.mute,
              border:`1px solid ${i===qIdx ? c.oxblood : c.line}` }}>
            {i+1}
          </button>
        ))}
      </div>
      {/* Current question */}
      {q && (
        <div className="rounded-2xl p-4 space-y-3" style={{ background:c.surface, border:`1px solid ${c.line}` }}>
          <div className="flex items-center justify-between">
            <span className="font-mono font-bold text-xs" style={{ color:c.oxblood }}>Q{q.qNumber} [{q.marks}m]</span>
            <span className="text-[11px]" style={{ color:c.mute }}>{qIdx+1}/{questions.length}</span>
          </div>
          <p className="text-sm font-semibold" style={{ color:c.ink }}>{q.summary}</p>
          <textarea value={answers[q.id]||""} onChange={e=>setAnswers(a=>({...a,[q.id]:e.target.value}))}
            placeholder="Write your answer here…" rows={6}
            className="w-full rounded-xl px-3 py-2.5 text-sm resize-none"
            style={{ border:`1px solid ${c.line}`, color:c.ink, background:"#fff" }} />
        </div>
      )}
      <div className="flex gap-2">
        <button onClick={()=>setQIdx(i=>Math.max(0,i-1))} disabled={qIdx===0}
          className="rounded-xl px-4 py-2.5 text-sm font-semibold disabled:opacity-30"
          style={{ background:c.lineSoft, color:c.inkSoft, border:`1px solid ${c.line}` }}>← Prev</button>
        <button onClick={()=>qIdx<questions.length-1?setQIdx(i=>i+1):(clearInterval(timerRef.current),setPhase("done"))}
          className="flex-1 rounded-xl py-2.5 text-sm font-bold text-white" style={{ background:c.oxblood }}>
          {qIdx<questions.length-1?"Next →":"Finish exam"}
        </button>
      </div>
    </div>
  );
}


function CalendarPanel({ board, level, subject, data }) {
  const today = new Date();
  const [month, setMonth] = React.useState(today.getMonth());
  const [year, setYear] = React.useState(today.getFullYear());
  const [sessions, setSessions] = React.useState(() => {
    try { return JSON.parse(localStorage.getItem("ec_calendar")||"{}"); } catch { return {}; }
  });
  const [note, setNote] = React.useState("");
  const [selected, setSelected] = React.useState(null);

  function saveSession(dateStr, text) {
    const updated = { ...sessions, [dateStr]: text };
    setSessions(updated);
    try { localStorage.setItem("ec_calendar", JSON.stringify(updated)); } catch {}
  }

  const daysInMonth = new Date(year, month+1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay();
  const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];

  // Upcoming exams
  const exams = React.useMemo(() => {
    const all = [
      ...(typeof EDEXCEL_GCSE_EXAMS!=="undefined"?EDEXCEL_GCSE_EXAMS:[]),
      ...(typeof AQA_GCSE_EXAMS!=="undefined"?AQA_GCSE_EXAMS:[]),
    ];
    return all.filter(e => {
      const d = new Date(e.date);
      return d.getMonth()===month && d.getFullYear()===year;
    }).map(e => ({ ...e, day: new Date(e.date).getDate() }));
  }, [month, year]);

  const todayStr = `${today.getFullYear()}-${today.getMonth()+1}-${today.getDate()}`;

  return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Revision Calendar" note="Tap a day to log what you revised. Exam dates shown automatically." />
      {/* Month nav */}
      <div className="flex items-center justify-between">
        <button onClick={()=>{ if(month===0){setMonth(11);setYear(y=>y-1);}else setMonth(m=>m-1); }}
          className="rounded-xl px-3 py-2 text-sm font-semibold"
          style={{ border:`1px solid ${c.line}`, color:c.inkSoft }}>←</button>
        <span className="font-bold text-base" style={{ color:c.ink }}>{MONTHS[month]} {year}</span>
        <button onClick={()=>{ if(month===11){setMonth(0);setYear(y=>y+1);}else setMonth(m=>m+1); }}
          className="rounded-xl px-3 py-2 text-sm font-semibold"
          style={{ border:`1px solid ${c.line}`, color:c.inkSoft }}>→</button>
      </div>
      {/* Calendar grid */}
      <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
        <div className="grid grid-cols-7" style={{ background:c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
          {["Su","Mo","Tu","We","Th","Fr","Sa"].map(d=>(
            <div key={d} className="text-center py-2 text-[10px] font-bold" style={{ color:c.mute }}>{d}</div>
          ))}
        </div>
        <div className="grid grid-cols-7">
          {Array.from({length:firstDay}).map((_,i)=><div key={"e"+i} className="h-12"/>)}
          {Array.from({length:daysInMonth}).map((_,i)=>{
            const day = i+1;
            const dateStr = `${year}-${month+1}-${day}`;
            const isToday = dateStr === todayStr;
            const hasSession = !!sessions[dateStr];
            const exam = exams.find(e=>e.day===day);
            return (
              <button key={day} onClick={()=>{setSelected(dateStr);setNote(sessions[dateStr]||"");}}
                className="h-12 flex flex-col items-center justify-center gap-0.5 relative"
                style={{ background: selected===dateStr?"rgba(201,168,76,0.12)":isToday?"rgba(201,168,76,0.06)":"transparent",
                  borderTop:`1px solid ${c.lineSoft}` }}>
                <span className="text-xs font-semibold rounded-full w-6 h-6 flex items-center justify-center"
                  style={{ background: isToday?"#C9A84C":"transparent", color: isToday?"#fff":c.ink, fontWeight:isToday?700:400 }}>
                  {day}
                </span>
                {exam && <div style={{ width:4,height:4,borderRadius:2,background:"#DC2626" }}/>}
                {hasSession && !exam && <div style={{ width:4,height:4,borderRadius:2,background:"#059669" }}/>}
              </button>
            );
          })}
        </div>
      </div>
      {/* Legend */}
      <div className="flex gap-4 text-[11px]" style={{ color:c.mute }}>
        <div className="flex items-center gap-1.5"><div style={{width:8,height:8,borderRadius:4,background:"#DC2626"}}/> Exam</div>
        <div className="flex items-center gap-1.5"><div style={{width:8,height:8,borderRadius:4,background:"#059669"}}/> Revision logged</div>
        <div className="flex items-center gap-1.5"><div style={{width:16,height:16,borderRadius:8,background:"#C9A84C",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,color:"#fff"}}>7</div> Today</div>
      </div>
      {/* Log session */}
      {selected && (
        <div className="rounded-2xl p-4 space-y-3" style={{ background:c.surface, border:`1px solid ${c.line}` }}>
          <p className="text-sm font-bold" style={{ color:c.ink }}>
            {new Date(selected.replace(/-/g,'/')).toLocaleDateString("en-GB",{weekday:"long",day:"numeric",month:"long"})}
          </p>
          <textarea value={note} onChange={e=>setNote(e.target.value)}
            placeholder="What did you revise today? (e.g. Medicine Q2a source analysis, Nazi Germany essay plans…)"
            rows={3} className="w-full rounded-xl px-3 py-2.5 text-sm resize-none"
            style={{ border:`1px solid ${c.line}`, color:c.ink, background:"#fff" }} />
          <div className="flex gap-2">
            <button onClick={()=>{saveSession(selected,note);setSelected(null);}}
              className="flex-1 rounded-xl py-2 text-sm font-bold text-white" style={{ background:c.oxblood }}>Save session</button>
            {sessions[selected] && <button onClick={()=>{saveSession(selected,"");setSelected(null);}}
              className="rounded-xl px-3 py-2 text-sm font-semibold" style={{ border:`1px solid ${c.line}`, color:c.mute }}>Clear</button>}
          </div>
        </div>
      )}
      {/* Upcoming exams this month */}
      {exams.length>0 && (
        <div className="rounded-2xl overflow-hidden" style={{ border:"1px solid #FECACA" }}>
          <div className="px-4 py-2" style={{ background:"#FEF2F2", borderBottom:"1px solid #FECACA" }}>
            <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color:"#DC2626" }}>📅 EXAMS THIS MONTH</span>
          </div>
          {exams.map((e,i)=>(
            <div key={i} className="px-4 py-2.5 flex items-center gap-3" style={{ borderTop:i?`1px solid #FECACA`:"none" }}>
              <span className="font-mono font-bold text-sm" style={{ color:"#DC2626", minWidth:24 }}>{e.day}</span>
              <span className="text-xs" style={{ color:c.ink }}>{e.name}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}


function ClassCompetitionPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const [classCode, setClassCode] = React.useState(() => { try { return localStorage.getItem("ec_class_code")||""; } catch { return ""; }});
  const [name, setName] = React.useState(() => { try { return localStorage.getItem("ec_student_name")||""; } catch { return ""; }});
  const [joined, setJoined] = React.useState(false);
  const [leaderboard, setLeaderboard] = React.useState([]);

  // Compute this student's stats
  const myStats = React.useMemo(() => {
    let total=0, confident=0;
    topics.forEach(t => {
      const entries = (data[t.id]||[]).filter(e=>e.source!=="scaffold");
      total += entries.length;
      confident += entries.filter(e=>e.confidence===2).length;
    });
    return { total, confident, pct: total>0?Math.round(confident/total*100):0 };
  }, [topics, data]);

  function joinClass() {
    if (!classCode.trim() || !name.trim()) { alert("Please enter your name and class code."); return; }
    try {
      localStorage.setItem("ec_class_code", classCode.trim().toUpperCase());
      localStorage.setItem("ec_student_name", name.trim());
      // Store my entry in shared leaderboard key
      const key = `ec_lb_${classCode.trim().toUpperCase()}`;
      const existing = JSON.parse(localStorage.getItem(key)||"[]");
      const myEntry = { name: name.trim(), pct: myStats.pct, confident: myStats.confident, total: myStats.total, updated: Date.now() };
      const updated = [...existing.filter(e=>e.name!==name.trim()), myEntry].sort((a,b)=>b.pct-a.pct);
      localStorage.setItem(key, JSON.stringify(updated));
      setLeaderboard(updated);
    } catch {}
    setJoined(true);
  }

  function refreshLeaderboard() {
    try {
      const key = `ec_lb_${classCode.trim().toUpperCase()}`;
      // Update my stats
      const existing = JSON.parse(localStorage.getItem(key)||"[]");
      const myEntry = { name: name.trim(), pct: myStats.pct, confident: myStats.confident, total: myStats.total, updated: Date.now() };
      const updated = [...existing.filter(e=>e.name!==name.trim()), myEntry].sort((a,b)=>b.pct-a.pct);
      localStorage.setItem(key, JSON.stringify(updated));
      setLeaderboard(updated);
    } catch {}
  }

  const MEDALS = ["🥇","🥈","🥉"];

  return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Class Competition" note="Share a class code with your students — confidence scores appear on a live leaderboard." />

      {!joined ? (
        <div className="space-y-3">
          <div className="rounded-2xl p-4 space-y-3" style={{ background:c.surface, border:`1px solid ${c.line}` }}>
            <p className="text-sm font-semibold" style={{ color:c.ink }}>👥 Join a class leaderboard</p>
            <div className="space-y-2">
              <input value={name} onChange={e=>setName(e.target.value)} placeholder="Your name"
                className="w-full rounded-xl px-3 py-2.5 text-sm" style={{ border:`1px solid ${c.line}`, color:c.ink, background:"#fff" }} />
              <input value={classCode} onChange={e=>setClassCode(e.target.value.toUpperCase())} placeholder="Class code (e.g. HISTORY2025)"
                className="w-full rounded-xl px-3 py-2.5 text-sm font-mono uppercase" style={{ border:`1px solid ${c.line}`, color:c.ink, background:"#fff" }} />
            </div>
            <button onClick={joinClass} className="w-full rounded-xl py-2.5 text-sm font-bold text-white" style={{ background:c.oxblood }}>
              Join leaderboard →
            </button>
          </div>
          <div className="rounded-2xl p-4" style={{ background:"#F5F3FF", border:"1px solid #DDD6FE" }}>
            <p className="text-xs font-semibold mb-1" style={{ color:"#7C3AED" }}>📋 For teachers: create a class</p>
            <p className="text-xs" style={{ color:c.mute }}>Pick any class code (e.g. your school name + year), share it with students, and everyone who joins with that code appears on the leaderboard. Scores are anonymous to classmates — only names and percentages are shown.</p>
            <div className="mt-3 flex gap-2">
              {["HISTORY25","GCSE2025","MRSSMITH"].map(code=>(
                <button key={code} onClick={()=>setClassCode(code)}
                  className="text-[10px] font-mono font-bold rounded-lg px-2 py-1"
                  style={{ background:"#EDE9FE", color:"#7C3AED" }}>{code}</button>
              ))}
            </div>
          </div>
        </div>
      ) : (
        <div className="space-y-3">
          {/* My stats */}
          <div className="rounded-2xl p-4 flex items-center gap-4" style={{ background:c.night, color:"#fff" }}>
            <div>
              <p className="text-3xl font-black font-mono" style={{ color:"#C9A84C" }}>{myStats.pct}%</p>
              <p className="text-xs" style={{ color:"#64748B" }}>your confidence</p>
            </div>
            <div className="flex-1">
              <p className="text-sm font-bold">{name}</p>
              <p className="text-xs mt-0.5" style={{ color:"#64748B" }}>Class: {classCode}</p>
              <div className="rounded-full h-1.5 mt-2" style={{ background:"rgba(255,255,255,0.15)" }}>
                <div className="rounded-full h-1.5" style={{ width:`${myStats.pct}%`, background:"#C9A84C" }} />
              </div>
            </div>
            <button onClick={refreshLeaderboard}
              className="rounded-xl px-3 py-2 text-xs font-semibold" style={{ background:"rgba(255,255,255,0.1)", color:"#fff" }}>
              <RefreshCw size={12} />
            </button>
          </div>

          {/* Leaderboard */}
          <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
            <div className="px-4 py-2.5 flex items-center justify-between" style={{ background:c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
              <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color:c.mute }}>🏆 LEADERBOARD</span>
              <span className="text-[10px]" style={{ color:c.mute }}>{leaderboard.length} students</span>
            </div>
            {leaderboard.length === 0 ? (
              <div className="p-8 text-center">
                <p className="text-sm" style={{ color:c.mute }}>No other students yet. Share the code <strong style={{color:c.ink}}>{classCode}</strong> with your class!</p>
              </div>
            ) : (
              <div className="divide-y" style={{ borderColor:c.lineSoft }}>
                {leaderboard.map((entry, i) => (
                  <div key={entry.name} className="px-4 py-3 flex items-center gap-3"
                    style={{ background: entry.name===name ? "rgba(201,168,76,0.06)" : "transparent" }}>
                    <span className="text-lg w-8 text-center">{MEDALS[i] || `${i+1}`}</span>
                    <div className="flex-1">
                      <p className="text-sm font-semibold" style={{ color:c.ink }}>{entry.name} {entry.name===name?"(you)":""}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <div className="flex-1 rounded-full h-1.5" style={{ background:c.lineSoft }}>
                          <div className="rounded-full h-1.5" style={{ width:`${entry.pct}%`, background:"linear-gradient(to right,#C9A84C,#059669)" }} />
                        </div>
                        <span className="text-[11px] font-mono font-bold" style={{ color:entry.pct>75?"#059669":"#C9A84C" }}>{entry.pct}%</span>
                      </div>
                    </div>
                    <span className="text-[10px] font-mono" style={{ color:c.mute }}>{entry.confident}/{entry.total}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
          <button onClick={()=>{setJoined(false);setLeaderboard([]);}}
            className="text-xs font-semibold" style={{ color:c.mute }}>← Leave class</button>
        </div>
      )}
    </div>
  );
}


function AIPredictorPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const [loading, setLoading] = React.useState(false);
  const [predictions, setPredictions] = React.useState(null);
  const [error, setError] = React.useState(null);
  const [selectedTopic, setSelectedTopic] = React.useState(null);
  const { provider, apiKey, endpoint } = useAIProvider();

  // Compute "gap" score for each topic/question type
  const gaps = React.useMemo(() => {
    const out = [];
    topics.forEach(t => {
      const entries = (data[t.id]||[]).filter(e=>e.source==="verified");
      if (!entries.length) return;
      const yearsSeen = [...new Set(entries.map(e=>e.series||0))].sort((a,b)=>b-a);
      const latestYear = yearsSeen[0] || 0;
      const currentYear = new Date().getFullYear();
      const yearsSinceLastSeen = currentYear - latestYear;
      // Group by question type
      const qTypes = {};
      entries.forEach(e => {
        const key = `Q${e.qNumber} [${e.marks}m]`;
        if (!qTypes[key]) qTypes[key] = {count:0, lastYear:0, marks:e.marks, qNum:e.qNumber, topic:t.name};
        qTypes[key].count++;
        qTypes[key].lastYear = Math.max(qTypes[key].lastYear, e.series||0);
      });
      Object.entries(qTypes).forEach(([key, val]) => {
        const gap = currentYear - val.lastYear;
        out.push({ topicId:t.id, topicName:t.name, qKey:key, gap, ...val, short:t.short });
      });
    });
    return out.sort((a,b) => b.gap-a.gap || b.marks-a.marks);
  }, [topics, data]);

  async function generatePredictions() {
    setLoading(true); setPredictions(null); setError(null);
    const topGaps = gaps.slice(0,12);
    const prompt = [
      "You are an expert " + board + " " + level + " " + subject + " examiner with deep knowledge of exam patterns.",
      "",
      "Based on these question types and their last appearance:",
      topGaps.map(g => "- " + g.topicName + " | " + g.qKey + " | Last seen: " + (g.lastYear||"unknown") + " | Gap: " + g.gap + "yrs | Appeared " + g.count + "x").join("\n"),
      "",
      "Predict the most likely questions for the next " + board + " " + level + " " + subject + " exam.",
      "",
      "Respond ONLY with valid JSON (no markdown):",
      JSON.stringify({hot:[{topic:"",question:"",marks:0,reason:"",confidence:"High/Medium"}],watch:[{topic:"",question:"",marks:0,reason:"",confidence:"Medium/Low"}],insight:""}),
      "",
      "Give 3-4 hot predictions (most likely) and 2-3 watch (worth preparing). Be specific about question wording and marks."
    ].join("\n");

    try {
      const raw = await callAIText({ provider, apiKey, endpoint, prompt });
      const clean = raw.replace(/```json|```/g,"").trim();
      setPredictions(JSON.parse(clean));
    } catch(e) { setError("Prediction failed: "+e.message); }
    setLoading(false);
  }

  const CONF_COLOR = { High:"#059669", Medium:"#D97706", Low:"#94A3B8" };

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="AI Question Predictor"
        note="Analyses historical paper patterns to predict the most likely questions for your next exam." />

      {/* Gap analysis preview */}
      {gaps.length > 0 && (
        <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
          <div className="px-4 py-2.5" style={{ background:c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
            <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color:c.mute }}>
              📊 PATTERN ANALYSIS — {gaps.length} question types tracked
            </span>
          </div>
          <div className="divide-y max-h-44 overflow-y-auto" style={{ borderColor:c.lineSoft }}>
            {gaps.slice(0,8).map((g,i) => (
              <div key={i} className="px-4 py-2 flex items-center gap-3">
                <div className="flex-1 min-w-0">
                  <p className="text-[11px] font-semibold truncate" style={{ color:c.ink }}>{g.topicName}</p>
                  <p className="text-[10px]" style={{ color:c.mute }}>{g.qKey}</p>
                </div>
                <div className="text-right shrink-0">
                  <p className="text-[11px] font-mono font-bold"
                    style={{ color: g.gap>=3?"#DC2626":g.gap>=2?"#D97706":"#059669" }}>
                    {g.gap}yr gap
                  </p>
                  <p className="text-[9px]" style={{ color:c.mute }}>last {g.lastYear||"?"}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <button onClick={generatePredictions} disabled={loading || !apiKey}
        className="w-full rounded-2xl py-3.5 font-bold text-sm text-white flex items-center justify-center gap-2 disabled:opacity-40"
        style={{ background:"linear-gradient(135deg,#0D1B2E,#C9A84C)" }}>
        {loading ? <><Loader2 size={16} className="animate-spin"/>Analysing patterns…</> : "🔮  Generate predictions"}
      </button>
      {!apiKey && <p className="text-xs text-center" style={{color:c.mute}}>Add an AI API key in the Marker panel to use this feature.</p>}

      {error && <div className="rounded-xl p-3 text-sm" style={{background:"#FEF2F2",color:"#DC2626"}}>{error}</div>}

      {predictions && (
        <div className="space-y-4">
          {predictions.insight && (
            <div className="rounded-2xl p-4" style={{background:"linear-gradient(135deg,#0D1B2E,#1A2B42)",color:"#fff"}}>
              <p className="text-[10px] font-mono font-bold mb-2" style={{color:"#C9A84C"}}>💡 EXAMINER INSIGHT</p>
              <p className="text-sm leading-relaxed">{predictions.insight}</p>
            </div>
          )}
          <div>
            <p className="text-[10px] font-mono font-bold tracking-widest mb-2" style={{color:"#DC2626"}}>
              🔥 MOST LIKELY TO APPEAR
            </p>
            <div className="space-y-2.5">
              {(predictions.hot||[]).map((p,i) => (
                <div key={i} className="rounded-2xl p-4" style={{background:c.surface,border:`1px solid ${c.line}`}}>
                  <div className="flex items-start justify-between gap-2 mb-2">
                    <span className="text-[10px] font-mono font-bold rounded-full px-2 py-0.5"
                      style={{background:c.oxbloodSoft,color:c.oxblood}}>{p.topic}</span>
                    <div className="flex items-center gap-1.5 shrink-0">
                      <span className="text-[9px] font-bold rounded-full px-2 py-0.5 text-white"
                        style={{background:CONF_COLOR[p.confidence]||"#94A3B8"}}>{p.confidence}</span>
                      <span className="text-[10px] font-mono font-bold" style={{color:c.oxblood}}>[{p.marks}m]</span>
                    </div>
                  </div>
                  <p className="text-sm font-semibold mb-1.5" style={{color:c.ink}}>{p.question}</p>
                  <p className="text-[11px] italic" style={{color:c.mute}}>{p.reason}</p>
                </div>
              ))}
            </div>
          </div>
          {(predictions.watch||[]).length > 0 && (
            <div>
              <p className="text-[10px] font-mono font-bold tracking-widest mb-2" style={{color:"#D97706"}}>
                👀 WORTH WATCHING
              </p>
              <div className="space-y-2">
                {(predictions.watch||[]).map((p,i) => (
                  <div key={i} className="rounded-xl p-3 flex gap-3" style={{background:c.brassSoft,border:`1px solid ${c.brass}30`}}>
                    <div className="flex-1">
                      <p className="text-[11px] font-semibold" style={{color:c.ink}}>{p.question}</p>
                      <p className="text-[10px] mt-0.5" style={{color:c.mute}}>{p.topic} · {p.reason}</p>
                    </div>
                    <span className="text-[10px] font-mono font-bold shrink-0" style={{color:c.brass}}>[{p.marks}m]</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


function SourcePracticePanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const [phase, setPhase] = React.useState("select"); // select | practice | marking | done
  const [selectedQ, setSelectedQ] = React.useState(null);
  const [answer, setAnswer] = React.useState("");
  const [timeLeft, setTimeLeft] = React.useState(0);
  const [feedback, setFeedback] = React.useState(null);
  const [loading, setLoading] = React.useState(false);
  const timerRef = React.useRef(null);
  const { provider, apiKey, endpoint } = useAIProvider();

  // All source/interpretation questions
  const sourceQs = React.useMemo(() => {
    const out = [];
    topics.forEach(t => {
      (data[t.id]||[]).filter(e => {
        if (e.source==="scaffold") return false;
        const q = String(e.qNumber||"");
        return q.match(/^[123]\(a\)|^[123]\(b\)|^[123]\(c\)|^1$/) && (e.marks||0) <= 12;
      }).forEach(e => out.push({entry:e, topic:t}));
    });
    return out.sort((a,b) => (b.entry.marks||0)-(a.entry.marks||0));
  }, [topics, data]);

  function startPractice(q) {
    setSelectedQ(q);
    const mins = q.entry.marks <= 4 ? 5 : q.entry.marks <= 8 ? 8 : 12;
    setTimeLeft(mins * 60);
    setAnswer(""); setFeedback(null); setPhase("practice");
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) { clearInterval(timerRef.current); setPhase("marking"); return 0; }
        return t-1;
      });
    }, 1000);
  }

  async function submitForMarking() {
    clearInterval(timerRef.current);
    setPhase("marking"); setLoading(true);
    const {entry:e, topic:t} = selectedQ;
    const sourceText = e.sourceText || e.interp1 || "";
    const prompt = [
          "You are an expert " + board + " " + level + " History examiner. Mark this student response.",
          "",
          "Question: \"" + e.summary + "\" [" + e.marks + " marks]",
          sourceText ? "Source: \"" + sourceText.slice(0,400) + "\"" : "",
          "Mark scheme: " + (e.markScheme || "Standard mark scheme criteria apply."),
          "",
          "Student answer:",
          "\"" + answer + "\"",
          "",
          "Mark this response. Respond ONLY with valid JSON:",
          JSON.stringify({score:0,maxScore:e.marks,level:"Level 1/2/3/4",strengths:["point"],improvements:["point"],examinerNote:"note"})
        ].filter(Boolean).join("\n");
    try {
      const raw = await callAIText({ provider, apiKey, endpoint, prompt });
      setFeedback(JSON.parse(raw.replace(/```json|```/g,"").trim()));
    } catch(e) { setFeedback({score:0,maxScore:e.marks,strengths:[],improvements:["Marking failed — "+e.message],examinerNote:""}); }
    setLoading(false); setPhase("done");
  }

  React.useEffect(() => () => clearInterval(timerRef.current), []);

  const mm = String(Math.floor(timeLeft/60)).padStart(2,"0");
  const ss = String(timeLeft%60).padStart(2,"0");
  const urgency = timeLeft<60?"#DC2626":timeLeft<180?"#D97706":"#059669";

  if (phase==="select") return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Timed Source Practice"
        note="Pick a source or interpretation question. Timer starts automatically. AI marks your response when time is up." />
      <div className="space-y-2">
        {sourceQs.length===0 && <p style={{color:c.mute}} className="text-sm">No source questions found for this spec.</p>}
        {sourceQs.slice(0,20).map(({entry:e,topic:t},i) => (
          <button key={e.id} onClick={() => startPractice({entry:e,topic:t})}
            className="w-full text-left rounded-2xl p-4"
            style={{background:c.surface,border:`1px solid ${c.line}`,transition:"all 0.15s"}}
            onMouseEnter={ev=>{ev.currentTarget.style.borderLeft="3px solid #C9A84C";ev.currentTarget.style.background="rgba(201,168,76,0.04)";}}
            onMouseLeave={ev=>{ev.currentTarget.style.borderLeft=`1px solid ${c.line}`;ev.currentTarget.style.background=c.surface;}}>
            <div className="flex items-center gap-2 mb-1 flex-wrap">
              <span className="text-[10px] font-mono font-bold rounded-full px-2 py-0.5"
                style={{background:c.oxbloodSoft,color:c.oxblood}}>{t.short}</span>
              <span className="text-[10px] font-mono" style={{color:c.mute}}>
                {e.series} · Q{e.qNumber} · {e.marks}m · {e.marks<=4?"5 min":e.marks<=8?"8 min":"12 min"}
              </span>
              {e.sourceText && <span className="text-[9px] rounded-full px-1.5 py-0.5 font-bold"
                style={{background:c.tealSoft,color:c.teal}}>HAS SOURCE</span>}
            </div>
            <p className="text-xs" style={{color:c.ink}}>{e.summary}</p>
          </button>
        ))}
      </div>
    </div>
  );

  const {entry:e,topic:t} = selectedQ||{entry:{},topic:{}};

  if (phase==="practice") return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-3">
      {/* Timer */}
      <div className="rounded-2xl p-3 flex items-center gap-3 sticky top-0 z-10"
        style={{background:c.night,boxShadow:"0 4px 16px rgba(13,27,46,0.3)"}}>
        <div className="flex-1 rounded-full h-2" style={{background:"rgba(255,255,255,0.1)"}}>
          <div className="h-2 rounded-full transition-all"
            style={{width:`${(timeLeft/(e.marks<=4?300:e.marks<=8?480:720))*100}%`,background:urgency}} />
        </div>
        <span className="font-mono font-bold text-sm shrink-0" style={{color:urgency,minWidth:52}}>{mm}:{ss}</span>
        <button onClick={() => { clearInterval(timerRef.current); setPhase("marking"); }}
          className="text-xs px-3 py-1.5 rounded-lg font-semibold" style={{background:"rgba(255,255,255,0.1)",color:"#fff"}}>
          Submit
        </button>
      </div>
      {/* Question */}
      <div className="rounded-2xl p-4 space-y-2" style={{background:c.surface,border:`1px solid ${c.line}`}}>
        <div className="flex items-center gap-2">
          <span className="font-mono font-bold text-[11px] rounded-full px-2 py-0.5"
            style={{background:c.oxbloodSoft,color:c.oxblood}}>Q{e.qNumber} [{e.marks}m]</span>
        </div>
        {(e.sourceText||e.interp1) && (
          <div className="rounded-xl p-3 italic text-xs leading-relaxed" style={{background:"#FFFEF5",border:"1px solid #FDE68A",color:"#78350F"}}>
            <p className="font-bold not-italic text-[10px] mb-1 uppercase tracking-wide">Source</p>
            {(e.sourceText||e.interp1).slice(0,500)}
          </div>
        )}
        <p className="text-sm font-semibold" style={{color:c.ink}}>{e.summary}</p>
      </div>
      {/* Answer */}
      <textarea value={answer} onChange={ev=>setAnswer(ev.target.value)}
        placeholder="Write your answer here…" rows={10}
        className="w-full rounded-2xl px-4 py-3 text-sm"
        style={{border:`1px solid ${c.line}`,color:c.ink,background:"#fff",resize:"none"}} />
      <button onClick={() => { clearInterval(timerRef.current); submitForMarking(); }}
        className="w-full rounded-2xl py-3 font-bold text-sm text-white"
        style={{background:c.oxblood}}>
        Submit for marking
      </button>
    </div>
  );

  if (phase==="marking") return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-20 text-center space-y-3">
      <Loader2 size={32} className="animate-spin mx-auto" style={{color:"#C9A84C"}} />
      <p className="text-sm font-semibold" style={{color:c.ink}}>Marking your response…</p>
    </div>
  );

  // done — show feedback
  const score = feedback?.score||0;
  const maxScore = feedback?.maxScore||e.marks||1;
  const pct = Math.round(score/maxScore*100);
  const col = pct>=75?"#059669":pct>=50?"#D97706":"#DC2626";

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      {/* Score */}
      <div className="rounded-2xl p-5 text-center" style={{background:c.night,color:"#fff"}}>
        <p style={{fontSize:52,fontWeight:900,color:col,fontFamily:"Montserrat,sans-serif",lineHeight:1}}>{score}</p>
        <p style={{color:"rgba(255,255,255,0.5)",fontSize:13}}>out of {maxScore} marks</p>
        {feedback?.level && <p className="mt-1 text-xs font-bold" style={{color:"#C9A84C"}}>{feedback.level}</p>}
      </div>
      {/* Strengths */}
      {feedback?.strengths?.length>0 && (
        <div className="rounded-2xl p-4" style={{background:c.tealSoft,border:`1px solid ${c.teal}30`}}>
          <p className="text-[10px] font-mono font-bold mb-2" style={{color:c.teal}}>✓ STRENGTHS</p>
          {feedback.strengths.map((s,i)=><p key={i} className="text-xs mb-1" style={{color:c.ink}}>• {s}</p>)}
        </div>
      )}
      {/* Improvements */}
      {feedback?.improvements?.length>0 && (
        <div className="rounded-2xl p-4" style={{background:c.brassSoft,border:`1px solid ${c.brass}30`}}>
          <p className="text-[10px] font-mono font-bold mb-2" style={{color:c.brass}}>⚠ IMPROVE</p>
          {feedback.improvements.map((s,i)=><p key={i} className="text-xs mb-1" style={{color:c.ink}}>• {s}</p>)}
        </div>
      )}
      {/* Examiner note */}
      {feedback?.examinerNote && (
        <div className="rounded-2xl p-4" style={{background:c.oxbloodSoft,border:`1px solid ${c.oxblood}30`}}>
          <p className="text-[10px] font-mono font-bold mb-1" style={{color:c.oxblood}}>📋 EXAMINER</p>
          <p className="text-xs italic" style={{color:c.ink}}>{feedback.examinerNote}</p>
        </div>
      )}
      <div className="flex gap-2">
        <button onClick={()=>{setPhase("select");setSelectedQ(null);setFeedback(null);setAnswer("");}}
          className="flex-1 rounded-2xl py-3 font-bold text-sm" style={{background:c.lineSoft,color:c.ink,border:`1px solid ${c.line}`}}>
          Try another
        </button>
        <button onClick={()=>{setPhase("practice");startPractice(selectedQ);}}
          className="flex-1 rounded-2xl py-3 font-bold text-sm text-white" style={{background:c.oxblood}}>
          Retry this question
        </button>
      </div>
    </div>
  );
}


function GradeTrackerPanel({ data, save }) {
  const KEY = "__grades";
  const grades = (data[KEY] || []);
  const [form, setForm] = React.useState({ date: new Date().toISOString().slice(0,10), label: "", score: "", max: "", note: "" });
  const [showForm, setShowForm] = React.useState(false);

  function addGrade() {
    if (!form.score || !form.max) return;
    const entry = { ...form, id: Date.now().toString(36), score: Number(form.score), max: Number(form.max) };
    save({ ...data, [KEY]: [...grades, entry].sort((a,b)=>a.date>b.date?1:-1) });
    setForm({ date: new Date().toISOString().slice(0,10), label: "", score: "", max: "", note: "" });
    setShowForm(false);
  }
  function removeGrade(id) { save({ ...data, [KEY]: grades.filter(g=>g.id!==id) }); }

  const scored = grades.filter(g=>g.score!==undefined && g.max>0);
  const maxScore = Math.max(...scored.map(g=>Math.round(g.score/g.max*100)), 0);
  const latest = scored.length ? Math.round(scored[scored.length-1].score/scored[scored.length-1].max*100) : null;
  const first   = scored.length > 1 ? Math.round(scored[0].score/scored[0].max*100) : null;
  const trend = (latest !== null && first !== null) ? latest - first : null;

  // Simple SVG line chart
  const W=300, H=90, PAD=16;
  const pts = scored.map((g,i)=>({x:PAD+(i/(Math.max(scored.length-1,1)))*(W-PAD*2), y:H-PAD-(g.score/g.max*(H-PAD*2))}));
  const polyline = pts.map(p=>p.x+","+p.y).join(" ");

  const GRADE_BAND = [
    {min:90,label:"A*",col:"#059669"},{min:80,label:"A",col:"#0D9488"},
    {min:70,label:"B",col:"#C9A84C"},{min:60,label:"C",col:"#D97706"},
    {min:50,label:"D",col:"#EA580C"},{min:0,label:"U",col:"#DC2626"}];
  const letterGrade = pct => (GRADE_BAND.find(b=>pct>=b.min)||GRADE_BAND[GRADE_BAND.length-1]);

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Grade Tracker" note="Log your mock and test scores to track improvement over time." />

      {/* Summary stats */}
      {scored.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          {[
            {label:"Latest",val:latest+"%",sub:letterGrade(latest).label,col:letterGrade(latest).col},
            {label:"Best",val:maxScore+"%",sub:letterGrade(maxScore).label,col:letterGrade(maxScore).col},
            {label:"Trend",val:(trend===null?"—":(trend>=0?"+":"")+trend+"%"),sub:trend===null?"no data":trend>0?"improving":trend<0?"declining":"steady",col:trend>0?"#059669":trend<0?"#DC2626":"#94A3B8"},
          ].map(({label,val,sub,col})=>(
            <div key={label} className="rounded-2xl p-4 text-center" style={{background:c.surface,border:"1px solid "+c.line}}>
              <p className="text-[10px] font-mono tracking-widest mb-1" style={{color:c.mute}}>{label.toUpperCase()}</p>
              <p className="text-2xl font-black font-mono" style={{color:col}}>{val}</p>
              <p className="text-[10px] mt-0.5" style={{color:c.mute}}>{sub}</p>
            </div>
          ))}
        </div>
      )}

      {/* Line chart */}
      {scored.length >= 2 && (
        <div className="rounded-2xl p-4" style={{background:c.surface,border:"1px solid "+c.line}}>
          <p className="text-[10px] font-mono tracking-widest mb-3" style={{color:c.mute}}>SCORE HISTORY</p>
          <svg width="100%" viewBox={"0 0 "+W+" "+H} style={{overflow:"visible"}}>
            {/* Grid lines */}
            {[25,50,75,100].map(pct=>(
              <g key={pct}>
                <line x1={PAD} y1={H-PAD-(pct/100*(H-PAD*2))} x2={W-PAD} y2={H-PAD-(pct/100*(H-PAD*2))}
                  stroke={c.lineSoft} strokeWidth="1" strokeDasharray="3,3"/>
                <text x={PAD-4} y={H-PAD-(pct/100*(H-PAD*2))+4} fontSize="8" fill={c.mute} textAnchor="end">{pct}%</text>
              </g>
            ))}
            {/* Line */}
            {pts.length>1&&<polyline points={polyline} fill="none" stroke="#C9A84C" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>}
            {/* Dots */}
            {pts.map((p,i)=>(
              <g key={i}>
                <circle cx={p.x} cy={p.y} r="4" fill={letterGrade(Math.round(scored[i].score/scored[i].max*100)).col} stroke="#fff" strokeWidth="1.5"/>
              </g>
            ))}
          </svg>
          <div className="flex justify-between mt-1" style={{fontSize:9,color:c.mute}}>
            {scored.map((g,i)=>(<span key={i} className="text-center" style={{flex:1}}>{g.date.slice(5)}</span>))}
          </div>
        </div>
      )}

      {/* Log list */}
      <div className="space-y-2">
        {grades.length === 0 && <p className="text-sm text-center py-8" style={{color:c.mute}}>No scores logged yet. Add your first result below.</p>}
        {grades.slice().reverse().map(g => {
          const pct = g.max>0?Math.round(g.score/g.max*100):0;
          const lg = letterGrade(pct);
          return (
            <div key={g.id} className="rounded-2xl px-4 py-3 flex items-center gap-3"
              style={{background:c.surface,border:"1px solid "+c.line}}>
              <div className="w-10 h-10 rounded-xl grid place-items-center font-black text-lg shrink-0"
                style={{background:lg.col+"22",color:lg.col}}>{lg.label}</div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold" style={{color:c.ink}}>{g.label||"Mock exam"}</p>
                <p className="text-[11px]" style={{color:c.mute}}>{g.date} · {g.score}/{g.max} marks · {pct}%</p>
                {g.note&&<p className="text-[10px] mt-0.5 italic" style={{color:c.mute}}>{g.note}</p>}
              </div>
              <button onClick={()=>removeGrade(g.id)} className="opacity-30 hover:opacity-80 text-sm" style={{color:c.ink}}>✕</button>
            </div>
          );
        })}
      </div>

      {/* Add form */}
      {showForm ? (
        <div className="rounded-2xl p-4 space-y-3" style={{background:c.surface,border:"1px solid "+c.line}}>
          <p className="text-xs font-bold" style={{color:c.ink}}>Add result</p>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-[10px] font-mono" style={{color:c.mute}}>DATE</label>
              <input type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}
                className="w-full rounded-lg px-3 py-2 text-sm mt-0.5" style={{border:"1px solid "+c.line,color:c.ink,background:"#fff"}}/>
            </div>
            <div>
              <label className="text-[10px] font-mono" style={{color:c.mute}}>PAPER / MOCK NAME</label>
              <input type="text" value={form.label} placeholder="e.g. Nov 2023 P1" onChange={e=>setForm({...form,label:e.target.value})}
                className="w-full rounded-lg px-3 py-2 text-sm mt-0.5" style={{border:"1px solid "+c.line,color:c.ink,background:"#fff"}}/>
            </div>
            <div>
              <label className="text-[10px] font-mono" style={{color:c.mute}}>SCORE</label>
              <input type="number" value={form.score} placeholder="54" onChange={e=>setForm({...form,score:e.target.value})}
                className="w-full rounded-lg px-3 py-2 text-sm mt-0.5" style={{border:"1px solid "+c.line,color:c.ink,background:"#fff"}}/>
            </div>
            <div>
              <label className="text-[10px] font-mono" style={{color:c.mute}}>MAX MARKS</label>
              <input type="number" value={form.max} placeholder="80" onChange={e=>setForm({...form,max:e.target.value})}
                className="w-full rounded-lg px-3 py-2 text-sm mt-0.5" style={{border:"1px solid "+c.line,color:c.ink,background:"#fff"}}/>
            </div>
          </div>
          <div>
            <label className="text-[10px] font-mono" style={{color:c.mute}}>NOTES (optional)</label>
            <input type="text" value={form.note} placeholder="e.g. ran out of time on Q4" onChange={e=>setForm({...form,note:e.target.value})}
              className="w-full rounded-lg px-3 py-2 text-sm mt-0.5" style={{border:"1px solid "+c.line,color:c.ink,background:"#fff"}}/>
          </div>
          <div className="flex gap-2">
            <button onClick={addGrade}
              className="flex-1 rounded-xl py-2.5 text-sm font-bold text-white" style={{background:c.oxblood}}>Save result</button>
            <button onClick={()=>setShowForm(false)}
              className="rounded-xl px-4 py-2.5 text-sm" style={{background:c.lineSoft,color:c.ink,border:"1px solid "+c.line}}>Cancel</button>
          </div>
        </div>
      ) : (
        <button onClick={()=>setShowForm(true)}
          className="w-full rounded-2xl py-3.5 text-sm font-bold flex items-center justify-center gap-2"
          style={{background:c.surface,color:c.oxblood,border:"2px dashed "+c.oxblood}}>
          + Add exam result
        </button>
      )}
    </div>
  );
}


function WeakSpotPanel({ data, board, level, subject, onQuickUpdate, setActive }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);

  const weak = React.useMemo(() => {
    const today = new Date().toISOString().slice(0,10);
    const items = [];
    topics.forEach(t => {
      (data[t.id]||[]).filter(e => e.source!=="scaffold").forEach(e => {
        const overdue = e.dueDate && e.dueDate <= today;
        const hard    = data.__difficulty?.[e.id]?.rating === "Hard";
        const conf    = e.confidence||0;
        // Score: lower = weaker (0=never done, conf=0, overdue/hard boost)
        const score = conf * 10 + (overdue?-5:0) + (hard?-3:0) + (e.dueDate?0:-2);
        items.push({ entry:e, topic:t, score, overdue, hard });
      });
    });
    return items.sort((a,b)=>a.score-b.score).slice(0,10);
  }, [data, topics]);

  if (weak.length === 0) return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-16 text-center">
      <p className="text-4xl mb-3">🎯</p>
      <p className="font-bold text-lg" style={{color:c.ink}}>No weak spots found</p>
      <p className="text-sm mt-1" style={{color:c.mute}}>Add questions and track confidence to see your focus areas.</p>
    </div>
  );

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-3">
      <SectionTitle n="01" title="Weak Spots" note="Your lowest-confidence questions across all topics. Focus here first." />
      {weak.map(({entry:e, topic:t, overdue, hard}) => (
        <div key={e.id} className="rounded-2xl p-4 space-y-2"
          style={{background:c.surface,border:"1px solid "+c.line}}>
          <div className="flex items-start justify-between gap-2 flex-wrap">
            <div className="flex items-center gap-1.5 flex-wrap">
              <span className="text-[10px] font-mono font-bold rounded-full px-2 py-0.5"
                style={{background:c.oxbloodSoft,color:c.oxblood}}>{t.short}</span>
              {overdue && <span className="text-[9px] font-bold rounded-full px-1.5 py-0.5"
                style={{background:"rgba(201,168,76,0.15)",color:"#C9A84C"}}>due</span>}
              {hard && <span className="text-[9px] font-bold rounded-full px-1.5 py-0.5"
                style={{background:"rgba(220,38,38,0.1)",color:"#DC2626"}}>hard</span>}
            </div>
            <span className="text-[10px] font-mono" style={{color:c.mute}}>{e.marks}m</span>
          </div>
          <p className="text-sm" style={{color:c.ink}}>{e.summary}</p>
          {e.note && <p className="text-[11px] italic px-2 py-1 rounded-lg"
            style={{background:c.tealSoft,color:c.teal}}>{e.note}</p>}
          <div className="flex items-center gap-2 pt-1">
            {["○","◑","●"].map((sym,v) => (
              <button key={v} onClick={() => onQuickUpdate(t.id, e.id, {confidence:v})}
                className="flex-1 rounded-xl py-2 text-sm font-bold transition-all"
                style={{background:(e.confidence===v)?["#94A3B8","#D97706","#059669"][v]+"22":"transparent",
                  color:["#94A3B8","#D97706","#059669"][v],
                  border:"1px solid "+["#94A3B8","#D97706","#059669"][v]+(e.confidence===v?"":"33")}}>
                {sym}
              </button>
            ))}
            <button onClick={() => setActive(t.id)}
              className="rounded-xl px-3 py-2 text-xs font-semibold"
              style={{background:c.lineSoft,color:c.inkSoft,border:"1px solid "+c.line}}>
              Go to topic
            </button>
          </div>
        </div>
      ))}
    </div>
  );
}


function DueQueuePanel({ data, board, level, subject, onQuickUpdate }) {
  const topics = TOPICS.filter(t => t.board===board && t.level===level && t.subject===subject);
  const today  = new Date().toISOString().slice(0,10);

  const queue = React.useMemo(() => {
    const items = [];
    topics.forEach(t => {
      (data[t.id]||[]).filter(e => e.source!=="scaffold" && e.dueDate && e.dueDate<=today)
        .forEach(e => items.push({entry:e, topic:t}));
    });
    return items.sort((a,b)=>(a.entry.dueDate||"").localeCompare(b.entry.dueDate||""));
  }, [data, topics, today]);

  const [idx, setIdx] = React.useState(0);
  const [flipped, setFlipped] = React.useState(false);
  const [done, setDone] = React.useState(false);

  function markAndNext(conf) {
    const {entry:e, topic:t} = queue[idx];
    onQuickUpdate(t.id, e.id, {confidence:conf});
    if (idx >= queue.length-1) { setDone(true); return; }
    setIdx(i => i+1); setFlipped(false);
  }

  if (queue.length===0) return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-16 text-center">
      <p className="text-4xl mb-3">✨</p>
      <p className="font-bold text-lg" style={{color:c.ink}}>Nothing due today!</p>
      <p className="text-sm mt-1" style={{color:c.mute}}>Your spaced repetition schedule is clear. Come back tomorrow.</p>
    </div>
  );

  if (done) return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-16 text-center">
      <p className="text-4xl mb-3">🎉</p>
      <p className="font-bold text-xl" style={{color:c.ink}}>Session complete!</p>
      <p className="text-sm mt-1" style={{color:c.mute}}>You reviewed all {queue.length} due questions.</p>
      <button onClick={() => {setIdx(0);setFlipped(false);setDone(false);}}
        className="mt-6 rounded-2xl px-6 py-3 text-sm font-bold text-white"
        style={{background:c.oxblood}}>Review again</button>
    </div>
  );

  const {entry:e, topic:t} = queue[idx];
  const progress = Math.round((idx/queue.length)*100);

  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <div className="flex items-center justify-between">
        <SectionTitle n={String(idx+1).padStart(2,"0")} title="Due Today"
          note={queue.length+" question"+(queue.length>1?"s":"")} />
        <span className="text-xs font-mono" style={{color:c.mute}}>{idx+1}/{queue.length}</span>
      </div>
      {/* Progress bar */}
      <div className="rounded-full h-1.5" style={{background:c.lineSoft}}>
        <div className="h-1.5 rounded-full transition-all duration-500"
          style={{width:progress+"%",background:"linear-gradient(90deg,#C9A84C,#059669)"}} />
      </div>
      {/* Card */}
      <div className="rounded-2xl p-5 min-h-[160px] space-y-3"
        style={{background:c.surface,border:"1px solid "+c.line}}>
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-[10px] font-mono font-bold rounded-full px-2 py-0.5"
            style={{background:c.oxbloodSoft,color:c.oxblood}}>{t.short}</span>
          <span className="text-[10px] font-mono" style={{color:c.mute}}>{e.marks}m</span>
          {e.dueDate && <span className="text-[9px] rounded-full px-1.5 py-0.5 font-bold"
            style={{background:"rgba(201,168,76,0.15)",color:"#C9A84C"}}>due {e.dueDate}</span>}
        </div>
        <p className="text-base font-semibold leading-snug" style={{color:c.ink}}>{e.summary}</p>
        {flipped && (
          <div className="rounded-xl p-3 text-xs leading-relaxed"
            style={{background:c.brassSoft,border:"1px solid "+c.brass+"40",color:c.ink}}>
            <p className="text-[9px] font-mono font-bold mb-1" style={{color:c.brass}}>MARK SCHEME</p>
            {e.markScheme||"No mark scheme stored."}
          </div>
        )}
        {e.note && !flipped && (
          <p className="text-[11px] italic px-2 py-1 rounded-lg"
            style={{background:c.tealSoft,color:c.teal}}>{e.note}</p>
        )}
      </div>
      {!flipped ? (
        <button onClick={() => setFlipped(true)}
          className="w-full rounded-2xl py-3.5 font-bold text-sm text-white"
          style={{background:"linear-gradient(135deg,#0D1B2E,#1A2B42)"}}>Show answer</button>
      ) : (
        <div className="grid grid-cols-3 gap-2">
          {[["○","Still learning","#94A3B8"],["◑","Getting there","#D97706"],["●","Got it!","#059669"]].map(([sym,label,col],v)=>(
            <button key={v} onClick={() => markAndNext(v)}
              className="rounded-2xl py-3 flex flex-col items-center gap-1"
              style={{background:col+"22",border:"2px solid "+col,color:col}}>
              <span className="text-xl">{sym}</span>
              <span className="text-[10px] font-bold">{label}</span>
            </button>
          ))}
        </div>
      )}
      <button onClick={() => {setIdx(i=>Math.min(i+1,queue.length-1));setFlipped(false);}}
        className="w-full text-xs py-2" style={{color:c.mute}}>Skip this one →</button>
    </div>
  );
}


function StudyPlanPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board === board && t.level === level && t.subject === subject);
  const today = new Date(); today.setHours(0,0,0,0);
  const nextExam = React.useMemo(() => {
    const all = [
      ...(typeof EDEXCEL_GCSE_EXAMS !== "undefined" ? EDEXCEL_GCSE_EXAMS : []),
      ...(typeof AQA_GCSE_EXAMS !== "undefined" ? AQA_GCSE_EXAMS : []),
      ...(typeof EDEXCEL_AL_EXAMS !== "undefined" ? EDEXCEL_AL_EXAMS : []),
      ...(typeof AQA_AL_EXAMS !== "undefined" ? AQA_AL_EXAMS : []),
    ];
    return all.map(e => { const d=new Date(e.date); d.setHours(0,0,0,0); return {...e,days:Math.round((d-today)/86400000)}; })
      .filter(e=>e.days>=0).sort((a,b)=>a.days-b.days)[0]||null;
  }, []);
  const stats = React.useMemo(() => {
    let total=0,notDone=0,attempted=0,confident=0;
    topics.forEach(t=>{
      const entries=(data[t.id]||[]).filter(e=>e.source!=="scaffold");
      total+=entries.length;
      entries.forEach(e=>{ if(!e.confidence||e.confidence===0)notDone++; else if(e.confidence===1)attempted++; else confident++; });
    });
    return {total,notDone,attempted,confident};
  },[topics,data]);
  const dailyTarget=nextExam&&nextExam.days>0?Math.ceil((stats.notDone+stats.attempted)/nextExam.days):stats.notDone+stats.attempted;
  return (
    <div className="max-w-2xl mx-auto px-3 sm:px-0 py-4 space-y-4">
      <SectionTitle n="01" title="Study Plan" note="Based on your confidence ratings and upcoming exam dates." />
      <div className="rounded-2xl p-4 sm:p-5" style={{background:c.night,color:"#fff"}}>
        {nextExam?(<>
          <div className="flex items-center justify-between mb-3">
            <div><p className="text-xs font-mono" style={{color:"#64748B"}}>NEXT EXAM</p><p className="font-bold text-base mt-0.5">{nextExam.name}</p></div>
            <div className="text-right">
              <p className="text-4xl font-bold font-mono" style={{color:nextExam.days<=7?"#FCD34D":"#34D399"}}>{nextExam.days}</p>
              <p className="text-xs" style={{color:"#64748B"}}>days away</p>
            </div>
          </div>
          <div className="rounded-xl p-3" style={{background:"rgba(255,255,255,0.06)"}}>
            <p className="text-xs font-semibold" style={{color:"#94A3B8"}}>To finish {stats.notDone+stats.attempted} remaining question{stats.notDone+stats.attempted!==1?"s":""} in time:</p>
            <p className="text-xl font-bold mt-0.5"><span style={{color:"#34D399"}}>{dailyTarget}</span><span className="text-sm font-normal ml-1" style={{color:"#94A3B8"}}>questions per day</span></p>
          </div>
        </>):(<p className="text-sm" style={{color:"#94A3B8"}}>No upcoming exams in the next 60 days.</p>)}
      </div>
      <div className="rounded-2xl p-4" style={{background:c.surface,border:`1px solid ${c.line}`}}>
        <p className="text-[10px] font-mono font-bold tracking-widest mb-3" style={{color:c.mute}}>OVERALL PROGRESS — {stats.total} QUESTIONS</p>
        <div className="flex gap-1 rounded-full overflow-hidden h-3 mb-3">
          {stats.total>0&&<>
            <div style={{width:`${stats.confident/stats.total*100}%`,background:"#059669"}}/>
            <div style={{width:`${stats.attempted/stats.total*100}%`,background:"#D97706"}}/>
            <div style={{width:`${stats.notDone/stats.total*100}%`,background:"#E2E8F0"}}/>
          </>}
        </div>
        <div className="flex gap-4 text-xs">
          {[["●","Confident",stats.confident,"#059669"],["◑","Attempted",stats.attempted,"#D97706"],["○","Not done",stats.notDone,"#94A3B8"]].map(([icon,l,n,col])=>(
            <div key={l} className="flex items-center gap-1.5"><span style={{color:col,fontWeight:"bold"}}>{icon}</span><span style={{color:c.inkSoft}}>{l}</span><span className="font-mono font-bold" style={{color:col}}>{n}</span></div>
          ))}
        </div>
      </div>
      <div className="rounded-2xl overflow-hidden" style={{border:`1px solid ${c.line}`}}>
        <div className="px-4 py-2.5" style={{background:c.lineSoft,borderBottom:`1px solid ${c.line}`}}>
          <span className="text-[10px] font-mono font-bold tracking-widest" style={{color:c.mute}}>PER-TOPIC BREAKDOWN</span>
        </div>
        <div className="divide-y" style={{borderColor:c.lineSoft}}>
          {topics.map(t=>{
            const entries=(data[t.id]||[]).filter(e=>e.source!=="scaffold");
            if(!entries.length)return null;
            const conf=entries.filter(e=>e.confidence===2).length;
            const att=entries.filter(e=>e.confidence===1).length;
            const none=entries.filter(e=>!e.confidence||e.confidence===0).length;
            const pct=Math.round(conf/entries.length*100);
            const Icon=t.icon;
            return(
              <div key={t.id} className="px-4 py-2.5 flex items-center gap-3">
                <Icon size={13} style={{color:c.mute,flexShrink:0}}/>
                <span className="text-xs flex-1 font-medium" style={{color:c.ink}}>{t.short}</span>
                <div className="flex gap-0.5 w-24 rounded-full overflow-hidden h-1.5">
                  <div style={{width:`${conf/entries.length*100}%`,background:"#059669"}}/>
                  <div style={{width:`${att/entries.length*100}%`,background:"#D97706"}}/>
                  <div style={{width:`${none/entries.length*100}%`,background:"#E2E8F0"}}/>
                </div>
                <span className="text-[11px] font-mono font-bold w-8 text-right" style={{color:pct===100?"#059669":c.mute}}>{pct}%</span>
                <ConfRing pct={pct} size={18}/>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}


/* ═══════════════════════════════════════════════════════════════════════════
   KnowledgeTest — AI-generated spec knowledge questions as flashcards
   ═══════════════════════════════════════════════════════════════════════════ */
/* ═══════════════════════════════════════════════════════════════════════════
   Self-marking — shared by both past-paper flashcards and knowledge test.
   Student types (or photos) their answer; AI compares to model answer and
   returns strengths, gaps and next steps.
   ═══════════════════════════════════════════════════════════════════════════ */

function AnimatedScore({ target, max }) {
  const [val, setVal] = React.useState(0);
  React.useEffect(() => {
    if (!target) return;
    let start = 0;
    const step = Math.max(1, Math.ceil(target / 24));
    const timer = setInterval(() => {
      start += step;
      if (start >= target) { setVal(target); clearInterval(timer); }
      else { setVal(start); }
    }, 32);
    return () => clearInterval(timer);
  }, [target]);
  const pct = max ? Math.round(val / max * 100) : 0;
  return (
    <div className="text-center shrink-0">
      <p className="font-black" style={{ fontSize:42, lineHeight:1, fontFamily:"'Montserrat',sans-serif",
        color: pct >= 75 ? "#34D399" : pct >= 50 ? "#FCD34D" : "#F87171" }}>
        {val}
      </p>
      <p className="text-xs opacity-60 mt-0.5">/ {max}</p>
    </div>
  );
}


function buildSelfMarkPrompt(question, modelAnswer, studentText) {
  return `You are an expert examiner marking a student's revision response.

QUESTION:
${question}

MODEL ANSWER / MARK SCHEME:
${modelAnswer}

STUDENT'S RESPONSE:
${studentText || "(No response provided — student left blank)"}

Compare the student's response against the model answer. Be constructive but honest.
Respond ONLY with a valid JSON object — no preamble, no markdown:

{
  "summary":   "<one sentence overall verdict>",
  "strengths": ["<specific thing they got right, referencing their actual words>", "..."],
  "gaps":      ["<specific knowledge or point missing from their response>", "..."],
  "nextSteps": ["<concrete revision action — e.g. 'Learn the date/name/fact X'>", "..."],
  "confidence": <0, 1, or 2>
}

confidence scoring:
  2 = strong (covered ≥75% of key points with accurate detail)
  1 = partial (covered 40–74% or had gaps in detail)
  0 = needs work (covered <40% or major inaccuracies)

strengths and gaps: 2–3 each, specific to THIS student's response.
nextSteps: 2–3 concrete, actionable revision suggestions.`;
}

async function callAISelfMark({ provider, apiKey, endpoint, prompt, imgB64, imgType }) {
  // If there is an image, use vision; otherwise text-only
  if (imgB64) {
    return callAI({ provider, apiKey, endpoint, prompt, imgB64, imgType: imgType || "image/jpeg" });
  }
  return callAIText({ provider, apiKey, endpoint, prompt });
}

function SelfMarkFeedback({ result, onNext, onOverride }) {
  const confItem = CONF[result.confidence] || CONF[0];
  return (
    <div className="space-y-2.5">
      {/* Verdict banner */}
      <div className="rounded-xl p-3 flex items-center gap-3"
        style={{ background: confItem.bg, border:`1px solid ${confItem.color}30` }}>
        <span className="text-2xl">{confItem.icon}</span>
        <div className="flex-1">
          <p className="text-xs font-bold" style={{ color: confItem.color }}>{confItem.label.toUpperCase()}</p>
          <p className="text-xs mt-0.5" style={{ color: c.inkSoft }}>{result.summary}</p>
        </div>
        <div className="flex flex-col gap-1">
          {CONF.map((cf, v) => (
            <button key={v} onClick={() => onOverride(v)} title={`Override: ${cf.label}`}
              className="rounded-md text-[10px] px-2 py-0.5 font-bold"
              style={{ background: v===result.confidence ? confItem.color : c.lineSoft,
                color: v===result.confidence ? "#fff" : c.mute }}>
              {cf.icon}
            </button>
          ))}
        </div>
      </div>

      {/* Strengths */}
      {result.strengths?.length > 0 && (
        <div className="rounded-xl p-3" style={{ background:"#ECFDF5", border:"1px solid #6EE7B7" }}>
          <p className="text-[10px] font-mono font-bold tracking-widest mb-1.5" style={{ color:"#065F46" }}>✓ STRENGTHS</p>
          <ul className="space-y-1">
            {result.strengths.map((s,i)=>(
              <li key={i} className="flex gap-2 text-xs" style={{ color:"#065F46" }}><span>•</span><span>{s}</span></li>
            ))}
          </ul>
        </div>
      )}

      {/* Gaps */}
      {result.gaps?.length > 0 && (
        <div className="rounded-xl p-3" style={{ background:"#FEF2F2", border:"1px solid #FCA5A5" }}>
          <p className="text-[10px] font-mono font-bold tracking-widest mb-1.5" style={{ color:"#991B1B" }}>⚠ GAPS IN YOUR ANSWER</p>
          <ul className="space-y-1">
            {result.gaps.map((s,i)=>(
              <li key={i} className="flex gap-2 text-xs" style={{ color:"#991B1B" }}><span>•</span><span>{s}</span></li>
            ))}
          </ul>
        </div>
      )}

      {/* Next steps */}
      {result.nextSteps?.length > 0 && (
        <div className="rounded-xl p-3" style={{ background:"#FFF7ED", border:"1px solid #FCD34D" }}>
          <p className="text-[10px] font-mono font-bold tracking-widest mb-1.5" style={{ color:"#92400E" }}>→ NEXT STEPS</p>
          <ul className="space-y-1">
            {result.nextSteps.map((s,i)=>(
              <li key={i} className="flex gap-2 text-xs" style={{ color:"#92400E" }}><span>{i+1}.</span><span>{s}</span></li>
            ))}
          </ul>
        </div>
      )}

      <button onClick={onNext}
        className="w-full rounded-xl py-2.5 text-sm font-bold text-white"
        style={{ background: c.oxblood }}>Next question →</button>
    </div>
  );
}

function SelfMarkInput({ onSubmit, onSkip, loading, question }) {
  const [text, setText] = React.useState("");
  const [imgB64, setImgB64] = React.useState(null);
  const [imgSrc, setImgSrc] = React.useState(null);
  const [imgType, setImgType] = React.useState("image/jpeg");
  const fileRef = React.useRef();

  async function handleFile(e) {
    const file = e.target.files?.[0]; if (!file) return;
    const type = file.type || "image/jpeg";
    setImgType(type);
    const compressed = await compressImage(file);
    setImgSrc(compressed); setImgB64(compressed.split(",")[1]);
  }

  const canSubmit = text.trim().length > 0 || !!imgB64;

  return (
    <div className="space-y-2">
      <p className="text-[10px] font-mono font-semibold tracking-widest" style={{ color: c.mute }}>YOUR ANSWER</p>
      <textarea
        value={text} onChange={e => setText(e.target.value)}
        placeholder="Type your answer here before revealing…"
        rows={4}
        className="w-full rounded-xl px-3 py-2.5 text-sm resize-none"
        style={{ border:`1px solid ${c.line}`, color: c.ink, background:"#fff", lineHeight:1.5 }}
      />
      {imgSrc && (
        <div className="relative rounded-xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
          <img src={imgSrc} alt="Your answer" className="w-full object-contain max-h-40" />
          <button onClick={() => { setImgSrc(null); setImgB64(null); }}
            className="absolute top-1.5 right-1.5 rounded-lg px-2 py-1 text-[10px] font-bold"
            style={{ background:"#DC2626", color:"#fff" }}>Remove</button>
        </div>
      )}
      <div className="flex gap-2">
        <input ref={fileRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFile} />
        <button onClick={() => fileRef.current?.click()}
          className="rounded-xl px-3 py-2 text-xs font-semibold"
          style={{ border:`1px solid ${c.line}`, color: c.mute, background:"#fff" }} title="Upload photo of handwritten answer">
          📷
        </button>
        <button onClick={onSkip}
          className="rounded-xl px-3 py-2 text-xs font-semibold"
          style={{ border:`1px solid ${c.line}`, color: c.mute }}>Skip</button>
        <button onClick={() => onSubmit({ text, imgB64, imgType })} disabled={!canSubmit || loading}
          className="flex-1 rounded-xl py-2 text-sm font-bold text-white disabled:opacity-40 flex items-center justify-center gap-2"
          style={{ background: c.oxblood }}>
          {loading ? <><Loader2 size={14} className="animate-spin" />Marking…</> : "Submit & mark ✓"}
        </button>
      </div>
    </div>
  );
}


function buildKnowledgePrompt(topic) {
  const specAreas = (SPEC_AREAS[topic.id] || []).join(", ");
  const examiner  = EXAMINER[topic.id];
  const papers    = topic.papers || topic.paper || topic.code || "";
  return `You are an experienced ${topic.board} ${topic.level} ${topic.subject} teacher creating a timed revision knowledge test.

TOPIC: ${topic.name}
SPECIFICATION CODE: ${topic.code || topic.id}
BOARD & LEVEL: ${topic.board} ${topic.level}
SPECIFICATION AREAS COVERED: ${specAreas || "All core content"}
${examiner ? "\nKEY EXAMINER NOTES: " + examiner.summary : ""}

Generate exactly 15 knowledge questions for students revising this specification. Cover:
- Key events, people, dates, causes and consequences  
- Specific factual detail examiners reward (statistics, names, turning points)
- Thematic patterns and change over time  
- Contested interpretations or significance debates where relevant

Mix difficulty:
- 5 EASY: direct recall — names, dates, simple facts
- 6 MEDIUM: explain a concept, event or change
- 4 HARD: evaluate significance, compare factors, or argue a case

Questions must be specific to this topic. Do NOT generate generic questions.

Respond ONLY with a valid JSON array — no preamble, no markdown fences, no explanation:
[
  { "q": "Question text?", "a": "Model answer (3-5 sentences with specific factual detail an examiner would reward)", "d": "easy" },
  { "q": "...", "a": "...", "d": "medium" }
]`;
}

