function ShimmerCard({ lines = 3, type = "question" }) {
  if (type === "question") return (
    <div className="rounded-2xl p-4 space-y-2.5" style={{ background:"#fff", border:"1px solid #E2E8F0" }}>
      {/* Exam-style header: Q-number badge + marks */}
      <div className="flex items-center gap-2">
        <div className="ec-shimmer rounded-full" style={{ height:20, width:20 }} />
        <div className="ec-shimmer rounded" style={{ height:12, width:60 }} />
        <div className="ec-shimmer rounded-full ml-auto" style={{ height:18, width:40 }} />
      </div>
      {/* Question text lines */}
      <div className="ec-shimmer rounded" style={{ height:11, width:"90%" }} />
      <div className="ec-shimmer rounded" style={{ height:11, width:"75%" }} />
      {lines > 2 && <div className="ec-shimmer rounded" style={{ height:11, width:"55%" }} />}
      {/* Confidence + actions row */}
      <div className="flex gap-2 pt-1">
        <div className="ec-shimmer rounded-lg" style={{ height:26, width:26 }} />
        <div className="ec-shimmer rounded" style={{ height:26, width:80 }} />
      </div>
    </div>
  );
  return (
    <div className="rounded-2xl p-4 space-y-2.5" style={{ background:"#fff", border:"1px solid #E2E8F0" }}>
      <div className="ec-shimmer" style={{ height:12, width:"60%" }} />
      {Array.from({length:lines}).map((_,i)=>(
        <div key={i} className="ec-shimmer" style={{ height:10, width:i===lines-1?"40%":"100%" }} />
      ))}
    </div>
  );
}


function KnowledgeTestPanel({ board, level, subject, data }) {
  const topics = TOPICS.filter(t => t.board === board && t.level === level && t.subject === subject);
  const { provider, apiKey, endpoint } = useAIProvider();

  const [tid, setTid] = React.useState(null);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState(null);
  const [cache, setCache] = React.useState({}); // tid → questions[]
  const [idx, setIdx] = React.useState(0);
  const [flipped, setFlipped] = React.useState(false);
  const [done, setDone] = React.useState(false);
  const [filterDiff, setFilterDiff] = React.useState("all");
  const [smLoading, setSmLoading] = React.useState(false);
  const [smResult, setSmResult]   = React.useState(null);

  React.useEffect(() => { setSmResult(null); setFlipped(false); }, [idx, tid]);

  const topic = TOPICS.find(t => t.id === tid);

  const deck = React.useMemo(() => {
    const qs = cache[tid] || [];
    if (filterDiff === "all") return qs;
    return qs.filter(q => q.d === filterDiff);
  }, [tid, cache, filterDiff]);

  async function generate(topicId) {
    const t = TOPICS.find(x => x.id === topicId);
    if (!t) return;
    setLoading(true); setError(null);
    try {
      const raw = await callAIText({ provider, apiKey, endpoint, prompt: buildKnowledgePrompt(t) });
      const qs = JSON.parse(raw);
      setCache(c => ({ ...c, [topicId]: qs }));
      setIdx(0); setFlipped(false); setDone(false);
    } catch (e) { setError("Could not generate questions: " + e.message); }
    finally { setLoading(false); }
  }

  function selectTopic(topicId) {
    setTid(topicId); setIdx(0); setFlipped(false); setDone(false);
    if (!cache[topicId]) generate(topicId);
  }

  function next() { if (idx >= deck.length - 1) { setDone(true); return; } setIdx(i=>i+1); setFlipped(false); }
  function prev() { setIdx(i=>Math.max(0,i-1)); setFlipped(false); }

  async function selfMarkKT({ text, imgB64, imgType }) {
    const card = deck[idx]; if (!card) return;
    const prompt = buildSelfMarkPrompt(card.q, card.a, text);
    setSmLoading(true);
    try {
      const raw = await callAISelfMark({ provider, apiKey, endpoint, prompt, imgB64, imgType });
      const result = JSON.parse(raw.replace(/```json|```/g,"").trim());
      setSmResult(result); setFlipped(true);
    } catch(err) {
      setSmResult({ summary: "Marking failed: " + err.message, strengths:[], gaps:[], nextSteps:[], confidence:1 });
      setFlipped(true);
    } finally { setSmLoading(false); }
  }

  const DIFF_COL = { easy: "#059669", medium: "#D97706", hard: "#DC2626" };
  const DIFF_BG  = { easy: "#ECFDF5", medium: "#FFF7ED", hard: "#FEF2F2" };

  return (
    <div className="space-y-3">
      {/* Topic grid */}
      {!tid ? (
        <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
          <div className="px-4 py-2.5" style={{ background: c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
            <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color: c.mute }}>SELECT SPEC TO TEST</span>
          </div>
          <div className="p-3 flex flex-wrap gap-2">
            {topics.map(t => {
              const cached = cache[t.id];
              const Icon = t.icon;
              return (
                <button key={t.id} onClick={() => selectTopic(t.id)}
                  className="flex items-center gap-2 rounded-xl px-3 py-2 text-sm font-medium text-left transition-colors"
                  style={{ background: c.surface, border:`1px solid ${c.line}` }}>
                  <Icon size={13} style={{ color: c.mute }} />
                  <span style={{ color: c.ink }}>{t.short}</span>
                  {cached && <span className="text-[10px] font-mono rounded-full px-1.5 py-0.5" style={{ background: "#7C3AED20", color:"#7C3AED" }}>{cached.length}q</span>}
                </button>
              );
            })}
          </div>
        </div>
      ) : (
        <>
          {/* Header row */}
          <div className="flex items-center gap-2 flex-wrap">
            <button onClick={() => setTid(null)} className="text-xs font-semibold rounded-lg px-3 py-1.5"
              style={{ color: c.mute, border:`1px solid ${c.line}` }}>← Topics</button>
            <span className="text-sm font-bold" style={{ color: c.ink }}>{topic?.short}</span>
            <span className="text-[11px] rounded-full px-2.5 py-0.5" style={{ background:"#7C3AED15", color:"#7C3AED", fontWeight:600 }}>AI Knowledge Test</span>
            {cache[tid] && (
              <button onClick={() => generate(tid)} disabled={loading}
                className="ml-auto text-[11px] font-semibold rounded-lg px-2.5 py-1 flex items-center gap-1"
                style={{ color:"#7C3AED", border:`1px solid #7C3AED30`, background:"#7C3AED0D" }}>
                <RefreshCw size={11} className={loading ? "animate-spin" : ""} /> Regenerate
              </button>
            )}
          </div>

          {/* Loading */}
          {loading && (
            <div className="space-y-3">
              <div className="flex items-center gap-2 px-1">
                <Loader2 size={14} className="animate-spin" style={{color:"#7C3AED"}} />
                <p className="text-xs font-semibold" style={{color:"#7C3AED"}}>{provider.logo} {provider.name} — generating questions for {topic?.short}…</p>
              </div>
              {[3,4,2].map((lines,i) => <ShimmerCard key={i} lines={lines} type="question" />)}
            </div>
          )}

          {/* Error */}
          {error && !loading && (
            <div className="rounded-xl p-4 space-y-2" style={{ background:"#FEF2F2", border:"1px solid #FCA5A5" }}>
              <p className="text-sm font-semibold text-red-700">{error}</p>
              <button onClick={() => generate(tid)}
                className="text-xs font-semibold rounded-lg px-3 py-1.5"
                style={{ background:"#DC2626", color:"#fff" }}>Try again</button>
            </div>
          )}

          {/* Deck */}
          {!loading && !error && deck.length > 0 && !done && (
            <div className="space-y-3">
              {/* Difficulty filter + progress */}
              <div className="flex items-center gap-2 flex-wrap">
                <div className="flex gap-1">
                  {[["all","All"],["easy","Easy"],["medium","Medium"],["hard","Hard"]].map(([v,l])=>(
                    <button key={v} onClick={()=>{setFilterDiff(v);setIdx(0);setFlipped(false);setDone(false);}}
                      className="text-[11px] font-semibold rounded-lg px-2.5 py-1"
                      style={{ background:filterDiff===v?(v==="all"?"#7C3AED":(DIFF_COL[v]||"#7C3AED")):"transparent",
                        color:filterDiff===v?"#fff":(DIFF_COL[v]||c.mute),
                        border:`1px solid ${filterDiff===v?(v==="all"?"#7C3AED":(DIFF_COL[v]||"#7C3AED")):c.line}` }}>
                      {l}
                    </button>
                  ))}
                </div>
                <div className="ml-auto flex items-center gap-2">
                  <div className="rounded-full h-1.5 w-24" style={{ background: c.line }}>
                    <div className="rounded-full h-1.5" style={{ width:`${((idx+1)/deck.length)*100}%`, background:"#7C3AED" }} />
                  </div>
                  <span className="text-[11px] font-mono" style={{ color: c.mute }}>{idx+1}/{deck.length}</span>
                </div>
              </div>

              {/* Card */}
              {(() => {
                const card = deck[idx];
                const diffCol = DIFF_COL[card.d] || c.mute;
                const diffBg  = DIFF_BG[card.d]  || c.lineSoft;
                return (
                  <div onClick={() => setFlipped(f => !f)} style={{ cursor:"pointer" }}>
                    <div className="rounded-2xl p-5 space-y-3" style={{ background: c.surface, border:`2px solid ${c.line}`, minHeight: 180 }}>
                      <div className="flex items-center justify-between">
                        <span className="rounded-full px-2.5 py-0.5 text-[10px] font-bold"
                          style={{ background: diffBg, color: diffCol }}>
                          {card.d?.toUpperCase() || "MEDIUM"}
                        </span>
                        <span className="text-[11px]" style={{ color: c.mute }}>
                          {flipped ? "▲ hide answer" : "▼ reveal answer"}
                        </span>
                      </div>
                      <p className="text-sm font-semibold leading-relaxed" style={{ color: c.ink }}>{card.q}</p>
                      {flipped && (
                        <div className="pt-3 mt-1 space-y-1.5" style={{ borderTop:`1px solid ${c.line}` }}>
                          <p className="text-[10px] font-mono font-bold tracking-widest" style={{ color:"#7C3AED" }}>MODEL ANSWER</p>
                          <p className="text-xs leading-relaxed" style={{ color: c.inkSoft }}>{card.a}</p>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })()}

              {/* Nav + self-marking */}
              {flipped ? (
                smResult
                  ? <SelfMarkFeedback result={smResult} onNext={next} onOverride={v=>setSmResult(r=>({...r,confidence:v}))} />
                  : <div className="space-y-2">
                      <div className="flex gap-2">
                        <button onClick={prev} disabled={idx===0}
                          className="rounded-xl px-4 py-2.5 text-sm font-semibold disabled:opacity-30"
                          style={{background:c.lineSoft,color:c.inkSoft,border:`1px solid ${c.line}`}}>← Prev</button>
                        <button onClick={next}
                          className="flex-1 rounded-xl py-2.5 text-sm font-bold text-white"
                          style={{background:"#7C3AED"}}>Next →</button>
                      </div>
                    </div>
              ) : (
                <div className="space-y-2">
                  <SelfMarkInput onSubmit={selfMarkKT} onSkip={()=>setFlipped(true)} loading={smLoading} />
                  <div className="flex gap-2">
                    <button onClick={prev} disabled={idx===0}
                      className="rounded-xl px-3 py-2 text-sm font-semibold disabled:opacity-30"
                      style={{background:c.lineSoft,color:c.inkSoft,border:`1px solid ${c.line}`}}>← Prev</button>
                    <button onClick={next}
                      className="rounded-xl px-3 py-2 text-sm font-semibold"
                      style={{background:c.lineSoft,color:c.inkSoft,border:`1px solid ${c.line}`}}>Skip →</button>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Done */}
          {done && !loading && (
            <div className="rounded-2xl p-8 text-center space-y-3" style={{ background:"#F5F3FF", border:"1px solid #DDD6FE" }}>
              <p className="text-3xl">🎓</p>
              <p className="font-bold text-lg" style={{ color:"#7C3AED" }}>Knowledge test complete!</p>
              <p className="text-sm" style={{ color: c.mute }}>{deck.length} question{deck.length!==1?"s":""} reviewed for {topic?.short}.</p>
              <div className="flex justify-center gap-2">
                <button onClick={()=>{setIdx(0);setFlipped(false);setDone(false);}}
                  className="rounded-xl px-4 py-2 text-sm font-semibold text-white" style={{background:"#7C3AED"}}>Restart</button>
                <button onClick={()=>generate(tid)}
                  className="rounded-xl px-4 py-2 text-sm font-semibold" style={{background:"#EDE9FE",color:"#7C3AED"}}>New questions</button>
              </div>
            </div>
          )}

          {/* Empty deck for filter */}
          {!loading && !error && deck.length === 0 && cache[tid]?.length > 0 && (
            <div className="rounded-xl p-6 text-center" style={{background:c.lineSoft}}>
              <p className="text-sm" style={{color:c.mute}}>No {filterDiff} questions. Try a different difficulty.</p>
            </div>
          )}
        </>
      )}
    </div>
  );
}


function FlashcardPanel({ board, level, subject, data, quickUpdate }) {
  const topics = TOPICS.filter(t => t.board === board && t.level === level && t.subject === subject);
  const [mode, setMode] = React.useState("papers"); // "papers" | "knowledge"
  const [tid, setTid] = React.useState(null);
  const [filterConf, setFilterConf] = React.useState("all"); // all | notyet | attempted
  const [idx, setIdx] = React.useState(0);
  const [flipped, setFlipped] = React.useState(false);
  const [done, setDone] = React.useState(false);
  const [smLoading, setSmLoading] = React.useState(false);
  const [smResult, setSmResult]   = React.useState(null);
  const { provider, apiKey, endpoint } = useAIProvider();

  React.useEffect(() => { setSmResult(null); setFlipped(false); }, [idx, tid]);

  const topic = TOPICS.find(t => t.id === tid);

  const deck = React.useMemo(() => {
    if (!tid) return [];
    const entries = (data[tid] || []).filter(e => e.source !== "scaffold");
    let filtered = entries;
    if (filterConf === "notyet") filtered = entries.filter(e => !e.confidence || e.confidence === 0);
    else if (filterConf === "attempted") filtered = entries.filter(e => e.confidence === 1);
    if (filterConf !== "all") return filtered;
    // Spaced repetition weighting: ○ 4x, ◑ 2x, ● 1x
    const weighted = [];
    filtered.forEach(e => {
      const w = e.confidence === 2 ? 1 : e.confidence === 1 ? 2 : 4;
      for (let i=0; i<w; i++) weighted.push(e);
    });
    // Shuffle while keeping some ○ questions early
    return weighted.sort(() => Math.random()-0.5);
  }, [tid, data, filterConf]);

  function start(newTid) { setTid(newTid); setIdx(0); setFlipped(false); setDone(false); }
  function next() {
    if (idx >= deck.length - 1) { setDone(true); return; }
    setIdx(i => i + 1); setFlipped(false);
  }
  function prev() { setIdx(i => Math.max(0, i - 1)); setFlipped(false); }
  function markConf(val) {
    const e = deck[idx];
    if (e && quickUpdate) quickUpdate(tid, e.id, { confidence: val });
    next();
  }

  async function selfMark({ text, imgB64, imgType }) {
    const e = deck[idx]; if (!e) return;
    const topic2 = TOPICS.find(t => t.id === tid);
    const question = e.summary || "";
    const modelAns = e.markScheme || "Award marks for accurate knowledge and clear explanation.";
    const prompt = buildSelfMarkPrompt(question, modelAns, text);
    setSmLoading(true);
    try {
      const raw = await callAISelfMark({ provider, apiKey, endpoint, prompt, imgB64, imgType });
      const result = JSON.parse(raw.replace(/```json|```/g,"").trim());
      setSmResult(result);
      setFlipped(true);
      if (quickUpdate && result.confidence !== undefined) {
        quickUpdate(tid, e.id, { confidence: result.confidence });
      }
    } catch(err) {
      setSmResult({ summary: "Marking failed: " + err.message, strengths: [], gaps: [], nextSteps: [], confidence: 1 });
      setFlipped(true);
    } finally { setSmLoading(false); }
  }

  const card = deck[idx];

  return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-3">
      {/* Mode tabs */}
      <div className="flex rounded-xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
        {[["papers","📋  Past papers","Questions from real exam papers"],["knowledge","🧠  Knowledge test","AI-generated spec questions"]].map(([m,label,sub])=>(
          <button key={m} onClick={()=>{setMode(m);setTid(null);setIdx(0);setFlipped(false);setDone(false);}}
            className="flex-1 py-2.5 px-3 text-left transition-colors"
            style={{ background: mode===m ? (m==="knowledge"?"#7C3AED":c.oxblood) : "transparent",
              borderRight: m==="papers" ? `1px solid ${c.line}` : "none" }}>
            <p className="text-xs font-bold" style={{ color: mode===m?"#fff":c.inkSoft }}>{label}</p>
            <p className="text-[10px]" style={{ color: mode===m?"rgba(255,255,255,0.7)":c.mute }}>{sub}</p>
          </button>
        ))}
      </div>

      {/* Knowledge test mode */}
      {mode === "knowledge" && <KnowledgeTestPanel board={board} level={level} subject={subject} data={data} />}

      {/* Past paper mode */}
      {mode === "papers" && <>
      <SectionTitle n="01" title="Past Paper Flashcards" note="Flip each card, mark how confident you feel. Confidence rings update on the topic tabs." />

      {/* Topic selector */}
      {!tid && (
        <div className="rounded-2xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
          <div className="px-4 py-2.5" style={{ background: c.lineSoft, borderBottom:`1px solid ${c.line}` }}>
            <span className="text-[10px] font-mono font-bold tracking-widest" style={{ color: c.mute }}>SELECT TOPIC</span>
          </div>
          <div className="p-3 flex flex-wrap gap-2">
            {topics.map(t => {
              const entries = (data[t.id]||[]).filter(e=>e.source!=="scaffold");
              if (!entries.length) return null;
              const pct = topicConfPct(data[t.id]);
              const Icon = t.icon;
              return (
                <button key={t.id} onClick={() => start(t.id)}
                  className="flex items-center gap-2 rounded-xl px-3 py-2 text-sm font-medium text-left"
                  style={{ background: c.surface, border:`1px solid ${c.line}` }}>
                  <Icon size={14} style={{color:c.mute}} />
                  <span style={{color:c.ink}}>{t.short}</span>
                  <span className="text-[11px] font-mono" style={{color:c.mute}}>{entries.length}q</span>
                  {pct >= 0 && <ConfRing pct={pct} size={16} />}
                </button>
              );
            })}
          </div>
        </div>
      )}

      {/* Filter + back when topic selected */}
      {tid && (
        <div className="flex items-center gap-2 flex-wrap">
          <button onClick={() => setTid(null)} className="text-xs font-semibold rounded-lg px-3 py-1.5"
            style={{ color: c.mute, border:`1px solid ${c.line}` }}>← Back</button>
          <span className="text-sm font-semibold" style={{ color: c.ink }}>{topic?.short}</span>
          <div className="flex gap-1 ml-auto">
            {[["all","All"],["notyet","Not attempted"],["attempted","Attempted"]].map(([v,l]) => (
              <button key={v} onClick={() => { setFilterConf(v); setIdx(0); setFlipped(false); setDone(false); }}
                className="text-[11px] font-semibold rounded-lg px-2.5 py-1"
                style={{ background: filterConf===v ? c.oxblood : "transparent", color: filterConf===v ? "#fff" : c.mute, border:`1px solid ${filterConf===v ? c.oxblood : c.line}` }}>
                {l}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Deck empty */}
      {tid && !deck.length && (
        <div className="rounded-2xl p-8 text-center" style={{ background: c.tealSoft, border:`1px solid ${c.teal}25` }}>
          <p className="text-2xl mb-2">🎉</p>
          <p className="font-bold" style={{ color: c.teal }}>No questions match this filter</p>
          <p className="text-sm mt-1" style={{ color: c.mute }}>Try switching to "All" or choose another topic.</p>
        </div>
      )}

      {/* Done */}
      {tid && done && (
        <div className="rounded-2xl p-8 text-center space-y-3" style={{ background: c.tealSoft, border:`1px solid ${c.teal}25` }}>
          <p className="text-3xl">✅</p>
          <p className="font-bold text-lg" style={{ color: c.teal }}>Deck complete!</p>
          <p className="text-sm" style={{ color: c.mute }}>{deck.length} question{deck.length!==1?"s":""} reviewed.</p>
          <button onClick={() => { setIdx(0); setFlipped(false); setDone(false); }}
            className="rounded-xl px-4 py-2 text-sm font-semibold text-white"
            style={{ background: c.oxblood }}>Restart deck</button>
        </div>
      )}

      {/* Card */}
      {tid && card && !done && (
        <div className="space-y-3">
          {/* Progress */}
          <div className="flex items-center gap-2">
            <div className="flex-1 rounded-full h-1.5" style={{ background: c.line }}>
              <div className="rounded-full h-1.5 transition-all" style={{ width:`${((idx+1)/deck.length)*100}%`, background: c.oxblood }} />
            </div>
            <span className="text-[11px] font-mono" style={{ color: c.mute }}>{idx+1}/{deck.length}</span>
          </div>

          {/* Card */}
          <div onClick={() => setFlipped(f => !f)} style={{ cursor:"pointer" }}>
            {/* Front */}
            <div className="rounded-2xl p-5 space-y-3" style={{ background: c.surface, border:`2px solid ${c.line}`, minHeight: 180 }}>
              <div className="flex items-center justify-between">
                <span className="font-mono text-[11px] font-bold" style={{ color: c.oxblood }}>Q{card.qNumber} · {card.marks}m{card.spag?"+SPaG":""}</span>
                <span className="text-[11px]" style={{ color: c.mute }}>{flipped ? "▲ click to hide" : "▼ tap to reveal"}</span>
              </div>
              <p className="text-sm font-medium leading-relaxed" style={{ color: c.ink }}>{card.summary}</p>

              {/* Flip: mark scheme */}
              {flipped && (
                <div className="pt-2 mt-2 space-y-2" style={{ borderTop:`1px solid ${c.line}` }}>
                  <p className="text-[10px] font-mono font-bold tracking-widest" style={{ color: c.mute }}>MARK SCHEME</p>
                  {card.markScheme && <p className="text-xs leading-relaxed" style={{ color: c.inkSoft }}>{card.markScheme}</p>}
                  {/* AO breakdown */}
                  {(() => {
                    const topic2 = TOPICS.find(t=>t.id===tid);
                    if (!topic2) return null;
                    const bd = getAOBreakdown(topic2, card);
                    return (
                      <div className="flex flex-wrap gap-1.5 mt-2">
                        {Object.entries(bd).map(([k,v]) => (
                          <span key={k} className="text-[10px] font-mono font-semibold rounded-full px-2 py-0.5"
                            style={{ background: aoBg(k), color: aoColour(k) }}>
                            {aoLabel(k)} {v}m
                          </span>
                        ))}
                      </div>
                    );
                  })()}
                </div>
              )}
            </div>
          </div>

          {/* Navigation + self-marking */}
          {flipped ? (
            smResult
              ? <SelfMarkFeedback result={smResult} onNext={next}
                  onOverride={v => { if (quickUpdate) quickUpdate(tid, deck[idx]?.id, {confidence:v}); setSmResult(r=>({...r,confidence:v})); }} />
              : <div className="space-y-2">
                  <p className="text-[11px] text-center" style={{color:c.mute}}>How confident do you feel?</p>
                  <div className="grid grid-cols-3 gap-2">
                    {CONF.map((cf,v)=>(
                      <button key={v} onClick={()=>markConf(v)}
                        className="rounded-xl py-2.5 text-xs font-bold flex flex-col items-center gap-1"
                        style={{background:cf.bg,color:cf.color,border:`1px solid ${cf.color}30`}}>
                        <span className="text-lg">{cf.icon}</span><span>{cf.label}</span>
                      </button>
                    ))}
                  </div>
                </div>
          ) : (
            <div className="space-y-2">
              <SelfMarkInput onSubmit={selfMark} onSkip={()=>setFlipped(true)} loading={smLoading} />
              <div className="flex gap-2">
                <button onClick={prev} disabled={idx===0}
                  className="rounded-xl px-3 py-2 text-sm font-semibold disabled:opacity-30"
                  style={{background:c.lineSoft,color:c.inkSoft,border:`1px solid ${c.line}`}}>← Prev</button>
                <button onClick={next}
                  className="rounded-xl px-3 py-2 text-sm font-semibold"
                  style={{background:c.lineSoft,color:c.inkSoft,border:`1px solid ${c.line}`}}>Skip card →</button>
              </div>
            </div>
          )}
        </div>
      )}
      </>
    }
    </div>
  );
}


function MarkerPanel({ board, level, subject, data, save }) {
  const topics = TOPICS.filter(t => t.board === board && t.level === level && t.subject === subject);
  const [tid, setTid] = React.useState(topics[0]?.id || "");
  const [entryId, setEntryId] = React.useState(null);
  const providerState = useAIProvider();

  const topic = TOPICS.find(t => t.id === tid) || null;
  const entries = (data[tid] || []).filter(e => e.source !== "scaffold");
  const entry = entries.find(e => e.id === entryId) || null;

  // Reset entry when topic changes
  React.useEffect(() => { setEntryId(null); }, [tid]);

  // Auto-select first entry when topic loaded
  React.useEffect(() => {
    if (entries.length && !entry) setEntryId(entries[0].id);
  }, [tid, entries.length]);

  return (
    <div className="max-w-xl mx-auto px-3 sm:px-0 py-4 space-y-3">

      {/* ── AI Provider selector — top of panel ── */}
      <AIProviderWidget {...providerState} />

      <SectionTitle n="01" title="Question Marker" note="Upload a photo of your handwritten answer for AI-powered conservative Edexcel marking." />

      {subject === "Religious Studies" && (
        <div className="max-w-xl mx-auto px-4 py-16 flex flex-col items-center text-center gap-5">
          <div className="grid place-items-center rounded-2xl"
            style={{ width:72, height:72, background:"linear-gradient(135deg,#7C3AED,#4F46E5)", boxShadow:"0 4px 20px rgba(79,70,229,0.25)" }}>
            <span style={{fontSize:34}}>✝️</span>
          </div>
          <div>
            <h2 className="text-lg font-bold mb-2" style={{color:c.ink}}>Religious Studies</h2>
            <p className="text-sm leading-relaxed max-w-sm" style={{color:c.mute}}>
              Past-paper question tracking for GCSE &amp; A Level Religious Studies is coming soon.
              AQA, Edexcel and OCR specifications will be covered.
            </p>
          </div>
          <span className="inline-flex items-center gap-2 rounded-full px-4 py-2 text-xs font-bold"
            style={{background:c.oxbloodSoft, color:c.oxblood, border:`1px solid ${c.oxblood}25`}}>
            <span style={{width:7,height:7,borderRadius:"50%",background:c.oxblood,display:"inline-block"}} />
            Coming soon
          </span>
        </div>
      )}
      {subject !== "History" && (
        <div className="rounded-lg p-4 text-sm" style={{ background:"#FFF7ED", border:"1px solid #FCD34D", color:"#92400E" }}>
          The Question Marker supports History (AQA, Edexcel, OCR). Switch to History to use this tool.
        </div>
      )}

      {subject === "History" && (<>
        {/* Step 1: Pick topic */}
        <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border:`1px solid ${c.line}` }}>
          <div className="px-4 py-3 flex items-center gap-2" style={{ borderBottom:`1px solid ${c.lineSoft}`, background:"#F8FAFC" }}>
            <span className="text-[11px] font-mono font-semibold tracking-widest" style={{ color: c.mute }}>STEP 1 — SELECT TOPIC</span>
          </div>
          <div className="p-3">
            <div className="flex flex-wrap gap-1.5">
              {topics.map(t => {
                const n = (data[t.id]||[]).filter(e=>e.source!=="scaffold").length;
                const on = t.id === tid;
                const Icon = t.icon;
                return (
                  <button key={t.id} onClick={() => setTid(t.id)}
                    className="inline-flex items-center gap-1.5 rounded-lg px-2.5 py-1.5 text-xs font-medium"
                    style={{ background: on ? c.oxblood : n > 0 ? "#F8FAFC" : c.lineSoft,
                      color: on ? "#fff" : n > 0 ? c.ink : c.mute,
                      border:`1px solid ${on ? c.oxblood : n > 0 ? c.line : c.lineSoft}` }}>
                    <Icon size={12} />{t.short}
                    {n > 0 && <span className="font-mono text-[10px]" style={{ opacity:0.7 }}>({n})</span>}
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        {/* Step 2: Pick question */}
        {topic && (
          <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border:`1px solid ${c.line}` }}>
            <div className="px-4 py-3" style={{ borderBottom:`1px solid ${c.lineSoft}`, background:"#F8FAFC" }}>
              <span className="text-[11px] font-mono font-semibold tracking-widest" style={{ color: c.mute }}>STEP 2 — SELECT QUESTION</span>
            </div>
            {entries.length === 0 ? (
              <p className="px-4 py-3 text-sm" style={{ color: c.mute }}>
                No confirmed questions for this topic yet. Load a year first, or use Auto-fill to retrieve questions.
              </p>
            ) : (
              <div className="divide-y" style={{ borderColor: c.lineSoft }}>
                {entries.slice(0, 30).map(e => (
                  <button key={e.id} onClick={() => setEntryId(e.id)}
                    className="w-full text-left px-4 py-2.5 flex items-start gap-3 text-sm"
                    style={{ background: e.id === entryId ? c.oxbloodSoft : "transparent" }}>
                    <span className="font-mono text-[11px] shrink-0 mt-0.5" style={{ color: c.oxblood, width:34 }}>Q{e.qNumber}</span>
                    <span className="flex-1 leading-snug" style={{ color: c.ink }}>{e.summary?.slice(0, 90)}{e.summary?.length > 90 ? "…" : ""}</span>
                    <span className="font-mono text-[11px] shrink-0 mt-0.5" style={{ color: c.mute }}>{e.marks}m{e.spag?"+SPaG":""}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Step 3: Mark it */}
        {topic && entry && (
          <div className="rounded-lg overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
            <div className="px-4 py-3" style={{ borderBottom:`1px solid ${c.lineSoft}`, background:"#F8FAFC" }}>
              <span className="text-[11px] font-mono font-semibold tracking-widest" style={{ color: c.mute }}>STEP 3 — UPLOAD &amp; MARK</span>
            </div>
            <div className="p-3">
              <MarkerInline topic={topic} entry={entry} providerState={providerState} data={data} save={save} />
            </div>
          </div>
        )}
      </>)}
    </div>
  );
}

/* Inline marker (used inside MarkerPanel — not a modal) */
function MarkerInline({ topic, entry, providerState, data, save }) {
  const [imgSrc, setImgSrc] = React.useState(null);
  const [imgB64, setImgB64] = React.useState(null);
  const [imgType, setImgType] = React.useState("image/jpeg");
  const [marking, setMarking] = React.useState(false);
  const [result, setResult] = React.useState(null);
  const [errMsg, setErrMsg] = React.useState(null);
  const fileRef = React.useRef();
  // Use shared providerState from parent if available, else own instance
  const ownProvider = useAIProvider();
  const { provider, apiKey, endpoint } = providerState || ownProvider;

  // Reset when entry changes
  React.useEffect(() => { setResult(null); setImgSrc(null); setImgB64(null); setErrMsg(null); }, [entry.id]);

  const breakdown = getAOBreakdown(topic, entry);

  function handleFile(e) {
    const file = e.target.files?.[0]; if (!file) return;
    const type = file.type || "image/jpeg";
    setImgType(type); setResult(null); setErrMsg(null);
    const reader = new FileReader();
    reader.onload = (ev) => { const d = ev.target.result; setImgSrc(d); setImgB64(d.split(",")[1]); };
    reader.readAsDataURL(file);
  }

  async function mark() {
    if (!imgB64) return;
    setMarking(true); setResult(null); setErrMsg(null);
    const prompt = buildMarkingPrompt(topic, entry, breakdown);
    try {
      const raw = await callAI({ provider, apiKey, endpoint, prompt, imgB64, imgType });
      setResult(JSON.parse(raw));
    } catch(e) { setErrMsg("Marking failed: " + e.message); }
    finally { setMarking(false); }
  }

  const scored = result ? Object.entries(result)
    .filter(([k]) => ["ao1","ao2","ao3","ao4","spag"].includes(k) && result[k]?.max != null) : [];

  return (
    <div className="space-y-3">
      {/* Question info */}
      <div className="rounded-lg p-3 text-sm" style={{ background:"#F8FAFC", border:`1px solid ${c.line}` }}>
        <p className="font-mono text-[10px] mb-1" style={{ color: c.oxblood }}>Q{entry.qNumber} · {entry.marks}m{entry.spag?" + 4 SPaG":""}</p>
        <p style={{ color: c.ink }}>{entry.summary}</p>
      </div>
      {/* AO pills */}
      <div className="flex flex-wrap gap-1.5">
        {Object.entries(breakdown).map(([k,v]) => (
          <span key={k} className="text-[11px] font-mono font-semibold rounded-full px-3 py-1"
            style={{ background: aoBg(k), color: aoColour(k), border:`1px solid ${aoColour(k)}30` }}>
            {aoLabel(k)}: {v}m
          </span>
        ))}
      </div>
      {/* Question stem */}
      {(() => { const s = getQuestionStem(topic, entry); return s ? (
        <div className="rounded-xl p-3 space-y-1.5" style={{ background: c.elevated, border:`1px solid ${c.line}` }}>
          <p className="text-[10px] font-mono font-bold tracking-widest" style={{ color: c.oxblood }}>{s.label.toUpperCase()} — QUESTION STEM</p>
          <p className="text-xs leading-relaxed font-medium" style={{ color: c.ink }}>{s.stem}</p>
          <p className="text-[11px] leading-relaxed" style={{ color: c.mute }}>💡 {s.tip}</p>
        </div>
      ) : null; })()}
      {/* Upload */}
      <input ref={fileRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFile} />
      {imgSrc ? (
        <div className="relative">
          <img src={imgSrc} alt="Answer" className="w-full rounded-lg object-contain max-h-72"
            style={{ border:`1px solid ${c.line}` }} />
          <button onClick={() => fileRef.current?.click()}
            className="absolute bottom-2 right-2 text-xs font-semibold rounded-lg px-3 py-1.5"
            style={{ background: c.ink, color:"#fff" }}>Retake</button>
        </div>
      ) : (
        <button onClick={() => fileRef.current?.click()}
          className="w-full rounded-xl flex flex-col items-center justify-center gap-2 py-8"
          style={{ border:`2px dashed ${c.line}`, color: c.inkSoft, background:"#FAFAFA" }}>
          <span style={{ fontSize:32 }}>📷</span>
          <span className="text-sm font-semibold">Take photo or upload answer</span>
          <span className="text-xs">Photograph handwritten response clearly</span>
        </button>
      )}
      {/* Mark button */}
      {imgSrc && !result && (
        marking
          ? <div className="space-y-2">
              <div className="flex items-center justify-center gap-2 py-2">
                <Loader2 size={14} className="animate-spin" style={{color:c.oxblood}} />
                <span className="text-xs font-semibold" style={{color:c.oxblood}}>Marking conservatively…</span>
              </div>
              <ShimmerCard lines={2} />
            </div>
          : <button onClick={mark}
              className="w-full rounded-2xl py-3.5 font-bold text-sm flex items-center justify-center gap-2"
              style={{ background: c.oxblood, color:"#fff" }}>
              <ClipboardCheck size={16} />Mark this answer
            </button>
      )}
      {errMsg && <div className="rounded-lg p-3 text-sm" style={{ background:"#FEF2F2", border:"1px solid #FCA5A5", color:"#991B1B" }}>{errMsg}</div>}
      {/* Results */}
      {result && (<>
        <div className="rounded-xl p-4 flex items-center gap-4" style={{ background: c.ink, color:"#fff" }}>
          <AnimatedScore target={result.total} max={result.maxTotal} />
          <div className="flex-1">
            <div className="rounded-full h-2.5 mb-2" style={{ background:"rgba(255,255,255,0.2)" }}>
              <div className="rounded-full h-2.5" style={{ width:`${Math.round((result.total/result.maxTotal)*100)}%`, background:"#34D399" }} />
            </div>
            <p className="text-xs opacity-80">{result.examinerNote}</p>
            <p className="text-[10px] mt-1.5 opacity-50">{provider.logo} Marked by {provider.name} ({provider.vendor})</p>
          </div>
        </div>
        <div className="space-y-2">
          <p className="text-[10px] font-mono font-semibold" style={{ color: c.mute }}>AO BREAKDOWN</p>
          {scored.map(([k, ao]) => (
            <div key={k} className="rounded-lg p-3" style={{ background: aoBg(k), border:`1px solid ${aoColour(k)}20` }}>
              <div className="flex items-center justify-between mb-1">
                <span className="text-[11px] font-mono font-semibold" style={{ color: aoColour(k) }}>{aoLabel(k)}</span>
                <span className="font-bold text-sm" style={{ color: aoColour(k) }}>{ao.marks} / {ao.max}</span>
              </div>
              <div className="rounded-full h-1.5 mb-1.5" style={{ background:`${aoColour(k)}20` }}>
                <div className="rounded-full h-1.5" style={{ width:`${Math.round((ao.marks/ao.max)*100)}%`, background: aoColour(k) }} />
              </div>
              <p className="text-xs" style={{ color: c.inkSoft }}>{ao.comment}</p>
            </div>
          ))}
        </div>
        {result.strengths?.length > 0 && (
          <div className="rounded-lg p-3" style={{ background:"#ECFDF5", border:"1px solid #6EE7B7" }}>
            <p className="text-[11px] font-mono font-semibold mb-2" style={{ color:"#065F46" }}>✓ STRENGTHS</p>
            <ul className="space-y-1">{result.strengths.map((s,i) => <li key={i} className="flex gap-2 text-sm" style={{ color:"#065F46" }}><span>•</span><span>{s}</span></li>)}</ul>
          </div>
        )}
        {result.improve?.length > 0 && (
          <div className="rounded-lg p-3" style={{ background:"#FFF7ED", border:"1px solid #FCD34D" }}>
            <p className="text-[11px] font-mono font-semibold mb-2" style={{ color:"#92400E" }}>⟳ AREAS TO DEVELOP</p>
            <ul className="space-y-1">{result.improve.map((s,i) => <li key={i} className="flex gap-2 text-sm" style={{ color:"#92400E" }}><span>{i+1}.</span><span>{s}</span></li>)}</ul>
          </div>
        )}
        <div className="flex items-center gap-2 flex-wrap pt-1">
          <span className="text-[10px] font-mono" style={{color:c.mute}}>Difficulty for you:</span>
          {["Easy","Medium","Hard"].map(d => {
            const saved = data?.__difficulty?.[entry?.id]?.rating;
            const col = d==="Easy"?"#059669":d==="Medium"?"#D97706":"#DC2626";
            return (
              <button key={d} onClick={() => {
                if (!save||!entry) return;
                const pct = result?.total&&result?.maxTotal?Math.round(result.total/result.maxTotal*100):0;
                save({...data,__difficulty:{...(data.__difficulty||{}),[entry.id]:{rating:d,pct,ts:Date.now()}}});
              }}
                className="text-[10px] font-bold rounded-full px-2.5 py-1"
                style={{background:(saved===d)?col+"22":c.lineSoft,color:(saved===d)?col:c.mute,border:"1px solid "+((saved===d)?col:c.lineSoft)}}>
                {d==="Easy"?"🟢":d==="Medium"?"🟡":"🔴"} {d}
              </button>
            );
          })}
        </div>
        <button onClick={() => { setResult(null); setImgSrc(null); setImgB64(null); }}
          className="w-full rounded-xl py-2.5 text-sm font-semibold"
          style={{ border:`1px solid ${c.line}`, color: c.inkSoft, background:"#FAFAFA" }}>
          📷 Mark another answer
        </button>
      </>)}
      <p className="text-[10px] text-center" style={{ color: c.mute }}>
        AI marking is indicative only and intentionally conservative. Verify against the official Edexcel mark scheme.
      </p>
    </div>
  );
}


/* ------------------------------ paper builder ------------------------------ */
function paperHtml(topic, entries, meta) {
  const total = entries.reduce((s, e) => s + (Number(e.marks) || 0), 0);
  const board = topic.board === "Edexcel" ? "Pearson Edexcel" : topic.board;
  const qual = `${topic.level === "A Level" ? "A-Level" : "GCSE (9–1)"} ${topic.subject || "History"} (${(topic.code || "").split("/")[0]})`;
  const qs = entries.map((e, idx) => {
    const lines = Math.min(10, Math.max(2, Math.round((Number(e.marks) || 4) / 2)));
    const ruled = Array.from({ length: lines }).map(() => '<div class="rule"></div>').join("");
    const t = e.topic ? ` <em>(${escapeHtml(e.topic)})</em>` : "";
    return `<div class="q"><div class="qhead"><span class="qn">${idx + 1}</span><span class="qt">${escapeHtml(e.summary)}${t}</span><span class="qm">(${e.marks} marks)</span></div>
      <div class="orig">From ${escapeHtml(topic.short)} ${e.series}, Q${escapeHtml(e.qNumber)}</div>${ruled}</div>`;
  }).join("");
  return `<!doctype html><html><head><meta charset="utf-8"><title>${escapeHtml(meta.title)}</title><style>
  @page{size:A4;margin:18mm 16mm;} *{box-sizing:border-box;} body{font-family:'Times New Roman',Times,serif;color:#111;margin:0;}
  .topbar{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #111;padding-bottom:8px;}
  .board{font-size:14px;font-weight:bold;letter-spacing:.5px;} .qualq{font-size:12px;}
  .markbox{border:1px solid #111;width:120px;height:46px;font-size:10px;padding:4px;text-align:center;}
  .title{margin:30px 0 4px;font-size:22px;font-weight:bold;text-align:center;} .sub{text-align:center;font-size:13px;margin-bottom:20px;}
  h3{font-size:11px;text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid #111;padding-bottom:2px;margin:16px 0 6px;}
  .meta{font-size:13px;line-height:1.5;} .disc{margin-top:10px;font-size:10px;color:#666;}
  .namebox{margin-top:20px;border:1px solid #111;padding:12px;font-size:12px;display:flex;gap:24px;} .namebox div{flex:1;border-bottom:1px solid #888;padding-top:20px;}
  .q{margin:16px 0;page-break-inside:avoid;} .qhead{display:flex;gap:8px;align-items:baseline;}
  .qn{font-weight:bold;min-width:22px;} .qt{flex:1;font-size:14px;} .qm{font-weight:bold;font-size:13px;white-space:nowrap;}
  .orig{font-size:10px;color:#777;margin:2px 0 8px 30px;font-style:italic;} .rule{border-bottom:1px solid #c4c4c4;height:22px;margin-left:30px;}
  .footer{margin-top:14px;text-align:center;font-size:11px;color:#444;} .pb{page-break-before:always;}
  @media screen{body{background:#52555a;padding:18px;} .sheet{background:#fff;max-width:780px;margin:0 auto;padding:34px 40px;box-shadow:0 6px 24px rgba(0,0,0,.35);}}
  </style></head><body><div class="sheet">
  <div class="topbar"><div><div class="board">${board}</div><div class="qualq">${qual}</div></div><div class="markbox">For examiner’s use<br><br>Total ____ / ${total}</div></div>
  <div class="title">${escapeHtml(meta.title)}</div><div class="sub">${escapeHtml(topic.name)} · ${escapeHtml(topic.paper)}</div>
  <div class="meta"><h3>Time allowed</h3><div>${escapeHtml(meta.duration || topic.duration)}</div>
  <h3>Instructions</h3><div>Answer the questions in the spaces provided. Write in continuous prose where the question requires it.</div>
  <h3>Information</h3><div>The total mark for this practice paper is ${total}. The marks for each question are shown in brackets.</div>
  <div class="disc">Practice paper compiled from past-question topics for revision — this is not an official exam-board paper.</div>
  <div class="namebox"><div>Name</div><div>Date</div></div></div>
  <div class="pb"></div>${qs}<div class="footer">END OF PRACTICE PAPER</div></div></body></html>`;
}
function printPaper(html) {
  // Try iframe approach first; fall back to window.open if iframe is blocked
  try {
    const f = document.createElement("iframe");
    f.style.cssText = "position:fixed;right:0;bottom:0;width:0;height:0;border:0;";
    document.body.appendChild(f);
    const cw = f.contentWindow;
    if (!cw) throw new Error("iframe contentWindow unavailable");
    const d = cw.document; d.open(); d.write(html); d.close();
    setTimeout(() => {
      try { cw.focus(); cw.print(); }
      catch (e) {
        // iframe print blocked — open in new tab instead
        document.body.removeChild(f);
        const w = window.open("", "_blank");
        if (w) { w.document.write(html); w.document.close(); w.focus(); w.print(); }
        else { downloadHtml(html, "practice-paper.html"); }
      }
      setTimeout(() => { try { document.body.removeChild(f); } catch {} }, 1500);
    }, 350);
  } catch (e) {
    // iframe creation failed — open in new tab
    try {
      const w = window.open("", "_blank");
      if (w) { w.document.write(html); w.document.close(); w.focus(); w.print(); }
      else { downloadHtml(html, "practice-paper.html"); }
    } catch (e2) {
      downloadHtml(html, "practice-paper.html");
    }
  }
}
function downloadHtml(html, name) {
  const blob = new Blob([html], { type: "text/html" });
  const url = URL.createObjectURL(blob); const a = document.createElement("a");
  a.href = url; a.download = name; a.click(); URL.revokeObjectURL(url);
}

function PaperPanel({ board, level, subject, data }) {
  const levelTopics = TOPICS.filter((t) => t.board === board && t.level === level && t.subject === subject);
  const [tid, setTid] = useState(levelTopics[0] ? levelTopics[0].id : "");
  const topic = TOPICS.find((t) => t.id === tid && t.board === board) || levelTopics[0] || null;
  const [sel, setSel] = useState(() => new Set());
  const [title, setTitle] = useState(topic ? `${topic.short} ${subject === 'Geography' ? 'geography' : 'history'} practice paper` : "Practice paper");
  const [duration, setDuration] = useState(topic ? topic.duration : "");
  useEffect(() => { if (!TOPICS.find((t) => t.id === tid && t.board === board && t.level === level && t.subject === subject)) setTid(levelTopics[0] ? levelTopics[0].id : ""); }, [board, level, subject]); // eslint-disable-line
  useEffect(() => { const t = TOPICS.find((x) => x.id === tid); setSel(new Set()); setTitle(t ? `${t.short} practice paper` : "Practice paper"); setDuration(t ? t.duration : ""); }, [tid]); // eslint-disable-line
  const entries = topic ? (data[tid] || []).slice().sort((a, b) => (b.series - a.series) || a.qNumber.localeCompare(b.qNumber, undefined, { numeric: true })) : [];

  const toggle = (id) => { const n = new Set(sel); n.has(id) ? n.delete(id) : n.add(id); setSel(n); };
  const chosen = entries.filter((e) => sel.has(e.id));
  const total = chosen.reduce((s, e) => s + (Number(e.marks) || 0), 0);
  const byYear = useMemo(() => { const m = {}; entries.forEach((e) => { (m[e.series] = m[e.series] || []).push(e); }); return m; }, [entries]);

  const build = (mode) => {
    if (!chosen.length || !topic) return;
    const html = paperHtml(topic, chosen, { title, duration });
    if (mode === "print") printPaper(html); else downloadHtml(html, `${tid}-practice-paper.html`);
  };

  if (!topic) return <BoardEmpty board={board} level={level} />;

  return (
    <div>
      <section className="rounded-lg p-5 sm:p-6 flex gap-3" style={{ background: c.surface, border: `1px solid ${c.line}`, borderLeft: `4px solid ${c.brass}` }}>
        <FileText size={22} style={{ color: c.brass, flexShrink: 0, marginTop: 2 }} />
        <div><h2 className="font-serif text-xl">Paper builder</h2>
          <p className="text-sm mt-1" style={{ color: c.inkSoft }}>Pick questions and generate a print-ready paper in an exam-board layout. Use your browser’s <strong>Save as PDF</strong> in the print dialog. Built from your tracked questions — a revision practice paper, not an official paper.</p></div>
      </section>

      <div className="flex flex-wrap gap-2 mt-5">
        {levelTopics.map((t) => { const on = t.id === tid, TIcon = t.icon; return (
          <button key={t.id} onClick={() => setTid(t.id)} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-medium"
            style={{ background: on ? c.ink : c.surface, color: on ? "#fff" : c.inkSoft, border: `1px solid ${on ? c.ink : c.line}` }}><TIcon size={14} /> {t.short}</button>); })}
      </div>

      <div className="grid sm:grid-cols-2 gap-3 mt-4">
        <Field label="Paper title"><input value={title} onChange={(e) => setTitle(e.target.value)} className="w-full rounded px-3 py-2 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink, background: c.surface }} /></Field>
        <Field label="Time allowed"><input value={duration} onChange={(e) => setDuration(e.target.value)} className="w-full rounded px-3 py-2 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink, background: c.surface }} /></Field>
      </div>

      <div className="flex items-center justify-between mt-5 mb-2">
        <SectionTitleInline title="Select questions" />
        <span className="text-xs" style={{ color: c.mute }}>{chosen.length} selected · {total} marks</span>
      </div>
      <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        {Object.keys(byYear).sort((a, b) => b - a).map((yr) => (
          <div key={yr}>
            <div className="px-4 py-2 font-mono text-xs" style={{ background: "#F4F5F7", color: c.inkSoft, borderTop: `1px solid ${c.lineSoft}` }}>{yr}</div>
            {byYear[yr].map((e) => (
              <label key={e.id} className="flex items-center gap-3 px-4 py-2.5 cursor-pointer" style={{ borderTop: `1px solid ${c.lineSoft}` }}>
                <input type="checkbox" checked={sel.has(e.id)} onChange={() => toggle(e.id)} />
                <span className="font-mono text-xs shrink-0" style={{ color: c.inkSoft, width: 34 }}>{e.qNumber}</span>
                <span className="text-sm flex-1 min-w-0 truncate" style={{ color: e.source === "scaffold" ? c.mute : c.ink }}>{e.summary}{e.topic ? ` — ${e.topic}` : ""}</span>
                <MarkBadge m={e.marks} />
              </label>
            ))}
          </div>
        ))}
      </div>

      <div className="flex flex-wrap gap-2 mt-4">
        <button onClick={() => build("print")} disabled={!chosen.length} className="inline-flex items-center gap-1.5 rounded px-4 py-2 text-sm font-semibold text-white disabled:opacity-40" style={{ background: c.brass }}><Printer size={16} /> Save as PDF (print)</button>
        <button onClick={() => build("download")} disabled={!chosen.length} className="inline-flex items-center gap-1.5 rounded px-4 py-2 text-sm font-medium disabled:opacity-40" style={{ background: c.surface, border: `1px solid ${c.line}`, color: c.inkSoft }}><Download size={16} /> Download (.html)</button>
      </div>
      <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: c.mute }}><Info size={12} /> If the print dialog doesn’t open (some embedded viewers block it), use Download and open the file, then print to PDF.</p>
    </div>
  );
}

/* ----------------------------- predictor panel ----------------------------- */
function PredictPanel({ board, level, predict, onSet, predsheet, onField, onBatch }) {
  const levelTopics = TOPICS.filter((t) => t.board === board && t.level === level);
  const [tid, setTid] = useState(levelTopics[0] ? levelTopics[0].id : "");
  useEffect(() => { if (!TOPICS.find((t) => t.id === tid && t.board === board && t.level === level)) setTid(levelTopics[0] ? levelTopics[0].id : ""); }, [board, level]); // eslint-disable-line
  const topic = TOPICS.find((t) => t.id === tid && t.board === board) || levelTopics[0] || null;
  const tlevel = topic ? topic.level : level;
  const areas = topic ? (SPEC_AREAS[topic.id] || []) : [];
  const flags = topic ? (predict[topic.id] || {}) : {};
  const sheet = topic ? (predsheet[topic.id] || {}) : {};
  const getText = (i) => (topic ? (sheet[i] && sheet[i].text !== undefined ? sheet[i].text : (PREDICTIONS[topic.id] || [])[i]) : "");
  const getOutcome = (i) => (sheet[i] && sheet[i].outcome) || "pending";
  const correctN = topic ? topic.structure.filter((_, i) => getOutcome(i) === "correct").length : 0;
  const wrongN = topic ? topic.structure.filter((_, i) => getOutcome(i) === "incorrect").length : 0;
  const meta = sheet.__meta || {};
  const pend = pendingYearFor(tlevel);
  const latestReleased = realYears(tlevel).slice(-1)[0];
  const [gradeYear, setGradeYear] = useState(pend);
  const [checking, setChecking] = useState(false);
  const [note, setNote] = useState("");
  const didAuto = useRef(false);
  const boardName = `${board} ${tlevel === "A Level" ? "A-Level" : "GCSE"}`;
  const yearReleased = (y) => realYears(tlevel).includes(y);

  async function autoCheck(y) {
    if (!topic) return;
    const target = y || gradeYear; setChecking(true); setNote("");
    try {
      const slots = topic.structure.map((r, i) => ({ i, q: r.q, type: r.s, predicted: getText(i) }));
      const prompt =
`Verify real past exam questions using web search. Find the ACTUAL questions on the ${boardName} History ${topic.paper} "${topic.name}" paper from May/June ${target} (${codeHint(topic)}).
For each slot below, identify that exact question's specific topic in 12 words or fewer, then judge the student's prediction.
Rules: use only reliable sources (official exam-board papers or reputable exam/revision sites). Never guess or invent. If a question cannot be confirmed from a real source, set "found" to false.
Slots:
${slots.map((s) => `#${s.i} Q${s.q} [${s.type}] predicted: "${s.predicted}"`).join("\n")}
Return ONLY a JSON array (no prose, no markdown). Each item:
{"i":<number>,"found":true|false,"actualTopic":"<focus or empty>","verdict":"correct"|"incorrect"|"unverifiable"}
"correct" = the prediction's theme matches the real question; "incorrect" = it clearly does not; "unverifiable" = found is false.`;
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 1500, messages: [{ role: "user", content: prompt }], tools: [{ type: "web_search_20250305", name: "web_search" }] }),
      });
      const json = await res.json();
      const text = (json.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
      const arr = extractJsonArray(text);
      const perIndex = {}; let found = 0;
      arr.forEach((item) => { if (item.i === undefined || !item.found) return; const v = item.verdict;
        perIndex[item.i] = { actual: item.actualTopic || "", outcome: v === "correct" ? "correct" : v === "incorrect" ? "incorrect" : "pending", aiAt: Date.now() }; found++; });
      onBatch(topic.id, perIndex, { checkedYear: target, at: Date.now() });
      setNote(found ? `Auto-checked ${found} question${found > 1 ? "s" : ""} against the ${target} paper. AI-retrieved — verify against the official paper.` : `No verified ${target} questions found online${yearReleased(target) ? "" : " — that paper isn’t published yet"}. Nothing changed.`);
    } catch (e) { setNote("Couldn’t complete the auto-check (network or response issue). You can still type actual topics and grade manually."); }
    finally { setChecking(false); }
  }
  useEffect(() => { if (didAuto.current) return; if (meta.autoOpen && latestReleased && meta.checkedYear !== latestReleased) { didAuto.current = true; autoCheck(latestReleased); } }, [tid]); // eslint-disable-line

  if (!topic) return <BoardEmpty board={board} level={level} />;

  return (
    <div>
      <section className="rounded-lg p-5 sm:p-6 flex gap-3" style={{ background: c.surface, border: `1px solid ${c.line}`, borderLeft: `4px solid ${c.teal}` }}>
        <Target size={22} style={{ color: c.teal, flexShrink: 0, marginTop: 2 }} />
        <div><h2 className="font-serif text-xl">Paper predictor</h2>
          <p className="text-sm mt-1" style={{ color: c.inkSoft }}>Informed revision guesswork from the <strong>fixed format</strong> and <strong>public spec</strong>. “Check now” searches the web for the released paper and grades each prediction; it can’t know an unreleased paper, and isn’t based on insider information.</p></div>
      </section>

      <div className="flex flex-wrap gap-2 mt-5">
        {levelTopics.map((t) => { const on = t.id === tid, TIcon = t.icon; return (
          <button key={t.id} onClick={() => setTid(t.id)} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-medium"
            style={{ background: on ? c.ink : c.surface, color: on ? "#fff" : c.inkSoft, border: `1px solid ${on ? c.ink : c.line}` }}><TIcon size={14} /> {t.short}</button>); })}
      </div>

      <SectionTitle n="01" title="Certain to appear" note={`${topic.paper} always uses these exact slots.`} />
      <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        <table className="w-full text-sm border-collapse"><thead><tr style={{ background: c.ink, color: "#fff" }} className="text-left"><Th>Q</Th><Th>You will be asked to…</Th><Th className="text-right pr-5">Marks</Th></tr></thead>
          <tbody>{topic.structure.map((r, i) => (<tr key={i} style={{ borderTop: `1px solid ${c.lineSoft}` }}><Td className="font-mono" style={{ color: c.inkSoft }}>{r.q}</Td><Td>{r.s}{r.spag && <SpagTag />}{r.extended && <ExtTag />}</Td><Td className="text-right pr-5"><MarkBadge m={r.m} /></Td></tr>))}</tbody>
        </table>
      </div>

      <SectionTitle n="02" title={`Prediction tracker — Summer ${pend}`} note="Predict each question’s topic, then auto-check or mark right/wrong." />
      <div className="flex items-center gap-2 mb-3">
        <span className="font-mono text-xs rounded px-2 py-1" style={{ background: c.greenSoft, color: c.green }}>{correctN} right</span>
        <span className="font-mono text-xs rounded px-2 py-1" style={{ background: c.redSoft, color: c.red }}>{wrongN} wrong</span>
        <span className="text-xs" style={{ color: c.mute }}>of {topic.structure.length} questions</span>
      </div>
      <div className="rounded-lg p-3 mb-3 flex flex-wrap items-center gap-2" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        <span className="text-xs font-medium" style={{ color: c.inkSoft }}>Auto-check against</span>
        <select value={gradeYear} onChange={(e) => setGradeYear(Number(e.target.value))} className="rounded px-2 py-1.5 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink }}>{[...realYears(topic.level), pend].map((y) => <option key={y} value={y}>{y}</option>)}</select>
        <button onClick={() => autoCheck()} disabled={checking} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-semibold text-white disabled:opacity-50" style={{ background: c.teal }}>{checking ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}{checking ? "Checking…" : "Check now"}</button>
        <button onClick={() => onBatch(topic.id, {}, { autoOpen: !meta.autoOpen })} className="inline-flex items-center gap-1.5 rounded px-3 py-1.5 text-sm font-medium" style={{ background: meta.autoOpen ? c.tealSoft : "#fff", border: `1px solid ${meta.autoOpen ? c.teal : c.line}`, color: meta.autoOpen ? c.teal : c.inkSoft }}><Sparkles size={14} /> Auto on open · {meta.autoOpen ? "on" : "off"}</button>
        {meta.at && <span className="text-xs" style={{ color: c.mute }}>Last checked {new Date(meta.at).toLocaleDateString()}</span>}
      </div>
      {note && <div className="rounded-lg p-3 mb-3 flex gap-2 text-xs" style={{ background: c.brassSoft, border: `1px solid ${c.brass}33`, color: c.ink }}><AlertTriangle size={14} style={{ color: c.brass, flexShrink: 0, marginTop: 1 }} /><span>{note}</span></div>}
      <div className="space-y-2">
        {topic.structure.map((r, i) => {
          const oc = getOutcome(i), right = oc === "correct", wrong = oc === "incorrect";
          const edge = right ? c.green : wrong ? c.red : c.line, fieldBg = right ? c.greenSoft : wrong ? c.redSoft : "#fff";
          return (
            <div key={i} className="rounded-lg p-3 sm:p-4" style={{ background: c.surface, border: `1px solid ${c.line}`, borderLeft: `4px solid ${edge}` }}>
              <div className="flex items-center gap-2 mb-2"><span className="font-mono text-sm shrink-0" style={{ color: c.inkSoft }}>{r.q}</span><MarkBadge m={r.m} /><span className="text-xs truncate" style={{ color: c.mute }}>{r.s}</span></div>
              <div className="flex flex-wrap items-center gap-2">
                <input value={getText(i)} onChange={(e) => onField(topic.id, i, { text: e.target.value })} placeholder="Your predicted topic…" className="flex-1 min-w-[180px] rounded px-3 py-2 text-sm outline-none" style={{ background: fieldBg, border: `1px solid ${edge}66`, color: c.ink }} />
                <div className="flex gap-1.5">
                  <OutcomeBtn active={right} color={c.green} bg={c.greenSoft} onClick={() => onField(topic.id, i, { outcome: right ? "pending" : "correct" })}><Check size={14} /> Right</OutcomeBtn>
                  <OutcomeBtn active={wrong} color={c.red} bg={c.redSoft} onClick={() => onField(topic.id, i, { outcome: wrong ? "pending" : "incorrect" })}><X size={14} /> Wrong</OutcomeBtn>
                </div>
              </div>
              {sheet[i] && sheet[i].actual ? <div className="mt-2 text-xs flex items-start gap-1.5 flex-wrap" style={{ color: c.inkSoft }}><span className="font-mono rounded px-1.5 py-0.5" style={{ background: c.tealSoft, color: c.teal }}>actual</span><span>{sheet[i].actual}</span>{sheet[i].aiAt ? <Badge color={c.mute} bg="#F4F5F7">AI-checked</Badge> : null}</div> : null}
            </div>
          );
        })}
      </div>
      <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: c.mute }}><Info size={12} /> “Check now” searches the web for the released paper and grades automatically. You can override with Right/Wrong or type the actual topic yourself.</p>

      <SectionTitle n="03" title="Spec coverage — prioritise your revision" note="Tap to cycle: Overdue → Likely → Revised." />
      <div className="rounded-lg overflow-hidden" style={{ background: c.surface, border: `1px solid ${c.line}` }}>
        {areas.map((a, i) => {
          const v = flags[i];
          const fs = v === "hot" ? { color: c.oxblood, bg: c.oxbloodSoft, label: "Likely" } : v === "due" ? { color: c.brass, bg: c.brassSoft, label: "Overdue" } : v === "covered" ? { color: c.teal, bg: c.tealSoft, label: "Revised" } : { color: c.mute, bg: "#F4F5F7", label: "Mark" };
          const order = [undefined, "due", "hot", "covered"];
          return (
            <div key={i} className="flex items-center justify-between gap-3 px-4 py-3" style={{ borderTop: i ? `1px solid ${c.lineSoft}` : "none" }}>
              <div className="flex items-center gap-3 min-w-0"><FlaskConical size={14} style={{ color: c.mute, flexShrink: 0 }} /><span className="text-sm truncate" style={{ color: c.ink }}>{a}</span></div>
              <button onClick={() => onSet(topic.id, i, order[(order.indexOf(v) + 1) % order.length])} className="font-mono text-[11px] rounded px-2.5 py-1 shrink-0" style={{ background: fs.bg, color: fs.color, border: `1px solid ${fs.color}33` }}>{fs.label}</button>
            </div>
          );
        })}
      </div>
      <p className="text-xs mt-3 flex items-center gap-1.5" style={{ color: c.mute }}><Info size={12} /> Areas not seen in recent confirmed papers are worth marking <span style={{ color: c.brass }}>Overdue</span>.</p>
    </div>
  );
}

/* ------------------------------- small parts ------------------------------- */
function Stat({ label, value }) { return <div className="rounded px-2.5 py-1.5 text-center" style={{ background: "#F4F5F7", border: `1px solid ${c.lineSoft}` }}><div className="text-[10px]" style={{ color: c.mute }}>{label}</div><div style={{ color: c.ink }}>{value}</div></div>; }
function SeriesCell({ s, count, active, onClick }) {
  const base = { flex: 1, minWidth: 0 };
  if (s.status === "cancelled") return <div style={base} className="text-center"><div className="rounded py-2" style={{ background: "#F1F0F1", border: `1px dashed ${c.line}` }}><div className="font-mono text-sm line-through" style={{ color: c.mute }}>{String(s.year).slice(2)}</div><div className="text-[9px]" style={{ color: c.mute }}>n/a</div></div></div>;
  if (s.status === "pending") return <div style={base} className="text-center"><div className="rounded py-2" style={{ border: `1px dashed ${c.brass}`, background: "#FBF8F2" }}><div className="font-mono text-sm" style={{ color: c.brass }}>{String(s.year).slice(2)}</div><div className="text-[9px]" style={{ color: c.brass }}>now</div></div></div>;
  return <button onClick={onClick} title={`Filter the question list to ${s.year}`} style={base} className="text-center">
    <div className="rounded py-2" style={{ background: count ? c.oxblood : "#fff", border: `1px solid ${count ? c.oxblood : c.line}`, boxShadow: active ? `0 0 0 2px ${c.teal}` : "none", cursor: "pointer" }}>
      <div className="font-mono text-sm" style={{ color: count ? "#fff" : c.ink }}>{String(s.year).slice(2)}</div>
      <div className="text-[9px]" style={{ color: count ? "#F0D8DC" : c.mute }}>{count ? `${count} done` : "scaffold"}</div>
    </div>
  </button>;
}
function SectionTitle({ n, title, note }) {
  return (
    <div className="mt-8 mb-3">
      <div style={{ height:1, background:"linear-gradient(to right,#C9A84C 0%,rgba(201,168,76,0.2) 50%,transparent 100%)", marginBottom:8 }} />
      <div className="flex items-baseline gap-3">
        <span className="font-mono text-xs font-bold" style={{ color: c.oxblood }}>{n}</span>
        <h3 className="font-bold text-base" style={{ color: c.ink }}>{title}</h3>
        {note && <span className="text-xs hidden sm:block" style={{ color: c.mute }}>{note}</span>}
      </div>
    </div>
  );
}


function SourceRefModal({ entry, onClose, onSave }) {
  const [url, setUrl] = React.useState(entry.sourceRef?.url || "");
  const [img, setImg] = React.useState(entry.sourceRef?.img || null);
  const [busy, setBusy] = React.useState(false);
  const fileRef = React.useRef();

  async function handleFile(e) {
    const file = e.target.files?.[0]; if (!file) return;
    setBusy(true);
    try { setImg(await compressImage(file)); }
    catch { alert("Could not load image — please try again."); }
    finally { setBusy(false); }
  }

  function save() {
    const ref = {};
    if (url.trim()) ref.url = url.trim();
    if (img) ref.img = img;
    onSave(Object.keys(ref).length ? ref : null);
  }

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center"
      style={{ background: "rgba(15,23,42,0.65)" }}
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="w-full sm:max-w-md rounded-t-2xl sm:rounded-2xl overflow-hidden flex flex-col"
        style={{ background: c.surface, maxHeight: "92vh" }}>

        {/* Header */}
        <div className="flex items-start justify-between px-4 py-3" style={{ borderBottom:`1px solid ${c.line}`, flexShrink:0 }}>
          <div>
            <p className="font-bold text-sm" style={{ color: c.ink }}>Attach source or interpretation</p>
            <p className="text-[11px] mt-0.5" style={{ color: c.mute }}>Upload a photo of the source text, or paste a link to the past paper</p>
          </div>
          <button onClick={onClose} className="grid place-items-center rounded-lg ml-2 flex-shrink-0"
            style={{ width:28,height:28,color:c.mute }}><X size={15} /></button>
        </div>

        <div className="p-4 space-y-4 overflow-y-auto flex-1">
          {/* Screenshot upload */}
          <div>
            <p className="text-xs font-semibold mb-2" style={{ color: c.inkSoft }}>Screenshot or photo of source</p>
            <input ref={fileRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFile} />
            {img ? (
              <div className="relative rounded-xl overflow-hidden" style={{ border:`1px solid ${c.line}` }}>
                <img src={img} alt="Source" className="w-full object-contain max-h-64" />
                <div className="absolute top-2 right-2 flex gap-1.5">
                  <button onClick={() => fileRef.current?.click()}
                    className="rounded-lg px-2.5 py-1 text-[11px] font-bold"
                    style={{ background: c.ink, color:"#fff" }}>Replace</button>
                  <button onClick={() => setImg(null)}
                    className="rounded-lg px-2.5 py-1 text-[11px] font-bold"
                    style={{ background: c.red, color:"#fff" }}>Remove</button>
                </div>
              </div>
            ) : (
              <button onClick={() => fileRef.current?.click()} disabled={busy}
                className="w-full rounded-xl py-6 flex flex-col items-center gap-2"
                style={{ border:`2px dashed ${c.line}`, background: c.lineSoft }}>
                {busy
                  ? <Loader2 size={22} className="animate-spin" style={{ color:c.oxblood }} />
                  : <><span style={{fontSize:28}}>📷</span>
                    <span className="text-sm font-semibold" style={{color:c.inkSoft}}>Take photo or upload screenshot</span>
                    <span className="text-xs" style={{color:c.mute}}>Photograph the source from your past paper</span></>}
              </button>
            )}
          </div>

          <div className="flex items-center gap-3">
            <div className="flex-1 h-px" style={{background:c.line}} />
            <span className="text-[11px] font-medium" style={{color:c.mute}}>or link to the paper</span>
            <div className="flex-1 h-px" style={{background:c.line}} />
          </div>

          {/* URL input */}
          <div>
            <p className="text-xs font-semibold mb-1.5" style={{color:c.inkSoft}}>Link to paper or source</p>
            <input value={url} onChange={e=>setUrl(e.target.value)}
              placeholder="Paste URL to past paper, revision site or PDF…"
              className="w-full rounded-xl px-3 py-2.5 text-sm"
              style={{ border:`1px solid ${c.line}`, outline:"none", color:c.ink }} />
            <p className="text-[10px] mt-1" style={{color:c.mute}}>e.g. link to the AQA or Edexcel past-paper PDF</p>
          </div>

          {/* Quick links */}
          <div>
            <p className="text-[10px] font-mono font-semibold tracking-widest mb-1.5" style={{color:c.mute}}>QUICK LINKS</p>
            <div className="flex flex-wrap gap-1.5">
              {[
                ["Edexcel past papers","https://qualifications.pearson.com/en/qualifications/edexcel-gcses/history-2016.html#tab-AssessmentMaterials"],
                ["AQA past papers","https://www.aqa.org.uk/subjects/history/gcse/history-8145/assessment-resources"],
                ["OCR past papers","https://www.ocr.org.uk/qualifications/gcse/history-b-schools-history-project-j411-from-2016/assessment/"],
                ["AQA A-Level","https://www.aqa.org.uk/subjects/history/a-level/history-7042/assessment-resources"],
              ].map(([label, href]) => (
                <button key={href} onClick={() => { setUrl(href); }}
                  className="inline-flex items-center gap-1 rounded-lg px-2.5 py-1 text-[11px] font-medium"
                  style={{background:c.oxbloodSoft, color:c.oxblood, border:`1px solid ${c.oxblood}20`}}>
                  {label} <ExternalLink size={9} />
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="flex gap-2 px-4 py-3" style={{ borderTop:`1px solid ${c.line}`, flexShrink:0 }}>
          {(entry.sourceRef) && (
            <button onClick={() => { onSave(null); onClose(); }}
              className="rounded-xl px-3 py-2 text-xs font-semibold"
              style={{ color: c.red, border:`1px solid ${c.red}25` }}>Remove all</button>
          )}
          <div className="flex-1" />
          <button onClick={onClose} className="rounded-xl px-4 py-2 text-sm font-medium"
            style={{ color:c.inkSoft, border:`1px solid ${c.line}` }}>Cancel</button>
          <button onClick={() => { save(); onClose(); }}
            className="rounded-xl px-4 py-2 text-sm font-semibold text-white"
            style={{ background: c.oxblood }}>Save</button>
        </div>
      </div>
    </div>
  );
}


function EntryModal({ topic, years, entry, onClose, onSave }) {
  const [series, setSeries] = useState(entry.series || years[years.length - 1]);
  const [qNumber, setQNumber] = useState(entry.qNumber || "");
  const [summary, setSummary] = useState(entry.summary || "");
  const [topicVal, setTopicVal] = useState(entry.topic || "");
  const [marks, setMarks] = useState(entry.marks ?? "");
  const [markScheme, setMarkScheme] = useState(entry.markScheme || "");
  const [sourceText, setSourceText] = useState(entry.sourceText || "");
  const [interp1, setInterp1] = useState(entry.interp1 || "");
  const [interp2, setInterp2] = useState(entry.interp2 || "");
  const [autoFilling, setAutoFilling] = useState(false);
  const { provider: aiPv, apiKey: aiKy, endpoint: aiEp } = useAIProvider();
  const qn = qNumber.trim();
  const isInference = qn === "1" && Number(marks) === 4;
  const isSourceUtil = !!qn.match(/^2\(a\)$|^3\(a\)$|^2a$|^3a$/);
  const isTwoSources = isSourceUtil;
  const isInterpQuestion = !!qn.match(/^3\(b\)$|^3\(c\)$|^3\(d\)$|^3b$|^3c$|^3d$|^01$|^02$|^03$/);
  const valid = qNumber.trim() && summary.trim() && marks !== "";
  const submit = () => valid && onSave({ ...entry, series: Number(series), paper: topic.paper, qNumber: qNumber.trim(), summary: summary.trim(), topic: topicVal.trim(), marks: Number(marks), markScheme: markScheme.trim(), source: "verified", ...(sourceRef ? { sourceRef } : {}), ...(sourceText.trim() ? { sourceText: sourceText.trim() } : {}), ...(interp1.trim() ? { interp1: interp1.trim() } : {}), ...(interp2.trim() ? { interp2: interp2.trim() } : {}) });

  async function autoFillSources() {
    setAutoFilling(true);
    const specAreas = (SPEC_AREAS[topic.id]||[]).join(", ");
    const prompt = isInterpQuestion
      ? `You are populating a History revision app. Topic: ${topic.name} (${topic.board} ${topic.level}, ${series}). Question: ${summary.trim()}. Spec areas: ${specAreas}. Generate TWO contrasting historian interpretations. Use real historians who have written on this topic. Each: historian name, book title (year), and a 2-3 sentence extract representing their argument. Respond ONLY with valid JSON: {"text1":"Historian Name, Book (Year): 'extract...' ","text2":"Historian Name, Book (Year): 'contrasting extract...'"}`
      : `You are populating a History revision app. Topic: ${topic.name} (${topic.board} ${topic.level}, ${series}). Question: ${summary.trim()}. Spec areas: ${specAreas}. Generate TWO period-appropriate primary source extracts. Each: attribution (author, date, type) and a 2-3 sentence extract. Respond ONLY with valid JSON: {"text1":"Attribution: 'extract'","text2":"Attribution: 'extract'"}`;
    try {
      const raw = await callAIText({ provider: aiPv, apiKey: aiKy, endpoint: aiEp, prompt });
      const p = JSON.parse(raw.replace(/```json|```/g,"").trim());
      if (isInterpQuestion) { setInterp1(p.text1||""); setInterp2(p.text2||""); }
      else { setSourceText(p.text1||""); setInterp1(p.text2||""); }
    } catch(e) { alert("Auto-fill failed: " + e.message); }
    finally { setAutoFilling(false); }
  }
  return (<>
    <div className="fixed inset-0 z-40 flex items-end sm:items-center justify-center p-0 sm:p-4" style={{ background: "rgba(27,42,58,0.45)" }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} className="w-full sm:max-w-lg rounded-t-2xl sm:rounded-lg overflow-hidden" style={{ background: c.surface }}>
        <div className="flex items-center justify-between px-5 py-4" style={{ borderBottom: `1px solid ${c.line}` }}>
          <div><h3 className="font-serif text-lg">{entry.id ? "Confirm / edit question" : "Add question"}</h3><p className="text-xs" style={{ color: c.mute }}>{topic.short} · {topic.paper}</p></div>
          <button onClick={onClose} className="grid place-items-center rounded" style={{ width: 30, height: 30, color: c.inkSoft }}><X size={18} /></button>
        </div>
        <div className="p-5 space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <Field label="Series (year)"><select value={series} onChange={(e) => setSeries(e.target.value)} className="w-full rounded px-3 py-2 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink }}>{years.map((y) => <option key={y} value={y}>{y}</option>)}</select></Field>
            <Field label="Question number"><input value={qNumber} onChange={(e) => setQNumber(e.target.value)} placeholder="e.g. 5 or 01" className="w-full rounded px-3 py-2 text-sm outline-none font-mono" style={{ border: `1px solid ${c.line}`, color: c.ink }} /></Field>
          </div>
          <Field label="Question summary (the actual topic asked)"><textarea value={summary} onChange={(e) => setSummary(e.target.value)} onBlur={() => { if (!topicVal.trim() && summary.trim()) { const g = guessSpecArea(SPEC_AREAS[topic.id] || [], summary); if (g) setTopicVal(g); } }} rows={2} placeholder="Paraphrase the real question…" className="w-full rounded px-3 py-2 text-sm outline-none resize-none" style={{ border: `1px solid ${c.line}`, color: c.ink }} /></Field>
          <Field label="Topic (spec area)">
            <input list="spec-areas" value={topicVal} onChange={(e) => setTopicVal(e.target.value)} placeholder="Choose or type a spec topic — auto-suggested from your summary" className="w-full rounded px-3 py-2 text-sm outline-none" style={{ border: `1px solid ${c.line}`, color: c.ink }} />
            <datalist id="spec-areas">{(SPEC_AREAS[topic.id] || []).map((a) => <option key={a} value={a} />)}</datalist>
          </Field>
          <Field label="Marks"><input type="number" value={marks} onChange={(e) => setMarks(e.target.value)} placeholder="4, 8, 25, 30…" min="0" className="w-32 rounded px-3 py-2 text-sm outline-none font-mono" style={{ border: `1px solid ${c.line}`, color: c.ink }} /></Field>
          <Field label="Mark scheme notes (optional — what earns the marks)"><textarea value={markScheme} onChange={(e) => setMarkScheme(e.target.value)} rows={2} placeholder="Paraphrase the indicative content / levels in your own words…" className="w-full rounded px-3 py-2 text-sm outline-none resize-none" style={{ border: `1px solid ${c.line}`, color: c.ink }} /></Field>

          {/* Source / Interpretation text — shown for source and interpretation question types */}
          {(isInference || isSourceUtil) && (
            <div className="rounded-xl p-3 space-y-2.5" style={{ background:"#EFF6FF", border:"1px solid #BFDBFE" }}>
              <div className="flex items-center justify-between">
                <p className="text-[10px] font-mono font-bold tracking-widest" style={{ color:"#2563EB" }}>🔍 SOURCES</p>
                <button onClick={autoFillSources} disabled={autoFilling}
                  className="inline-flex items-center gap-1 rounded-lg px-2.5 py-1 text-[11px] font-bold"
                  style={{ background:"#2563EB", color:"#fff", opacity:autoFilling?0.6:1 }}>
                  {autoFilling ? <Loader2 size={11} className="animate-spin"/> : <Sparkles size={11}/>}
                  {autoFilling ? "Generating…" : "Auto-fill ✨"}
                </button>
              </div>
              <Field label={isTwoSources ? "Source A text" : "Source A text"}>
                <textarea value={sourceText} onChange={e=>setSourceText(e.target.value)} rows={3}
                  placeholder="Paste Source A text here (attribution + extract)…"
                  className="w-full rounded-lg px-3 py-2 text-sm resize-none"
                  style={{ border:`1px solid ${c.line}`, color: c.ink }} />
              </Field>
              {isTwoSources && (
                <Field label="Source B text">
                  <textarea value={interp1} onChange={e=>setInterp1(e.target.value)} rows={3}
                    placeholder="Paste Source B text here (attribution + extract)…"
                    className="w-full rounded-lg px-3 py-2 text-sm resize-none"
                    style={{ border:`1px solid ${c.line}`, color: c.ink }} />
                </Field>
              )}
            </div>
          )}

          {isInterpQuestion && (
            <div className="rounded-xl p-3 space-y-2.5" style={{ background:"#F5F3FF", border:"1px solid #DDD6FE" }}>
              <div className="flex items-center justify-between">
                <p className="text-[10px] font-mono font-bold tracking-widest" style={{ color:"#7C3AED" }}>📜 INTERPRETATIONS</p>
                <button onClick={autoFillSources} disabled={autoFilling}
                  className="inline-flex items-center gap-1 rounded-lg px-2.5 py-1 text-[11px] font-bold"
                  style={{ background:"#7C3AED", color:"#fff", opacity:autoFilling?0.6:1 }}>
                  {autoFilling ? <Loader2 size={11} className="animate-spin"/> : <Sparkles size={11}/>}
                  {autoFilling ? "Generating…" : "Auto-fill ✨"}
                </button>
              </div>
              <Field label="Interpretation 1 (historian name + extract)">
                <textarea value={interp1} onChange={e=>setInterp1(e.target.value)} rows={3}
                  placeholder="e.g. Historian [Name], [Book/Year]: '[Extract from paper]'"
                  className="w-full rounded-lg px-3 py-2 text-sm resize-none"
                  style={{ border:`1px solid ${c.line}`, color: c.ink }} />
              </Field>
              <Field label="Interpretation 2 (historian name + extract)">
                <textarea value={interp2} onChange={e=>setInterp2(e.target.value)} rows={3}
                  placeholder="e.g. Historian [Name], [Book/Year]: '[Extract from paper]'"
                  className="w-full rounded-lg px-3 py-2 text-sm resize-none"
                  style={{ border:`1px solid ${c.line}`, color: c.ink }} />
              </Field>
            </div>
          )}
        </div>
        <div className="flex items-center gap-2 px-5 py-4" style={{ borderTop: `1px solid ${c.line}`, background: "#FAFAFB" }}>
          <button onClick={() => setShowSourceRef(true)}
            className="inline-flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-semibold"
            style={{ color: sourceRef ? c.oxblood : c.mute, border:`1px solid ${sourceRef ? c.oxblood+"40" : c.line}`, background: sourceRef ? c.oxbloodSoft : "transparent" }}>
            {sourceRef?.img ? "📷 Photo attached" : sourceRef?.url ? "🔗 Link attached" : "📎 Attach source"}
          </button>
          <div className="flex-1" />
          <button onClick={onClose} className="rounded-lg px-4 py-2 text-sm font-medium" style={{ color: c.inkSoft, border: `1px solid ${c.line}`, background: "#fff" }}>Cancel</button>
          <button onClick={submit} disabled={!valid} className="inline-flex items-center gap-1.5 rounded-lg px-4 py-2 text-sm font-semibold text-white hover:opacity-90 disabled:opacity-40" style={{ background: c.oxblood }}><Check size={15} /> Save</button>
        </div>
      </div>
    </div>
    {showSourceRef && <SourceRefModal entry={{ ...entry, sourceRef }} onClose={() => setShowSourceRef(false)} onSave={ref => { setSourceRef(ref); setShowSourceRef(false); }} />}
  </>);
}
function Field({ label, children }) { return <label className="block"><span className="text-xs font-medium block mb-1.5" style={{ color: c.inkSoft }}>{label}</span>{children}</label>; }

/* ----------------------------- exam dates ---------------------------------- */
const EDEXCEL_GCSE_EXAMS = [
  // Confirmed 2026 dates (all now past — today is June 2026)
  { year: 2026, paper: "Paper 1", label: "Medicine · Crime · Migration · Warfare", date: new Date("2026-05-15"), confirmed: true },
  { year: 2026, paper: "Paper 2", label: "Anglo-Saxons · American West · Elizabethan · Cold War", date: new Date("2026-06-04"), confirmed: true },
  { year: 2026, paper: "Paper 3", label: "Nazi Germany · Russia · USA · Mao's China", date: new Date("2026-06-09"), confirmed: true },
  // Estimated 2027 dates (same Thursday/Friday/Tuesday pattern; TBC)
  { year: 2027, paper: "Paper 1", label: "Medicine · Crime · Migration · Warfare", date: new Date("2027-05-14"), confirmed: false },
  { year: 2027, paper: "Paper 2", label: "Anglo-Saxons · American West · Elizabethan · Cold War", date: new Date("2027-06-03"), confirmed: false },
  { year: 2027, paper: "Paper 3", label: "Nazi Germany · Russia · USA · Mao's China", date: new Date("2027-06-08"), confirmed: false },
];

function ExamDates() {
  const now = new Date();
  const upcoming = EDEXCEL_GCSE_EXAMS.filter((e) => e.date >= now);
  const allDone2026 = EDEXCEL_GCSE_EXAMS.filter((e) => e.year === 2026).every((e) => e.date < now);

  const msPerDay = 86400000;
  const daysDiff = (d) => Math.ceil((d - now) / msPerDay);

  if (!upcoming.length) return null;
  const next = upcoming[0];
  const days = daysDiff(next.date);

  const urgency = days <= 7 ? c.oxblood : days <= 28 ? "#B45309" : c.teal;

  return (
    <div style={{ background: `${urgency}11`, borderBottom: `1px solid ${urgency}33` }}>
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-3 flex flex-col sm:flex-row sm:items-center gap-3">
        {/* Next exam */}
        <div className="flex items-center gap-3 flex-1">
          <div className="grid place-items-center rounded-lg shrink-0" style={{ width: 44, height: 44, background: `${urgency}22`, color: urgency }}>
            <Clock size={20} />
          </div>
          <div>
            <p className="text-xs font-medium" style={{ color: urgency }}>
              {days === 0 ? "Today!" : days === 1 ? "Tomorrow!" : `${days} days`}
              {" — "}<span className="font-bold">{next.paper}</span>
              {!next.confirmed && <span className="ml-1 opacity-60">(estimated)</span>}
            </p>
            <p className="text-xs" style={{ color: c.inkSoft }}>{next.label}</p>
            <p className="text-xs font-mono" style={{ color: urgency }}>
              {next.date.toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "long", year: "numeric" })}
            </p>
          </div>
        </div>

        {/* All upcoming dates */}
        <div className="flex flex-wrap gap-x-4 gap-y-1">
          {upcoming.map((e) => {
            const d = daysDiff(e.date);
            return (
              <div key={`${e.year}-${e.paper}`} className="text-xs" style={{ color: c.inkSoft }}>
                <span className="font-semibold" style={{ color: c.ink }}>{e.paper} {e.year}</span>
                {" — "}
                {e.date.toLocaleDateString("en-GB", { day: "numeric", month: "short" })}
                <span className="ml-1 opacity-60">({d}d{!e.confirmed ? " est." : ""})</span>
              </div>
            );
          })}
        </div>

        {/* 2026 done badge */}
        {allDone2026 && (
          <div className="shrink-0 rounded-full px-3 py-1 text-xs font-medium flex items-center gap-1.5"
            style={{ background: "#10B98122", color: "#059669" }}>
            <Check size={12} /> 2026 exams complete
          </div>
        )}
      </div>
    </div>
  );
}

function SubjectSelectorBottom({ subject, setSubject, data }) {
  return (
    <div className="sm:hidden px-3 py-3 space-y-2.5"
      style={{ background: c.paper, borderTop:`1px solid ${c.line}` }}>
      <p className="text-[9px] font-mono font-bold tracking-widest px-1"
        style={{ color: c.mute }}>SUBJECT</p>
      {SUBJECTS.map(({ id, label, icon }) => {
        const on = id === subject;
        const topicCount = TOPICS.filter(t => t.subject === id).length;
        const entries = TOPICS.filter(t => t.subject === id)
          .reduce((s, t) => s + (data?.[t.id] || []).filter(e => e.source !== "scaffold").length, 0);
        const conf = TOPICS.filter(t => t.subject === id)
          .reduce((s, t) => s + (data?.[t.id] || []).filter(e => e.confidence === 2).length, 0);
        const pct = entries > 0 ? Math.round(conf / entries * 100) : 0;
        return (
          <button key={id} onClick={() => setSubject(id)}
            className="w-full flex items-center gap-3 rounded-2xl px-4 py-3"
            style={{
              background:  on ? "#0D1B2E" : "#fff",
              border:      `1px solid ${on ? "#C9A84C" : c.line}`,
              boxShadow:   on
                ? "0 0 20px rgba(201,168,76,0.25), 0 4px 12px rgba(13,27,46,0.18)"
                : "0 1px 4px rgba(0,0,0,0.07)",
              transition:  "all 0.22s cubic-bezier(0.4,0,0.2,1)",
            }}>
            <span style={{ fontSize:28, lineHeight:1, flexShrink:0 }}>{icon}</span>
            <div className="flex-1 text-left min-w-0">
              <p className="text-sm font-bold leading-tight"
                style={{ color: on ? "#fff" : c.ink }}>{label}</p>
              <p className="text-[10px] mt-0.5"
                style={{ color: on ? "rgba(201,168,76,0.65)" : c.mute }}>
                {topicCount} topics · {entries} questions
              </p>
              {entries > 0 && (
                <div className="flex items-center gap-2 mt-1.5">
                  <div className="flex-1 rounded-full h-1.5 overflow-hidden"
                    style={{ background: on ? "rgba(255,255,255,0.12)" : c.lineSoft }}>
                    <div className="h-1.5 rounded-full transition-all duration-700"
                      style={{
                        width: `${pct}%`,
                        background: pct >= 75
                          ? "linear-gradient(90deg,#059669,#34D399)"
                          : "linear-gradient(90deg,#C9A84C,#F0C84A)",
                      }} />
                  </div>
                  <span className="text-[11px] font-black font-mono shrink-0"
                    style={{ color: on ? "#C9A84C" : pct > 0 ? "#C9A84C" : c.mute }}>
                    {pct}%
                  </span>
                </div>
              )}
            </div>
            <ConfRing pct={pct} size={38} />
          </button>
        );
      })}
    </div>
  );
}


function Footer({ useCount, data, board, level }) {
  const subjectStats = React.useMemo(() => {
    return SUBJECTS.map(({ id: subj, label, icon }) => {
      let total = 0, confident = 0;
      TOPICS.filter(t => t.subject === subj).forEach(t => {
        const entries = (data?.[t.id] || []).filter(e => e.source !== "scaffold");
        total += entries.length;
        confident += entries.filter(e => e.confidence === 2).length;
      });
      const pct = total > 0 ? Math.round(confident / total * 100) : 0;
      return { subj, label, icon, total, confident, pct };
    });
  }, [data]);

  return (
    <footer style={{ color: c.mute }}>
      {/* ── All-subjects progress strip ── */}
      <div style={{ background: c.night, borderTop: "1px solid rgba(201,168,76,0.18)" }}>
        <div className="max-w-6xl mx-auto px-4 sm:px-6 py-3">
          <p className="text-[9px] font-mono font-bold tracking-widest mb-2.5"
            style={{ color: "rgba(201,168,76,0.45)", textAlign:"center" }}>
            OVERALL PROGRESS · ALL SUBJECTS
          </p>
          <div className="flex gap-4 sm:gap-8">
            {subjectStats.map(({ subj, label, icon, total, confident, pct }) => (
              <div key={subj} className="flex-1 min-w-0 space-y-1">
                <div className="flex items-center justify-between">
                  <span className="flex items-center gap-1 text-[10px] font-semibold"
                    style={{ color: "#94A3B8" }}>
                    <span style={{ fontSize: 13 }}>{icon}</span>
                    <span className="hidden sm:inline">{label}</span>
                    <span className="sm:hidden">{label.slice(0, 4)}</span>
                  </span>
                  <span className="text-[12px] font-black font-mono"
                    style={{ color: pct >= 75 ? "#34D399" : pct >= 40 ? "#C9A84C" : "#475569" }}>
                    {pct}%
                  </span>
                </div>
                <div className="rounded-full overflow-hidden" style={{ height: 6, background: "rgba(255,255,255,0.08)" }}>
                  <div className="h-full rounded-full transition-all duration-700"
                    style={{
                      width: `${pct}%`,
                      background: pct >= 75
                        ? "linear-gradient(90deg,#059669,#34D399)"
                        : pct >= 40
                        ? "linear-gradient(90deg,#C9A84C,#F0C84A)"
                        : "linear-gradient(90deg,#2D3F55,#3D5068)",
                    }} />
                </div>
                <p className="text-[9px] font-mono text-center"
                  style={{ color: "#374151" }}>
                  {confident}/{total} questions
                </p>
              </div>
            ))}
          </div>
        </div>
      </div>
      {/* ── Legal / session ── */}
      <div className="max-w-6xl mx-auto px-6 py-4 text-xs flex flex-wrap gap-2 justify-between items-center">
        <span className="hidden sm:inline" style={{ color: c.mute }}>
          Spec structure follows Edexcel 1HI0, AQA 8145/7042 and OCR J411. Verify against the official paper.
        </span>
        <span className="sm:hidden" style={{ color: c.mute }}>Exam Chronicle · Always verify against official papers.</span>
        {useCount > 0 && (
          <div className="flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-medium shrink-0"
            style={{ background: `${c.oxblood}11`, color: c.oxblood, border: `1px solid ${c.oxblood}22` }}>
            <BookOpen size={11} />
            Session {useCount.toLocaleString()}
          </div>
        )}
      </div>
    </footer>
  );
}


function exportCsv(topic, entries) {
  const rows = [["Year", "Paper", "Question", "Summary", "Topic", "Marks", "Mark scheme notes", "Status"]];
  entries.slice().sort((a, b) => (b.series - a.series) || a.qNumber.localeCompare(b.qNumber, undefined, { numeric: true }))
    .forEach((e) => rows.push([e.series, e.paper, e.qNumber, `"${(e.summary || "").replace(/"/g, '""')}"`, `"${(e.topic || "").replace(/"/g, '""')}"`, e.marks, `"${(e.markScheme || "").replace(/"/g, '""')}"`, e.source]));
  const blob = new Blob([rows.map((r) => r.join(",")).join("\n")], { type: "text/csv" });
  const url = URL.createObjectURL(blob); const a = document.createElement("a");
  a.href = url; a.download = `${topic.id}-questions.csv`; a.click(); URL.revokeObjectURL(url);
}
